-- videos
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7512793707324165376', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何记笔记 #清华学霸 #学习方法', '如何记笔记 #清华学霸 #学习方法', 1749208600, 'https://www.douyin.com/video/7512793707324165376', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ogQgAHfDCQqi9YoA5zoclQDsCBjAWEzGFDfFQg~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=kCNQIQy0wvAcAA9SAsrU3BAFBJ8%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151032AA1ED6A5F55F07152BBF', 193913, 142353, 2340, 36681, 'done', 0, 'data/text/7512793707324165376.txt', 'data/summaries/7512793707324165376.md', '视频探讨了高效记笔记的方法，核心目的是通过缩写和提炼重点来加速复习与反思。主讲人以“爱情”概念为例，强调注意程度词和名词（编语）来把握定义关键，然后进行个性化缩写，并随着理解加深逐步精简笔记，最终形成口诀式记忆。笔记的迭代过程本身就是多次复习，能大幅强化长期记忆。对比在书上直接划线，单独记笔记带来的“陌生感”可有效检验真实掌握度，避免“以为会了”的错觉。此外，主讲人提倡在笔记中融入批判性思考，如质疑概念背后的预设，使笔记不仅是应试工具，更是深度学习的延伸。', '["记笔记的核心是提取程度词与名词进行缩写，以便快速触发完整记忆。", "笔记需经历从详细到精简的迭代过程，每次重写都是一次有效复习。", "单独记笔记带来的陌生感能避免“熟悉感错觉”，真实检验掌握程度。", "在笔记中加入批判性提问与个人感悟，可将学习从应试升维至深度思考。"]', '[{"topic": "主动回忆与测试效应", "why": "笔记的缩写与回看过程实质上是主动回忆，大量认知科学证实这种提取练习比反复阅读更能强化长期记忆，理解其原理有助于优化所有学习环节。", "direction": "可阅读《认知天性》（Make It Stick）一书，或研究“必要难度”（Desirable Difficulty）理论，深入学习记忆科学。"}, {"topic": "精细化复述策略", "why": "视频中将长句压缩为关键词并串联成口诀，是精细化复述的一种形式，它能提高信息加工深度，值得系统掌握其操作方法。", "direction": "推荐学习“康奈尔笔记法”或“思维导图笔记法”，并结合教育心理学中关于“精细加工”的章节进行实践。"}, {"topic": "批判性思维在笔记中的应用", "why": "主讲人在笔记中追问概念预设、理论框架的习惯，展现了批判性思维如何融入学习过程，能显著提升分析、评估和建构知识的能力。", "direction": "可研读《学会提问》（Asking the Right Questions）或布鲁姆认知目标分类学，练习在笔记中建立“质疑—探究—联结”的常规步骤。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783921446, 1783921446, 1783922560, '769.3', '619.4', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7502669135399226643', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何快速读书 #清华老公 #学习技巧', '如何快速读书 #清华老公 #学习技巧', 1746851521, 'https://www.douyin.com/video/7502669135399226643', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oUYBBP5G1QAa5HFvpfrz9eD2KAIeQCGoQQW7bL~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=k2hu7oNGPkRgJSDwYpc9qFQE6lE%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151034E24F6C8F703B4BFC6983', 271784, 163841, 4619, 39621, 'done', 0, 'data/text/7502669135399226643.txt', 'data/summaries/7502669135399226643.md', '视频分享了清华学霸的快速阅读方法，核心在于跳出逐字默读的窠臼，通过直接以词块、句子甚至段落为单位进行视觉化信息摄取，大幅提升阅读效率。具体技巧包括：默读是速度的瓶颈，应练习将文字切割为意群，让大脑跳过发音直接理解；中文段落常以首尾句总结观点，利用这一特点可先看论点再决定是否细读解释；跳读时以句为单位提炼核心词，避免大段跳过导致遗漏；跳读后结合笔记构建知识框架，用逻辑结构图确保理解系统自洽；阅读顺序上应先把握整体骨架，再回顾细节。这些方法需刻意练习，最终可实现快速而深入的阅读。', '["摒弃默读，练习以意群为单位直接视觉化理解文字。", "通过扫描段落首尾句快速获取论点，决定是否需要细读解释部分。", "跳读时以句子为单位提炼核心词，避免遗漏关键信息。", "跳读后必须整理结构笔记，将核心词串联成体系，确保理解自洽。", "采用“先总览全局，再研究细节”的顺序，以框架引领深入阅读。"]', '[{"topic": "意群阅读与视觉广度训练", "why": "意群阅读是速读的核心技术，涉及扩大眼距、减少回跳等，能从根本上改变阅读生理习惯。", "direction": "可阅读《如何阅读一本书》《超级快速阅读》等书籍，或练习舒尔特表格等辅助工具。"}, {"topic": "结构化思维与知识体系构建", "why": "将知识提炼为结构图不仅是笔记技巧，更是深度学习的本质，能帮助大脑建立索引，促进迁移应用。", "direction": "学习《金字塔原理》《结构思考力》，掌握MECE法则和思维导图制作。"}, {"topic": "阅读中的元认知与理解监控", "why": "判断何时跳过、何时细读，以及检验系统自洽，均涉及元认知技能，这是高效学习的支柱。", "direction": "了解教育心理学中“理解监控”概念，参考《认知心理学》或《元认知与学习策略》。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783921446, 1783921446, 1783922474, '325.8', '358.5', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7661580381732978405', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '难题答对了，成绩却下降 #清华学霸 #难题 #学习方法 #忽然知己', '难题答对了，成绩却下降 #清华学霸 #难题 #学习方法 #忽然知己', 1783850692, 'https://www.douyin.com/video/7661580381732978405', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015c000-ce/oE7Tebmk1In1AkExZBKivRMiI2BAVFAwLwfbt7~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=W%2BSHM9Q9UzD2%2FS4cXw9fx0mtJaE%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151038D8EDDCC346ABDCFB8CA9', 1248, 603, 32, 155, 'done', 0, 'data/text/7661580381732978405.txt', 'data/summaries/7661580381732978405.md', '视频揭示了一个反直觉现象：学生花大量精力攻克难题，成绩却不升反降。原因在于考试中占比更大的中低难度题同样重要，它们考察的是稳定准确且快速完成的能力，而非仅攻坚能力。真正的高手不仅要会做难题，更要通过精力管理和思维压缩，将简单题练到“任何时候都能快速轻松做对”的程度。文章指出，重新定义“会”的标准、建立执行检查流程、避免用“大意”掩盖能力不足，是从普通学生走向优等生的关键。', '["考试不仅考察攻坚难题的能力，更考察稳定、快速、准确完成占多数的中低难度题的能力。", "精锐的难题完成后，大脑精力耗竭，容易在简单题上因“马虎”丢分，本质是精力管理不足。", "真正的“会”不是看懂或偶尔做对，而是随时都能快速轻松准确地完成。", "建立执行流程（如规范草稿、验算）并拒绝用“大意”归因错误，是减少低级失误的关键。", "成绩突破需要同时具备攻克难题和思维压缩的双重能力。"]', '[{"topic": "精力管理与认知资源分配", "why": "理解大脑有限的工作记忆和认知资源如何影响考试表现，是提升学习效率的基础。", "direction": "可阅读《认知心理学》中关于工作记忆和注意力的章节，或学习《精力管理》一书。"}, {"topic": "刻意练习与自动化", "why": "思维压缩的本质是通过重复形成自动化的解题程序，这涉及刻意练习理论，对技能掌握至关重要。", "direction": "参考安德斯·艾利克森的《刻意练习》，了解如何从熟练到精通。"}, {"topic": "元认知与错误归因", "why": "正确归因错误而非简单用“马虎”搪塞，能精准定位学习漏洞，提升自我监控能力。", "direction": "学习元认知策略，可阅读《学习的本质》或《元认知：了解自己的思维》。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1783933155, 1783934198, '351.20325', '249.51649618148804', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7660139807154999439', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '急 #清华学霸 #急 #学习方法 #忽然知己', '急 #清华学霸 #急 #学习方法 #忽然知己', 1783515282, 'https://www.douyin.com/video/7660139807154999439', 'https://p3-pc-sign.douyinpic.com/tos-cn-p-0015/ogPJBf7SAiLDIJSx4A1giBTOIyeyAKB3NAWyaH~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=iX4KlvB85t4k0AAPaCox1MFT6tY%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151040AAA129F3477840896036', 5303, 2751, 51, 518, 'done', 0, 'data/text/7660139807154999439.txt', 'data/summaries/7660139807154999439.md', '视频探讨了学习过程中常见的「急躁」情绪，指出其本质是注意力过度聚焦结果，忽视过程。当人们无法预知结果时，会因未知而产生恐惧和焦虑，进而否定当下努力的意义，导致付出与收获不成正比。要克服急躁，首先要区分「学习」与「表演」，学习是扎实掌握内容，而非追求表面状态；其次要理解知识积累的结构性，初期进步缓慢是量变积累，达到质变点后才会加速；最后需珍视过程，因为真正的成长都发生在从起点到终点的漫长过程中。急躁本身并非坏事，它反映出积极向好的意愿，关键在于将这份焦虑转化为具体的行动规划，专注于脚下的每一步，才能稳步接近目标。', '["急躁的本质是注意力过度聚焦结果，忽视过程，从而引发对未知的恐惧和焦虑。", "区分「学习」与「表演」：学习重在内容掌握，不应只追求表面的学习状态。", "知识的积累是结构化过程，需要量变到质变的耐心，初期慢是正常现象。", "成功来源于过程的点滴，而非跳过过程的捷径，「急」应转化为具体的执行步骤。"]', '[{"topic": "学习焦虑与不确定性容忍度", "why": "急躁往往源于对学习结果未知的恐惧，理解认知心理学中的「不确定性容忍度」能帮助从根源调节情绪。", "direction": "阅读《驾驭情绪的力量》或学习认知行为疗法中的相关概念，了解如何应对不确定性的焦虑。"}, {"topic": "深度学习与表面学习", "why": "区分真实学习与表演学习是高效学习的第一步，了解「深度加工」理论能帮助我们避免无效努力。", "direction": "推荐阅读《刻意练习》或了解教育心理学中的「深层学习」与「表层学习」概念，并反思自己的学习模式。"}, {"topic": "知识体系建构与质变临界点", "why": "视频中提到积累到一定程度会发生质变，背后是系统论和知识结构化的原理，掌握它能设计更科学的学习计划。", "direction": "学习「最近发展区」理论、概念图等，参考《如何高效学习》一书中的整体性学习策略。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1783933436, 1784011350, '340.475625', '280.9281988143921', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7658610000244494690', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何不被环境影响 #清华学霸 #学习方法 #思考笔记 #不被影响', '如何不被环境影响 #清华学霸 #学习方法 #思考笔记 #不被影响', 1783159096, 'https://www.douyin.com/video/7658610000244494690', 'https://p3-pc-sign.douyinpic.com/tos-cn-p-0015/o8AIAAU1DimA2eiIu6IfBi2JxBXTqGIwDpU11g~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=crrDn6rOPt20P5Qh0Q00LjLpplY%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415104299E3AA6458C9A5E672F3', 31795, 18850, 172, 3457, 'done', 0, 'data/text/7658610000244494690.txt', 'data/summaries/7658610000244494690.md', '在看视频时，我们常因他人低声交谈或偶尔杂音而分神烦躁，视频指出这并非声音本身多大，而是我们将“自我”过度融入环境，把自我边界扩大至整个集体，充当“集体捍卫者”，将微小干扰放大为对全体的侵犯，从而产生愤怒与无力感。解决的核心在于建立“自我边界”：首先，不评价制造噪音的人，将声音中性化为自然声响，消除控制欲；其次，明确具体的学习目标，用专注力屏蔽干扰；再者，通过感受窗外自然等正向事物，切换注意力主体，避免与环境过度绑定；最后，树立“你大于环境”的心态，认识到自己是独立主体，环境仅为所用。这些方法能帮助我们在嘈杂中保持内心平静，高效学习。', '["过度融入环境、无边界地代表集体，是造成干扰敏感的根本原因。", "停止评价制造噪音的人，将其视为自然声响，可减少控制欲和情绪反应。", "明确具体的学习目标，用专注力构建屏蔽干扰的内在屏障。", "通过感受自然等正向事物，切换注意力主体，避免与环境过度绑定。", "树立“你大于环境”的心态，让环境为你所用，而非被动受影响。"]', '[{"topic": "自我边界理论", "why": "理解为何我们容易将集体问题个人化，从而产生不必要情绪，是改善心理抗干扰能力的基础。", "direction": "阅读心理学书籍如《自我边界》，或了解心理边界理论在人际关系和情绪管理中的应用。"}, {"topic": "斯多葛控制二分法", "why": "帮助我们区分可控与不可控，减少对环境的无谓纠结与情绪消耗。", "direction": "学习斯多葛哲学，推荐阅读《沉思录》或《生活的艺术》，练习区分“我能控制什么”和“我不能控制什么”。"}, {"topic": "正念与不评判", "why": "视频中提到不评价人，将声音看作自然现象，与正念冥想中的“不评判”原则一致，能有效减少压力与烦躁。", "direction": "尝试正念冥想练习，阅读《正念：此刻是一枝花》，培养对内外体验的非评判性觉察。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1783933675, 1784011437, '306.1100625', '238.11808800697327', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7656373630528977280', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何不被他人影响 #清华学霸 #学习方法 #思考笔记 #不被影响', '如何不被他人影响 #清华学霸 #学习方法 #思考笔记 #不被影响', 1782638400, 'https://www.douyin.com/video/7656373630528977280', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oEuAwRgQfAIS0ZplAD9qe0B35EADFA5rDOxIYy~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=yv5m8CwBnIi9QPjHsLuQd6tPDxY%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151045E4F6E11BBBE58B09AE58', 8181, 4659, 96, 960, 'done', 0, 'data/text/7656373630528977280.txt', 'data/summaries/7656373630528977280.md', '视频指出，人们容易受他人影响往往源于“找共性”的比较本能。由于自我认知依赖他人参照，我们常在环境反馈中迷失，将共同标签视为真实自我。而摆脱这种影响的关键在于树立个人志向，从人生长远目标俯瞰当下环境。一旦拥有志向，环境便只是人生切片，短暂得失不再动摇内心，从而实现不被他人左右的稳定状态。', '["受他人影响的根源在于过度寻找共性，依赖环境反馈建立自我认知。", "“镜中我”效应使我们不自觉地将他人的反应作为自我评价的标准。", "表面的共同标签掩盖了个体差异，比较应着眼于具体问题而非笼统结果。", "树立长远志向能够提供内在锚点，使人跳出环境漩涡，从人生视角看待当下得失。", "将注意力从外部环境转向内在目标，是实现精神独立的关键。"]', '[{"topic": "镜中我理论", "why": "揭示自我认知如何依赖他人反馈，理解比较行为的社会心理根源，有助于摆脱外控倾向。", "direction": "阅读查尔斯·库利的《人类本性与社会秩序》，或社会心理学中关于自我概念形成的章节。"}, {"topic": "社会标签与去个体化", "why": "标签化思维简化了人的复杂性，导致过度比较与压力，深入理解有助于打破认知局限。", "direction": "可阅读《乌合之众》古斯塔夫·勒庞，或社会学中关于标签理论的讨论，如贝克尔《局外人》。"}, {"topic": "目标设定与心理韧性", "why": "立志之所以有效，因为目标提供了意义感和方向感，是心理抗压的重要资源，值得结合心理学实证学习。", "direction": "阅读《成功、动机与目标》海蒂·格兰特·霍尔沃森，或积极心理学中关于目标与幸福感的著作。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1783933893, 1784011531, '300.1193125', '217.74137496948242', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7652304566675237568', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '提升认知 #清华学霸 #认知提升 #认知 #体系搭建', '提升认知 #清华学霸 #认知提升 #认知 #体系搭建', 1781690998, 'https://www.douyin.com/video/7652304566675237568', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ocIyJtniPKwglywchQAPIHB6AcuOIAZGcjija~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=de%2F6o9L%2Fc5HmWNNrGGsUGW8xi0s%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151047F44A9481FC9DBE0801FF', 3451, 1652, 44, 349, 'done', 0, 'data/text/7652304566675237568.txt', 'data/summaries/7652304566675237568.md', '视频指出，认知提升不等于知识点堆砌，而是理解知识背后的规律，从而在面对现实问题时能识别更多隐藏条件，构建可迁移的思维模型。真正的认知是大脑的系统升级，从孤立现象中提炼通用法则，再以此分析新情境。提升认知需要系统性学习：先建立猜想模型，反复验证，补充案例，并连接相关领域形成知识体系，最终将大脑打造成能处理复杂问题的“大工厂”。', '["认知不是知识量的堆积，而是识别现实条件、提炼底层规律并将规律灵活迁移的能力", "知识内容的价值在于其背后的生成逻辑，理解“为什么”远比记住“是什么”重要", "提升认知需要系统性地连接知识，构建可验证、可扩展的思维模型，而非孤立学习", "有效学习的方法是围绕主题深度探索，先建猜想模型，再反复印证、补充细节，最后扩展为知识体系"]', '[{"topic": "思维模型", "why": "思维模型是认知的核心构件，理解其构建与运用方法，能大幅提升分析复杂问题的能力", "direction": "可阅读《穷查理宝典》中关于多元思维模型的论述，或学习查理·芒格的跨学科方法"}, {"topic": "图式理论与建构主义学习", "why": "视频中“先建模型再验证”的策略与心理学的图式理论高度吻合，深入探究能优化个人学习方法", "direction": "可研读皮亚杰的建构主义认知发展理论，或学习《人是如何学习的》中关于知识组织的内容"}, {"topic": "系统性深度工作", "why": "碎片化学习是认知提升的大敌，了解如何通过深度工作构建知识体系，对长期成长至关重要", "direction": "推荐阅读卡尔·纽波特的《深度工作》，实践主题式学习和知识网络搭建"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1783934079, 1784011562, '239.8403125', '185.18283486366272', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7651193310380237730', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '自我重启 #清华学霸 #家里蹲 #重启这一年 #人生', '自我重启 #清华学霸 #家里蹲 #重启这一年 #人生', 1781432264, 'https://www.douyin.com/video/7651193310380237730', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oYBPMUPCjG2QBhW7FUgDieAGrfA8A5e5tSXg5M~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=HPrFaS1NNTUKcc4o0k4T6hMGxqU%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151050BC0FC80B5C4E97EBA5E9', 13381, 7372, 99, 1434, 'done', 0, 'data/text/7651193310380237730.txt', 'data/summaries/7651193310380237730.md', '视频以作者考研失败后的‘家里蹲’经历为引，探讨人生暂停或失败的三重价值：一是脱离外在标签和社会期待，在孤独中看清真实关系与自我位置；二是打破自我幻想的泡沫，从顺境陶醉中清醒，直面真实能力；三是在失控后通过微小行动重建掌控感，于日常细节中重寻生命意义。最后强调，暂停期还能冷静审视理想，发现短板并规划可行路径，但须保持希望与计划，避免沉沦。核心观点是，短暂的脱轨并非坏事，而是自我重启、回归本真的契机。', '["人生暂停能打破外在标签的束缚，帮助看清真实的人际关系和自我位置。", "失败是跳出自我幻想泡沫的契机，让人直面真实的自己，停止表演人生。", "在失控后从微小行动开始，可以重建生活的掌控感，于细节中重新发现意义。", "暂停期提供了审视理想、发现短板并规划具体路径的空间，但需保持希望与计划以避免沉沦。"]', '[{"topic": "社会角色与标签理论", "why": "视频深刻揭示了社会标签如何限制自我认知，理解该理论有助于分析身份认同的构建与束缚。", "direction": "可阅读欧文·戈夫曼的《日常生活中的自我呈现》，了解‘镜中我’等概念，或钻研贝克的标签理论。"}, {"topic": "存在主义心理学中的意义疗法", "why": "视频强调在微小日常中重新发现意义，与维克多·弗兰克尔的意义疗法核心思想一致，即在任何境遇中都能选择态度并创造意义。", "direction": "推荐阅读维克多·弗兰克尔的《活出生命的意义》，学习存在主义心理治疗的基本理念。"}, {"topic": "自我决定理论与内在动机", "why": "视频提到摆脱外在要求、回归自我掌控的状态，与自我决定理论中的自主性、胜任感、关系需求三维度相关，有助于理解持续行动的动力来源。", "direction": "阅读爱德华·德西与理查德·瑞安的《自我决定理论》，或相关论文，了解内在动机的培养。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1783934923, 1784011654, '325.800625', '194.05320692062378', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7648579420102238031', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何自己利用AI报志愿 #清华学霸 #高考志愿填报 #人类对豆包的开发不足百分之一 #豆包也太会写了 #我的同事豆包', '如何自己利用AI报志愿 #清华学霸 #高考志愿填报 #人类对豆包的开发不足百分之一 #豆包也太会写了 #我的同事豆包', 1781258414, 'https://www.douyin.com/video/7648579420102238031', 'https://p3-pc-sign.douyinpic.com/tos-cn-p-0015/oo2AIAfiEgEn137DIIBpeXAI7SIjilAaB3opNl~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=MIHF9hL%2B4SAYVaQNgjpePBBynR0%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141510520D77CA7C6D3033AC7E24', 16255, 7322, 394, 1863, 'done', 0, 'data/text/7648579420102238031.txt', 'data/summaries/7648579420102238031.md', '高考志愿填报是考生人生中的关键抉择，但面对海量信息，许多人感到无从下手。本文介绍一种利用AI工具（如豆包）自主完成志愿筛选的方法。通过使用AI的编程功能生成个性化筛选网站，考生可直观看到分数匹配的院校；将名单导出为Excel后，利用AI表格功能进行多维度排序，得到精准优先级；最后用AI写作功能生成生活环境对比，全面评估目标学校。这一流程不仅节省时间，更让考生和家长保留选择权，避免被他人或商业套路左右。AI作为辅助工具，帮助梳理数据，但最终决策仍应基于个人价值观和意愿。', '["利用AI生成个性化筛选网站，自主掌握院校匹配情况。", "通过Excel导出与AI排序，实现多维度精准志愿筛选。", "借助AI生成生活环境对比报告，辅助全面决策。", "AI作为工具能提升效率，但最终决策权始终归人所有。"]', '[{"topic": "自然语言生成与低代码开发", "why": "视频展示通过自然语言指令让AI编写网页，这背后涉及大型语言模型的代码生成能力，是未来非技术人员实现想法的关键技术。", "direction": "学习提示工程（Prompt Engineering）和基础Web开发概念，阅读相关论文或教程了解GPT-4等模型的代码生成原理。"}, {"topic": "多属性决策与数据驱动选校", "why": "志愿填报本质是多属性决策问题，需要考虑分数、兴趣、就业、地域等。AI辅助的量化排序方法值得教育工作者和学生掌握。", "direction": "研究多属性效用理论（MAUT）或层次分析法（AHP），阅读《决策分析》相关书籍，思考如何构建个人化的评价模型。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1783935000, 1784011719, '113.1058125', '76.24915814399719', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7645998410961070260', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '中等生陷阱之自命不凡 #清华学霸 #中等生 #自命不凡 #学习方法', '中等生陷阱之自命不凡 #清华学霸 #中等生 #自命不凡 #学习方法', 1780222732, 'https://www.douyin.com/video/7645998410961070260', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o8leBfIYDAYqFszAu4EFAAQjHBDQzMTgjN9xpA~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=8OdJrnDHO12Z8%2BCgTXIcaMGhUoY%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151055647F5FF810E4F7EF2076', 17187, 8753, 239, 1821, 'done', 0, 'data/text/7645998410961070260.txt', 'data/summaries/7645998410961070260.md', '视频剖析了中等生常见的‘自命不凡’陷阱：部分学生因早年经历或幻想，自认是‘天选之人’，高人一等，于是将知识分为三六九等，轻视基础，热衷难题。这种分类导致他们基础不牢，考试中因‘马虎’丢分，却归咎于精神状态而非知识欠缺，形成自欺闭环。他们依赖短时激发的意志力，陷入内耗，最终要么偏科固执，要么萎靡不振。视频指出，要跳出陷阱，须放弃知识分类，踏实内化简单内容，将宏愿落地为实际努力，以成绩而非幻想证明自己。', '["自命不凡的学生认为自己天生高人一等，并将知识划分为“垃圾”与“好知识”，轻视基础。", "忽视简单题和背诵等基础内容，导致考试中频繁因“马虎”丢分，形成自欺欺人的借口闭环。", "他们过度依赖短时意志力爆发，陷入内耗和偏科，总分始终难以突破。", "跳出陷阱的关键在于放弃知识分类，踏实内化所有知识，将宏大理想落实到具体行动中。", "真正的优秀需通过实际成绩证明，而非沉浸于自我幻想的优越感。"]', '[{"topic": "自命不凡的心理机制——达克效应", "why": "了解能力越低的人越容易高估自己的认知偏误，有助于看清这种心态的根源，避免自我欺骗。", "direction": "可阅读《知识错觉》或研究“邓宁-克鲁格效应”相关论文，理解元认知缺陷。"}, {"topic": "知识内化与刻意练习", "why": "视频强调将简单知识内化为思维本能，这正是刻意练习的核心：通过重复和专注，让基础技能自动化。", "direction": "推荐阅读安德斯·艾利克森的《刻意练习》，掌握如何有效训练基础能力。"}, {"topic": "意志力的自我损耗与善用", "why": "视频提出意志力不可盲目锻炼，需善用在关键时刻，这涉及心理学中的自我损耗理论。", "direction": "可学习罗伊·鲍迈斯特的《意志力》一书，理解意志力的有限性及科学管理方法。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1783935265, 1784011775, '352.828625', '265.3592357635498', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7645256207335747252', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '差生陷阱之傻瓜模拟器 #清华学霸 #差生 #反应慢半拍 #抖音精选app', '差生陷阱之傻瓜模拟器 #清华学霸 #差生 #反应慢半拍 #抖音精选app', 1780049925, 'https://www.douyin.com/video/7645256207335747252', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oQelaqUQfABMA3DlAAUZW8IgvF92WGS6kDEIAk~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=GPgYxUxT5UN2VglVqTq%2BafG8s4Q%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415105713B8B18329BB64166B8B', 2793, 1311, 55, 405, 'done', 0, 'data/text/7645256207335747252.txt', 'data/summaries/7645256207335747252.md', '视频揭示了“差生陷阱”中的“傻瓜模拟器”现象：一些学生通过扮演反应慢、笨拙的角色来逃避责任和压力，实则是一种自我保护。他们因长期处于被批评、打压的下位环境，害怕出错而不敢展现真实能力，内心保留着一个不被期望的小世界。这种伪装不仅未能减压，反而因外界期望更高陷入恶性循环。视频指出，改变的关键在于敢于表达、认识到学习是自己的事，并鼓励“偷偷学习”以对自己负责，同时忽略那些缺乏具体方法的空洞要求。核心论点是：差生不笨，只是环境塑造了其防御行为，跳出陷阱需重拾自主权。', '["“傻瓜模拟器”是差生通过扮演迟钝来逃避责任和压力的心理防御机制。", "缓慢表现源于害怕出错，根源在于长期被批评打压的下位环境。", "伪装背后藏着一个不为人知的小世界，学生不敢展现真实想法以免被攻击。", "跳出陷阱需要敢于表达、认识到学习是自己的事，并用“偷偷学习”对自己负责。", "忽略缺乏具体方法的空洞要求，避免为无效期待自我损耗。"]', '[{"topic": "习得性无助", "why": "“傻瓜模拟器”本质上是习得性无助的变体：当学生反复受到打压，认为自己无法掌控结果，便放弃努力甚至主动表演无能。深入这一概念能更系统理解行为背后的心理机制。", "direction": "可阅读马丁·塞利格曼的《习得性无助》原著或相关积极心理学著作，了解从无助到乐观的转变路径。"}, {"topic": "自我决定理论", "why": "视频强调“学习是自己的事”，这与自我决定理论中的自主需求高度契合。被剥夺自主权的孩子更容易发展出伪装行为。探究该理论有助于设计激发内在动机的环境。", "direction": "推荐阅读爱德华·德西与理查德·瑞安的《自我决定理论》，关注如何通过支持自主来促进成长。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1783935507, 1784011813, '312.3794375', '240.9512939453125', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7644571066065658978', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '焦虑的来源 #清华学霸 #焦虑 #成长 #学生思维 #抖音精选app', '焦虑的来源 #清华学霸 #焦虑 #成长 #学生思维 #抖音精选app', 1779890402, 'https://www.douyin.com/video/7644571066065658978', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oQYIWeNOgoxDMIWE1tkGeCg24NALCBeAeADogg~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=a7saK9EbQ76eabED9uGw7X5Jz8Y%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141510591388C45C939221033A7A', 1281, 519, 28, 144, 'done', 0, 'data/text/7644571066065658978.txt', 'data/summaries/7644571066065658978.md', '视频指出，学生群体中普遍存在的焦虑根源在于外在规则（如学校竞争标准）的异化。学校在育人同时施加社会规则，这些规则在竞争下不断上移，形成脱离实际的压迫感。个体将这种外在压力内化为自我要求，导致思想与身体对立，思想成为奴隶主，不断否定身体和努力，使人永远感觉“不够好”。这种内在冲突破坏了身心统一，使人无法获得真正的快乐与成功。缓解焦虑的关键在于重新关注自身具体经历，打破虚幻标准，看见真实的自己。', '["焦虑的本质是外在规则通过教育和社会竞争内化为自我压迫，而非单纯的个人心理问题。", "标准在竞争环境中不断上移，形成一种无形的、针对大多数人的压迫感。", "个体误将外部压力当成自我要求，导致思想与身体对立，陷入“永远不够好”的自责循环。", "身心分裂使个体失去内在驱动力，无法获得真正的成就感和快乐。", "缓解焦虑的有效途径是回归具体经验，关注真实的自己，打破虚幻的理想标准。"]', '[{"topic": "权力异化与规训", "why": "理解社会规则如何通过教育等机制塑造个体的自我认知和行为模式，是分析当代焦虑的关键视角。", "direction": "阅读米歇尔·福柯的《规训与惩罚》，了解权力如何通过标准化、考核等手段内化为自我监督。"}, {"topic": "内化与自我决定理论", "why": "区分外部动机和内部动机有助于识别焦虑的根源，发展真正自主的行为动力。", "direction": "学习心理学中的自我决定理论（SDT），阅读爱德华·德西和理查德·瑞安的著作，理解自主性、胜任感和归属感对心理健康的作用。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1783935755, 1784011901, '311.77575', '247.93500423431396', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7643424899633740520', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '高考如何超常发挥 #清华学霸  #超常发挥  #高考守护者 #抖音精选应援联盟 #高考AMA', '高考如何超常发挥 #清华学霸  #超常发挥  #高考守护者 #抖音精选应援联盟 #高考AMA', 1779623539, 'https://www.douyin.com/video/7643424899633740520', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oYAg61XBI5KiABievAIAVhADy5gfug3S0ICInB~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=xldKVJEb9iRIsr1CzfsTEA8z2Pc%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151102F6AA8B8C57F9D1083EB7', 982, 492, 11, 147, 'done', 0, 'data/text/7643424899633740520.txt', 'data/summaries/7643424899633740520.md', '视频指出高考超常发挥的秘诀并非在最后时刻查漏补缺，而是聚焦已掌握的知识，确保拿到八成基础分。许多学生三年只关注“不会什么”，却忽略“会什么”，导致考场波动。考前三件要事：第一，通读教材并对熟悉知识点自我确认，夯实基础；第二，整理错题时只梳理思路，完善思维而不重复自测，避免焦虑；第三，通过计时训练培养时间感，严格控制每题用时，超时难题果断放弃，将精力集中于能得分的题目。高考成功的关键在于扎实的基础、平稳的心态和合理的精力分配。', '["高考超常发挥的关键是巩固已会知识，而非追逐难题。", "考前回归教材并自我肯定，可以强化信心和基础。", "高效处理错题在于整理思路完善思维，而非反复自测。", "通过时间感训练掌控做题节奏，确保精力合理分配。", "遇到超时难题要果断放弃，把时间留给能得分的题目。"]', '[{"topic": "自我效能感与考试心态", "why": "通过确认已会知识来增强信心，这与心理学中的自我效能感理论高度相关，能有效降低考试焦虑，提升临场发挥的稳定性。", "direction": "建议阅读班杜拉的《自我效能：控制的实施》，或了解认知行为疗法（CBT）中的积极自我对话技术，练习如何在考前建立“我能行”的信念。"}, {"topic": "时间知觉与帕金森定律", "why": "限定时间完成任务能够避免时间膨胀，帕金森定律指出工作会自动占满所有可用时间，考试中训练严格的时间控制能提升效率。", "direction": "可学习番茄工作法及其背后的心理学原理，尝试用计时器模拟考试环境，研究时间压力如何影响决策和表现。"}, {"topic": "沉没成本误区与果断放弃", "why": "考生常因已投入时间而不愿放弃难题，这属于沉没成本谬误；学会识别并果断止损，是优化考场资源分配的关键策略。", "direction": "阅读丹尼尔·卡尼曼的《思考，快与慢》，了解前景理论及决策中的非理性陷阱，通过模拟练习强化“放弃”反应。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1784009970, 1784011954, '205.0', '33.340484857559204', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7642673375559540968', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '虚假目标 #清华学霸 #学习误区 #学习方法 #目标 #抖音精选app', '虚假目标 #清华学霸 #学习误区 #学习方法 #目标 #抖音精选app', 1779448563, 'https://www.douyin.com/video/7642673375559540968', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oUWUDep9GBBULaIBXAI6H9geICGgSgTAp07fUA~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=cdto%2BXugX8mqON4ZXOoPt1o7TKU%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415110411B83366775A8AA2E6C0', 76010, 47131, 552, 9211, 'done', 0, 'data/text/7642673375559540968.txt', 'data/summaries/7642673375559540968.md', '视频探讨了“虚假目标”现象，指出许多人通过设立过大、遥远的目标来幻想成功，却因完美主义和全有或全无思维陷入循环：制定宏大计划时获得多巴胺代偿，行动却迟缓，最终导致快速放弃与抑郁。这种心理源于自卑加完美主义，常与童年过高要求有关。为打破恶性循环，视频提出三种方法：将大目标细化成当下可执行的小步骤，变未来为现在；理解现实要求是“做到”而非“完美”，避免追求一百分而瘫痪；以及将计划直接减半，从概念自我回归现实自我。通过贴近实际的行动，才能真正实现目标，摆脱虚假希望综合症。', '["设立过大且遥远的目标会导致多巴胺代偿，形成幻想替代行动的恶性循环。", "全有或全无的零一逻辑使人一旦做不到完美便完全放弃，阻碍渐进式进步。", "将大目标细化为当下可执行的小步骤，是落地行动的关键。", "多数事情只需做到六十分，完美主义往往是拖延的根源。", "计划减半能帮助我们从概念自我回归现实自我，降低行动门槛。"]', '[{"topic": "虚假希望综合症", "why": "理解其机制有助于识别用幻想替代行动的心理陷阱，避免陷入反复计划却无行动的循环。", "direction": "可阅读《拖延心理学》中关于目标设定与情绪调节的章节，或研究心理学中“行动阶段模型”的相关概念。"}, {"topic": "多巴胺与目标追求", "why": "了解多巴胺在目标设定时的作用能解释为何幻想也能带来快感，从而警惕大脑奖赏系统的误用。", "direction": "可学习神经科学相关内容，如《自控力》中多巴胺与动机的关系，或听听 Andrew Huberman 的播客。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1784009990, 1784033371, '251.0', '19.255072116851807', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7640813489506170978', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '精力无法集中 #抖音精选高考应援福利 #清华学霸 #抖音精选高考应援联盟 #高考守护者 #精力 #2026高考', '精力无法集中 #抖音精选高考应援福利 #清华学霸 #抖音精选高考应援联盟 #高考守护者 #精力 #2026高考', 1779015523, 'https://www.douyin.com/video/7640813489506170978', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oQ2Az2qfAn9sEPQAFZAMKIIDJgaDCGgBgsf32n~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=fxGlXyUOpbRZsCQ4JQjExiS%2F%2Bug%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151107A9B19CBC9E760A87F043', 9569, 5168, 66, 745, 'done', 0, 'data/text/7640813489506170978.txt', 'data/summaries/7640813489506170978.md', '视频指出，许多学生精力无法集中、精神涣散，并非因为不够专注，而是源自过度自我填充导致的不安全感。越害怕犯错，就越想把每分每秒、每个细节都填满，结果精力反而更分散。解决之道在于：承认精力有限，学会分主次，通过分析作者书写目的来识别核心重点，合理分配高低精力投入；同时将思绪外化到纸面上，用理性分析替代感性恐惧，逐步摆脱紧张，恢复专注。核心论点强调，真正的专注来自勇于取舍与理性管理，而非无止境地压榨自己。', '["精力无法集中常因过度自我填充导致，根源是害怕出错的不安全感。", "人的精力有限，必须敢于分主次，将高精力投入真正重要的地方。", "通过分析作者书写目的，可以快速识别文本核心，合理分配阅读精力。", "将思绪和问题写在纸上，能有效缓解焦虑，用理性替代感性恐惧。"]', '[{"topic": "精力管理", "why": "它揭示了专注并非靠意志力硬撑，而是需要策略性地分配有限资源，对高效学习至关重要。", "direction": "可阅读《精力管理》一书，学习体能、情感、思维和意志四个维度的精力恢复技巧。"}, {"topic": "阅读策略与分析性阅读", "why": "学会判断文本目的、区分主次信息是提升学习效率的核心能力，避免无用功。", "direction": "推荐学习SQ3R阅读法或《如何阅读一本书》，重点练习分析作者意图和提问技巧。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1784010006, 1784033405, '184.0', '15.216247081756592', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7638226476555172066', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何提问 #清华学霸 #提问 #问问题评论区 #学习方法 #抖音精选app #抖音精选高考应援联盟 #2026高考', '如何提问 #清华学霸 #提问 #问问题评论区 #学习方法 #抖音精选app #抖音精选高考应援联盟 #2026高考', 1778413187, 'https://www.douyin.com/video/7638226476555172066', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oo4DgvtcEK5AiAQrQIwAaAoPQzyIIJYBibdzB~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=3N%2Fk%2FiZCepUksMXbLv1T6IjloL8%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151109D6EA842532EAC544A007', 1901, 962, 15, 190, 'done', 0, 'data/text/7638226476555172066.txt', 'data/summaries/7638226476555172066.md', '很多同学在向老师或AI提问时，常因缺乏背景描述而难以获得有效答案。视频指出，优质提问的关键在于帮助回答者“情景模拟”：首先，需详细说明具体背景和处境，让对方能代入你的场景；其次，针对个人问题（如学习或心理困扰），还需透露你的思考过程和尝试，以便回答者模拟你的思维路径。对于情绪类问题，更要精准定位情绪卡点。最终，提出一个高效公式：现状背景 + 卡点及想法尝试 + 期望的答案形式。掌握这一方法，能大幅提升提问效率，获得更具针对性的帮助。', '["提问时需详细描述具体背景和情境，帮助回答者代入场景", "涉及个人问题时要坦露自己的想法和尝试，便于回答者进行人格模拟", "心理和情绪问题需精准定位情绪卡点，才能获得有效解决方案", "高效提问公式：现状背景 + 卡点及想法尝试 + 明确想要的答案形式"]', '[{"topic": "情境化沟通与共情模拟", "why": "提问的本质是帮助对方建立共情，这与心理学中的情境认知理论相关，理解其原理能提升人际沟通效率", "direction": "可阅读《人性的弱点》中关于“真诚地站在他人角度”的章节，或学习“非暴力沟通”框架"}, {"topic": "元认知与问题表征", "why": "明确自己的想法和尝试属于元认知监控，将问题清晰表述能促进深层解决，对自主学习至关重要", "direction": "研究“波利亚解题表”中的“拟定计划”环节，或阅读《学习之道》中关于问题拆解的内容"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1784010014, 1784033545, '98.0', '7.939604997634888', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7637453516773340367', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '时间失衡 #清华学霸 #高考守护者 #抖音精选高考应援联盟 #全民守护高考倒计时30天  #高考过来人100招 #2026高考', '时间失衡 #清华学霸 #高考守护者 #抖音精选高考应援联盟 #全民守护高考倒计时30天  #高考过来人100招 #2026高考', 1778233219, 'https://www.douyin.com/video/7637453516773340367', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oob7yfEv9yQUk9G4BR7xr0AIDfA6FBAdeC5TaI~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=MVOQJcMP%2B6RLCqmNZve2Zj5QHnM%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141511120B6EEA0734FABEE341F6', 6600, 2683, 18, 625, 'done', 0, 'data/text/7637453516773340367.txt', 'data/summaries/7637453516773340367.md', '视频聚焦于学生常见的“时间体感失衡”问题，即做题时走神、拖延，导致效率低下。主讲人提出了一套三阶段训练法来解决这一困扰：第一阶段通过专注观看秒针3~5分钟，重建对时间流动的身体知觉；第二阶段在刷题时严格限时，坚持“时间大于正确率”的原则，超时立刻跳过，避免内耗；第三阶段脱离计时工具，凭感觉估算时间，并与实际用时对比校准，若不准则返回前两步继续训练。这套方法由外而内，帮助学习者重新掌控时间节奏，提升学习效率与考试表现。', '["时间体感失衡表现为走神、拖延，根源在于内部时钟与客观时间脱节。", "看表训练通过专注秒针流动，唤醒身体基础的时间知觉。", "限时刷题必须遵守“时间大于正确率”原则，超时即停，避免无效内耗。", "估算练习需从短时段开始，反复对比真实时间，校准内在时钟。", "三个阶段循序渐进，从外在工具到内在感知，逐步重塑时间掌控力。"]', '[{"topic": "时间知觉与认知心理学", "why": "理解时间知觉的心理机制有助于科学设计训练，提升时间管理效果。", "direction": "可阅读《认知心理学》相关章节，或研究“时间知觉”的经典实验，如韦伯定律在时间估计中的应用。"}, {"topic": "限时策略与考试技巧", "why": "限时不仅是速度训练，更是决策能力训练，对标准化考试至关重要。", "direction": "参考《如何学习》中关于间隔练习和测试效应的论述，或了解衡水中学等名校的限时训练模式。"}, {"topic": "心流状态与时间扭曲", "why": "当高度专注时，时间感会发生变化（如“光阴似箭”），善用心流状态可以提升学习愉悦感和效率。", "direction": "阅读米哈里·契克森米哈赖的《心流：最优体验心理学》，学习如何在学习中进入心流。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1784010025, 1784033727, '122.0', '10.584418058395386', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7636364957655256384', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '《给妻子的历史课》 #清华学霸 #中国古代史 #世界观 #个人成长', '《给妻子的历史课》 #清华学霸 #中国古代史 #世界观 #个人成长', 1777979769, 'https://www.douyin.com/video/7636364957655256384', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/osfLuExAwAzePHiYeAIYtSAgXkCfYLHdxVfoiO~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=xLjrfG4vlfgHMAQLH1tyRh6QDxg%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141511149CE5487D626F94EC65B7', 187, 56, 8, 19, 'done', 0, 'data/text/7636364957655256384.txt', 'data/summaries/7636364957655256384.md', '该视频介绍了一个名为《给妻子的历史课》的中国古代史课程，由一位清华学霸为其妻子讲授。视频主旨在于通过通俗易懂的方式普及中国古代史知识，帮助人们理解现代文化中许多常见现象的根源。核心论点是：了解历史能让我们看清问题的本质，从而更好地把握现在和未来。课程采用官方和学术界认可的史料，旨在提升人文素养，使学习者能够以更深刻的视角看待问题。', '["学习历史能帮助我们理解现代文化现象的根源。", "课程采用通俗易懂的方式，适合零基础学习者。", "历史知识能提升人文素养，使人看问题更深刻。", "了解过去是把握现在和未来的基础。"]', '[{"topic": "中国古代史中的文化传承", "why": "理解文化传承有助于解释现代社会中许多看似矛盾的现象，例如传统与现代的冲突与融合。", "direction": "阅读《中国文化史》或相关学术论文，关注文化符号的演变与延续。"}, {"topic": "历史视角下的问题本质分析", "why": "历史视角能帮助人们超越表面现象，洞察社会问题的深层原因，从而做出更明智的决策。", "direction": "学习历史分析方法，如年鉴学派的长时段理论，或阅读《历史的教训》等书籍。"}]', 'deepseek_chat', 'deepseek-chat', 1783921446, 1784022334, 1783923558, '59.6524375', '131.30844521522522', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7636022156296036800', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '《给妻子的中哲课》 #清华学霸 #中国哲学 #世界观 #忽然知己', '《给妻子的中哲课》 #清华学霸 #中国哲学 #世界观 #忽然知己', 1777899954, 'https://www.douyin.com/video/7636022156296036800', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oMsY2BdILtiEAw2fAgw4xDpbmH9TfAAciIkBAb~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=SztoyiBzlhRXpwB7pe0Cf8pRcKA%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141511168EC31503CC7CFFFE6424', 354, 104, 7, 22, 'done', 0, 'data/text/7636022156296036800.txt', 'data/summaries/7636022156296036800.md', '本视频介绍了一门中国哲学通史课程的由来与特色。作者因妻子作为理科艺术生的思维局限，特意录制该课程助其突破认知瓶颈。课程体系以中国古代三十一位思想家为线索，通过梳理哲学史的发展逻辑，最终聚焦于王阳明心学的集大成。它摒弃了繁琐的细节考据，着重勾勒每位哲人的核心思维轮廓及思想演进脉络，适合零文科基础的入门者。课程不仅传授智慧，更强调将古人哲理活用于现代生活，解决现实问题。整体而言，这是一门以学术史为经、以实践应用为纬的哲学通识课，旨在通过系统学习，让学习者获得心灵的提升与实际的受益。', '["课程从中国古代三十一位思想家入手，系统梳理中国哲学的发展逻辑和核心概念。", "强调学习哲学史是理解思想精髓的关键，尤其以王阳明心学为最终落脚点，展现其来龙去脉。", "适合零基础入门者，注重勾勒思维框架而非繁琐细节，提纲挈领地呈现思想演变。", "课程最终目标是让学习者能将古人智慧活用于现实生活，解决实际问题，突破思维局限。"]', '[{"topic": "王阳明心学", "why": "心学融合儒释道精髓，是宋明理学的高峰，其“知行合一”等命题对现代个人的自我完善与管理实践有深刻启发。", "direction": "研读《传习录》原著，结合陈来《有无之境——王阳明哲学的精神》等学术著作，探究心学的理论体系与修炼方法。"}, {"topic": "中国哲学史的学习方法", "why": "以“学科史”视角贯穿思想演进，能帮助学习者建立整体观，避免断章取义，深刻理解哲学的现实关怀。", "direction": "参考冯友兰《中国哲学简史》、张岱年《中国哲学大纲》，学习如何以历史脉络把握概念演变。"}, {"topic": "中国哲学的实践性特质", "why": "中国哲学始终将修身与治世相结合，对治现代生活的意义失落与知行分裂有独特的资源价值。", "direction": "阅读余英时《中国近世宗教伦理与商人精神》，或通过比较中西哲学实践观，理解中国哲学如何将智慧转化为生活方式。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1784010037, 1784033844, '141.0', '11.780011892318726', 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7635600192565788584', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '完美主义 #清华学霸 #学习方法 #个人成长 #完美主义  #抖音精选app #抖音精选高考应援联盟 #2026高考', '完美主义 #清华学霸 #学习方法 #个人成长 #完美主义  #抖音精选app #抖音精选高考应援联盟 #2026高考', 1777801708, 'https://www.douyin.com/video/7635600192565788584', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/osCWfPYe7TIHvGBqCCGuILLjUe07AAAQa5MqQB~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=bLZR1t2vbJsUvP3XzETK9ScV4%2B8%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141511191D728BBC1ED2759F612C', 35065, 21761, 253, 3561, 'transcribing', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1783932814, NULL, NULL, NULL, NULL, 1783921424, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7634134713661457014', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', 'DMN #清华学霸 #dmn #胡思乱想 #学习状态', 'DMN #清华学霸 #dmn #胡思乱想 #学习状态', 1777460499, 'https://www.douyin.com/video/7634134713661457014', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oQIxIBAoe5SfAdB0Ii3BvlorrjzASiFgNmHRBa~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=5Or53yfKMG2waIQ6HrsPxBuKuV8%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141518196E6A0ACF82D9450969E5', 1135, 466, 29, 105, 'done', 0, 'data/text/7634134713661457014.txt', 'data/summaries/7634134713661457014.md', '视频揭示了默认模式网络（DMN）作为大脑后台系统，在走神、发呆时活跃，常引发自我怀疑、回忆过去与灾难化想象，从而否定当下行动。若不加控制，它会反客为主，导致焦虑与分心。为化被动为主动，视频提出四种驾驭方法：一是及时自我定义与事件确认，阻断反复纠结；二是主动引导DMN进行面向事情的创造性想象，激发创造力；三是借助番茄工作法，以25分钟专注、5分钟自由联想的方式有节律地释放DMN；四是通过读秒等当下锚定技巧打断思维漫游。核心观点是将DMN从内耗源头转化为潜意识分析工具，提升学习效率与心理状态。', '["DMN是大脑走神、自我怀疑的神经基础，常否定当下行动。", "通过及时自我定义和确认事件的结论，可以减少DMN的反复循环。", "主动引导DMN进行面向事情的自由想象，能转化为创造力的源泉。", "运用番茄工作法，有规律地释放DMN，避免压抑带来的失控。", "通过读秒、合十等行为技巧，可以迅速将注意力拉回当下。"]', '[{"topic": "默认模式网络（DMN）", "why": "了解DMN的神经机制有助于理解走神、自我反刍的根源，是认知控制和心理健康的重要概念。", "direction": "可阅读神经科学家马库斯·雷切尔的相关研究，或书籍《大脑的未来》《心流》等。"}, {"topic": "番茄工作法", "why": "该方法不仅是时间管理技巧，更与大脑认知节律相契合，能有效平衡专注与发散思维。", "direction": "可阅读《番茄工作法图解》一书，实践并调整适合自己的专注间隔。"}, {"topic": "正念与当下锚定", "why": "读秒、合十等技巧本质上是正念练习的变体，帮助增强对当下的觉察，减少思维漫游。", "direction": "可学习正念减压（MBSR）课程，或阅读《正念：此刻是一枝花》等书籍。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1784011174, 1784034013, '228.0', '17.76881694793701', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7633014187383732456', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '自我怀疑 #清华学霸 #自我怀疑 #学习焦虑', '自我怀疑 #清华学霸 #自我怀疑 #学习焦虑', 1777199606, 'https://www.douyin.com/video/7633014187383732456', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ooeBq2BXwFtSACGXoTmx7dAvkEQkfBbDQb0fnQ~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=LfoKeOh6ya4kuHmA4uxotLJOXS0%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151821144C5C39A2D4CB987237', 4563, 2278, 27, 348, 'done', 0, 'data/text/7633014187383732456.txt', 'data/summaries/7633014187383732456.md', '视频探讨了学生普遍存在的自我怀疑问题，指出其根源在于过度依赖外部反馈（如老师、家长、成绩），将学习水平等同于他人态度，导致情绪不稳与考试失常。核心论点是：真实的学习成绩由对知识的记忆、理解和应用决定，而非外部评价。学习是分数叠加的过程，每天掌握内容并刷题验证，就能量化自己的水平，从而建立不被外界干扰的自信。解决自我怀疑的方法就是持续学习与刷题，用内部反馈替代外部揣测。', '["自我怀疑的根源是过度依赖外部反馈，将学习水平等同于他人的态度和评价。", "真实的学习成绩由对知识的记忆、理解以及在题型中的应用决定，而非外部环境。", "学习可以量化为分数叠加的过程，每天掌握内容并刷题验证，就能清晰评估自己的水平。", "应对自我怀疑的方法是持续学习与刷题，用内部客观反馈替代主观揣测。"]', '[{"topic": "内部反馈与外部反馈的心理学原理", "why": "理解为何依赖外部反馈会导致焦虑和自我怀疑，有助于建立健康的学习心态。", "direction": "可阅读爱德华·德西的《内在动机》或关于自我决定理论的研究，深入探索内在动机与外在动机的关系。"}, {"topic": "学习效果的量化评估与掌握学习", "why": "量化评估能提供客观反馈，减少不确定性，是提升学习效率和信心的关键。", "direction": "学习本杰明·布鲁姆的“掌握学习”理论，或参考《刻意练习》中关于反馈与进步循环的内容。"}, {"topic": "测试效应与检索练习", "why": "刷题不仅是评估，更是强化记忆的有效手段，理解其原理能优化学习策略。", "direction": "研读《认知天性》等书籍，了解检索练习如何提升长期记忆，以及如何科学安排练习。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1784010368, 1784034058, '239.0', '19.003034830093384', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7630441968062328035', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何总结 #清华学霸 #总结 #复习 #错题本整理 #2026高考 #抖音精选高考应援联盟', '如何总结 #清华学霸 #总结 #复习 #错题本整理 #2026高考 #抖音精选高考应援联盟', 1776600715, 'https://www.douyin.com/video/7630441968062328035', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oUfkLQXEcq95AILIhBFpAxvDgHDy6ABpfM5As4~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=n1dtN9ki11dWDgQWKuY%2Fl1tW88M%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141518242124B2739B05943C53CC', 8502, 5662, 51, 893, 'done', 0, 'data/text/7630441968062328035.txt', 'data/summaries/7630441968062328035.md', '视频分享了清华学霸的总结方法，强调错题本不仅收录错题，更是零碎知识点的收纳工具。碎片知识包括理科巧思、背诵难点、补充概念及灵感等，它们虽不成体系，但一看便知，能快速触发复习。总结时要记录知识内容及其对体系补充的重要性，复习时通过自我提问“是什么”和“为什么”来加深理解，从而将碎片融入整体知识框架，提升学习效率。', '["错题本不仅是错题的集合，更应成为碎片化知识的收纳库。", "碎片知识可分为巧思类、背诵类、补充概念和灵感四种常见形态。", "记录碎片知识时需明确“是什么”和“为什么”，以激活后续回忆。", "复习时通过自我提问“记得什么”与“为何记它”来强化知识链接。", "总结的最终目的是将碎片融入主干体系，提升整体知识网络的牢固度。"]', '[{"topic": "王阳明“我心光明”与禅宗“空”的概念辨析", "why": "理解这一区别有助于深入把握儒家心学与佛家思想的根本差异，避免混淆，提升哲学思辨能力。", "direction": "推荐阅读《传习录》中王阳明对“心即理”的阐述，以及《六祖坛经》中关于“空”的讲解，对比二者对现实世界的态度。"}, {"topic": "碎片化知识的系统化管理方法", "why": "碎片知识容易遗忘，掌握系统化管理技巧如间隔重复、主动回忆等，能大幅提升学习效率。", "direction": "可学习《如何学习》一书中关于记忆的原理，或了解Anki等间隔重复软件背后的算法逻辑。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1784011201, 1784034253, '375.0', '26.142138957977295', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7629708576591936655', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '理解的四个层次 #清华学霸 #学习方法 #理解能力 #理解能力天花板 #理解力 #抖音精选高考应援联盟 #2026高考', '理解的四个层次 #清华学霸 #学习方法 #理解能力 #理解能力天花板 #理解力 #抖音精选高考应援联盟 #2026高考', 1776429959, 'https://www.douyin.com/video/7629708576591936655', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ociMyFB9DDp74vArKgE9Aa5eIfuHMVAEP7IIiB~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=H2x7sBpPFtG5edMF5OfBOB4OgxQ%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151826223A4A6C6A53AB748FBA', 12906, 8811, 74, 1459, 'done', 0, 'data/text/7629708576591936655.txt', 'data/summaries/7629708576591936655.md', '理解的四个层次，从被动识记到主动实践，揭示了“理解”的真正内涵。基础层次是识记，即对知识的符号记忆；其次是复现，能复述或想象场景，但仍是被动能力。第三层次解构与结构，要求主动拆解和重组知识，把握内部逻辑与外部联系，是理解的核心。最高层次是实践，分为应用与创造：应用是在限定条件下运用知识体系解决问题；创造则是跳出原有框架，构建新知识体系，实现彻底理解。这一框架解释了为何许多学生“感觉懂了但不会用”，并指明了提升理解能力的路径。', '["识记与复现是理解的被动层次，仅能应付简单记忆和复述，无法保证灵活运用。", "解构与结构是主动理解的核心，要求把握知识内部逻辑与外部联系，并能用自己的话重新表述。", "实践的第一层是应用，即在限定条件下灵活调动知识体系解决问题，是学以致用的关键。", "实践的第二层是创造，跳出原有框架组建新知识体系，达到彻底理解。"]', '[{"topic": "结构性思维与系统性思维", "why": "视频强调解构和结构背后是结构性思维和系统性思维，它们是高阶学习能力的基础，深入探究能从根本上提升学习效率。", "direction": "推荐阅读《金字塔原理》（芭芭拉·明托）学习结构化思维，或研究“系统思考”相关著作，如《第五项修炼》。"}, {"topic": "布鲁姆认知分类学", "why": "布鲁姆将认知目标分为记忆、理解、应用、分析、评价、创造六个层次，与视频中的四层次高度对应，系统学习该理论可更科学地规划学习。", "direction": "查阅《学习、教学和评估的分类学：布卢姆教育目标分类学修订版》等书，了解如何设定学习目标并评估理解深度。"}, {"topic": "知识体系构建方法", "why": "视频中提到用“树状知识体系”来组织和应用知识，探索具体方法能帮助我们将解构和结构能力落地。", "direction": "学习东尼·博赞的思维导图法，或理查德·费曼的学习技巧，实践用自己的话解释并检验理解。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1783932814, 1784011221, 1784034330, '385.0', '18.88309073448181', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7627843484678190964', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何控制手机 #清华学霸 #不玩手机 #自律 #学习', '如何控制手机 #清华学霸 #不玩手机 #自律 #学习', 1775995709, 'https://www.douyin.com/video/7627843484678190964', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/okpdzvpi7IJQaAkW05AiuBS8IwuqbIPKABPii~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=Vjydel1RwcI2uaKk8Nlc9HnADEQ%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141518280AD8A595DB682B74521E', 11310, 7055, 66, 1169, 'done', 0, 'data/text/7627843484678190964.txt', 'data/summaries/7627843484678190964.md', '本视频深入剖析了过度使用手机的危害及控制手机的有效方法。刷手机会导致虚拟时间与现实时间混淆，破坏生物钟和计划性；同时，碎片化信息虽带来疲惫感和虚假的学习满足感，却无法形成知识体系，削弱真正的学习欲望。为此，视频提出三种控制方法：一是物理隔离，通过将手机置于视线外并手捏小物件转移注意力；二是计划调整，坚持先苦后甜，利用独立计时工具并设置提前五分钟提醒以锚定现实时间；三是分段戒断，从吃饭、如厕、睡前等特定场景逐步减少手机依赖，睡前可通过简短复习巩固知识。这些策略有助于重建专注力与健康的生活节奏。', '["刷手机会导致虚拟时间与现实时间混淆，破坏生物钟和个人计划性。", "碎片化信息无法形成知识体系，会带来虚假的学习满足感并削弱真正的学习欲望。", "物理隔离是最直接的方法，将手机放于他处并手捏小物件可有效缓解戒断反应。", "采用先苦后甜的计划调整，并借助独立计时工具设定提前五分钟提醒以锚定现实时间。", "分段戒断法可通过特定场景（吃饭、如厕、睡前）逐步减少手机依赖，睡前可用简短复习替代玩手机。"]', '[{"topic": "信息过载与认知疲劳", "why": "了解大脑处理信息的机制，能让人意识到碎片化信息同样消耗认知资源，从而解释为何刷手机后感到疲惫却无实质收获。", "direction": "建议阅读《思考，快与慢》或深入了解认知负荷理论的相关文献。"}, {"topic": "多巴胺戒断与习惯回路", "why": "刷手机带来的即时快感与多巴胺分泌有关，理解戒断反应的生理机制有助于采取正确策略（如触觉替代）克服行为依赖。", "direction": "建议学习行为心理学中的习惯回路模型及多巴胺戒断的相关概念。"}, {"topic": "时间知觉与心流体验", "why": "沉浸于手机会扭曲时间感，研究时间知觉能帮助理解虚拟世界如何剥夺我们对现实的掌控，并寻找重建深度专注的方法。", "direction": "建议阅读米哈里·契克森米哈赖的《心流：最优体验心理学》。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784010424, 1784115529, '306.0', '26.51408290863037', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7627077603073425576', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何看网课 #清华学霸 #学习方法 #网课 #抖音精选app #2026高考 #抖音精选高考应援联盟', '如何看网课 #清华学霸 #学习方法 #网课 #抖音精选app #2026高考 #抖音精选高考应援联盟', 1775817388, 'https://www.douyin.com/video/7627077603073425576', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oszIABBbiiAgB7AgIejBDqPpGr06j60YgAVfBr~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=VBBA8Jc%2F03xtYU8XjesWuMtRFwA%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141518319C990BAB8CCF1F908DA9', 42614, 32802, 267, 5874, 'summarize_failed', 1, 'data/text/7627077603073425576.txt', NULL, NULL, NULL, NULL, NULL, NULL, 1783932814, 1784010446, NULL, '174.0', '20.584389209747314', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7625234555053607375', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '上班如何学习 #清华学霸 #上班学习两不误 #学习计划 #抖音精选app', '上班如何学习 #清华学霸 #上班学习两不误 #学习计划 #抖音精选app', 1775388270, 'https://www.douyin.com/video/7625234555053607375', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oUgfNEkppA9JRhR2ADBlLoy0FBYQDQf9nAdvSo~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=oPH%2BWtMHXxZsFY%2Bi4GbVgA1CDek%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151833E81329D3C0D9617FBA91', 75153, 56895, 643, 14734, 'done', 0, 'data/text/7625234555053607375.txt', 'data/summaries/7625234555053607375.md', '本视频探讨了上班族如何在工作中高效学习的问题。作者指出，上班学习面临两大困难：计划容易被突发工作打乱，以及难以找到一整段连续时间进入学习状态。对此，作者提出了分段学习法，将大块学习时间拆分为多个小段（如两小时拆成六个二十分钟），以动态计划替代固定时间计划。在每个学习小段中，采用先复习后学习的方法，通过短时间复习快速唤醒学习状态，再进行新知识学习。此外，完成一段学习后若未被工作打断，应切换到低强度学习模式，避免过度沉浸导致身心失调。最后，作者建议将学习任务按重要性分级，在计划被打扰时能做出取舍，从而保持整体计划的延续性和稳定性。', '["上班学习的两大困境：计划易被工作打乱、难以获得连续时间进入学习状态", "采用分段式学习法，将大块学习时间拆解为多个二十分钟小段，以动态计划适应工作节奏", "每个学习段采用先复习后学习的结构，利用回忆状态快速唤醒学习专注力", "完成一段学习后切换低强度模式，避免过度沉浸导致工作与休息之间的身心失调", "将学习段按重要性分级，在计划被打扰时能快速取舍，保持整体计划的延续性"]', '[{"topic": "番茄工作法与碎片化时间管理", "why": "视频中的分段学习法与番茄工作法有异曲同工之妙，深入理解时间管理理论可以帮助职场人更系统地规划碎片化学习", "direction": "可阅读弗朗西斯科·西里洛的《番茄工作法图解》，以及卡尔·纽波特的《深度工作》，对比碎片化学习与深度工作的适用场景"}, {"topic": "艾宾浩斯遗忘曲线与间隔重复学习", "why": "视频中提到的先复习再学习的方法，本质上利用了记忆唤醒机制，了解遗忘曲线能更科学地安排复习频率", "direction": "学习艾宾浩斯遗忘曲线理论，了解Anki等间隔重复软件的算法原理，探索如何将复习前置应用到职场学习中"}, {"topic": "任务优先级管理（四象限法则）", "why": "视频中对学习段进行重要性分级的方法与四象限法则相通，掌握优先级管理能帮助在不确定性高的环境中做出更好的取舍", "direction": "研究史蒂芬·柯维的《高效能人士的七个习惯》中的时间管理矩阵，以及敏捷开发中的任务看板管理方法"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784010464, 1784115865, '210.0', '18.255465984344482', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7623747707765431220', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '主动回忆 #清华学霸 #背诵 #学习方法 #抖音精选app #2026高考 #抖音精选高考应援联盟', '主动回忆 #清华学霸 #背诵 #学习方法 #抖音精选app #2026高考 #抖音精选高考应援联盟', 1775042086, 'https://www.douyin.com/video/7623747707765431220', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oEBZiHee2nIkuMC9EjGZuqLfFizMAAQQxgfhQD~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=rJ4IT9fK3Qhgl%2FVVsMtJ%2BFSdfIY%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141518354451EC5808E000BAC612', 46483, 36516, 256, 6571, 'done', 0, 'data/text/7623747707765431220.txt', 'data/summaries/7623747707765431220.md', '视频介绍了一种名为“主动回忆”的高阶学习法，旨在打破“看懂即学会”的学习假象，通过强迫大脑主动提取信息来真正掌握知识。其核心操作为：学习后立刻合上书本，在白纸上写下问题与关键词回答，并在脑海中复述，随后与原文对比找差距。该方法强调知识点间的逻辑结构、概念理解和步骤顺序，而非机械记忆原文文字。视频还给出了科学的复习频率建议，即在学习后立即、一天后、三至四天后、一周及一个月后进行五到六次间隔复习，以短期痛苦换取长期高效的记忆效果，确保知识内化以应对考试。', '["打破“看懂即学会”的假象，通过主动回忆强迫大脑提取信息。", "学完立刻合书，用白纸写下问题及关键词回答，并在脑中复述。", "对比原文找差距，通过重点词的反复连接逼近逻辑，而非死记硬背。", "核心在于知识点间的逻辑结构、概念理解和步骤顺序，而非文字本身。", "遵循间隔复习频率，学后立即、一天、三四天、一周、一个月共五到六次。"]', '[{"topic": "能力错觉", "why": "理解这一心理现象能帮助学习者警惕被动阅读带来的虚假掌握感，从而主动寻求有效的学习反馈。", "direction": "建议阅读《认知天性》中关于“学习错觉”和“元认知”的章节。"}, {"topic": "间隔重复效应", "why": "文中提到的复习频率本质上是间隔重复，掌握其规律能科学规划学习周期，最大化记忆留存率。", "direction": "学习“艾宾浩斯记忆遗忘曲线”及 Anki 等间隔重复软件的底层原理。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784010487, 1784115927, '258.0', '21.642000913619995', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7622684782245855976', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '下班后如何学习 #清华学霸 #下班学习 #快速休息 #精力恢复 #抖音精选app', '下班后如何学习 #清华学霸 #下班学习 #快速休息 #精力恢复 #抖音精选app', 1774794605, 'https://www.douyin.com/video/7622684782245855976', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o0tAYfTSGgf9DU3QBjnEApBDbAyFQOrlpkbthu~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=lD6PZXCJ1oF%2FZMSglEGr6IMtJl4%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141518388F4D2F6B81754EE7576D', 141041, 101444, 1519, 28815, 'done', 0, 'data/text/7622684782245855976.txt', 'data/summaries/7622684782245855976.md', '下班后学习的核心障碍在于精力枯竭，因此如何快速恢复精力成为关键。本视频针对这一痛点，提出了三种不同层级的快速休息方法，以适应不同的疲惫状态。第一是物理时钟限制法，通过引入外部时间提醒来避免沉迷手机，帮助大脑从虚拟世界中抽离；第二是冥想，通过呼吸和意念练习，将自我从工作的牵引与焦虑中剥离，实现精神主体的回归；第三是NSDR（无睡眠休息法），通过身体扫描与内心对话，在十到二十分钟内实现深度放松，快速恢复被彻底抽干的体力。这三种方法能够帮助职场人在下班后高效回血，为后续学习储备充足精力。', '["下班后学习的本质问题是下班后如何快速休息，以解决精力枯竭。", "玩手机休息时可通过外部时钟提醒，制造紧迫感，避免陷入虚拟时间陷阱。", "冥想能帮助从工作的牵引状态中抽离，通过关注呼吸或经文让自我回归，三到十分钟见效。", "NSDR（无睡眠休息）通过身体扫描法快速恢复体力，十到二十分钟可达睡眠一小时的恢复状态。"]', '[{"topic": "NSDR（无睡眠深度休息）", "why": "由神经学家安德鲁·胡伯曼提出，能在清醒状态下实现类似深度睡眠的恢复效果，对脑力工作者和重度疲劳者极具实用价值。", "direction": "搜索安德鲁·胡伯曼关于NSDR的播客或相关研究，寻找并跟练NSDR或瑜伽休息术的引导音频。"}, {"topic": "冥想中的自我抽离", "why": "冥想中“抽离自我”的技巧是应对现代职场焦虑的有效工具，能帮助个体快速重置认知状态，停止内耗。", "direction": "阅读《当下的力量》或学习正念冥想中关于“观察者意识”的概念，理解如何将意识与念头分离。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784010505, 1784116026, '272.0', '17.902820110321045', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7621480663677869922', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '空中楼阁 #清华学霸 #空间型学习者 #抖音精选app #学霸秘籍', '空中楼阁 #清华学霸 #空间型学习者 #抖音精选app #学霸秘籍', 1774514249, 'https://www.douyin.com/video/7621480663677869922', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ocDdE2AATEXvfz6TAVADI8IEffB7nCBGLDs7iF~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=VXAX9ffZ8BJg8gzErDwTo%2FBeqo8%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141518426D045DB24381CD72E6D4', 8587, 5076, 154, 921, 'done', 0, 'data/text/7621480663677869922.txt', 'data/summaries/7621480663677869922.md', '视频针对“空间型学习者”常陷入的“过度溯源”误区，提出了一种名为“空中楼阁”的高效学习法。核心论点在于，空间型学习的本质不是探究知识的绝对源头，而是把握知识之间的结构关系。学习者应将基础公式或概念视为已知模块，关注其在知识体系中的推导与应用变形，从而锻炼提炼本质的能力。通过在关键节点夯实基础，并不断验证这些本质规律，学习者能够跨越冗杂的细节，建立起相互关联的知识结构网。一旦形成这种结构化思维，学习过程便如同搭建空中楼阁，能够实现短期内的快速跳跃与高效吸收。', '["空间型学习者常陷入过度“溯源”的误区，导致学习卡壳。", "空间型学习的本质是把握知识间的“结构”，而非纠结知识的历史源头。", "应将基础公式视为已知模块，重点关注其在体系中的推导、变形与相互关系。", "“空中楼阁”学习法要求提炼核心本质并夯实，通过跳跃式学习构建知识网。", "每个提炼的本质需反复代入原体系验证，确保基础扎实以支撑快速跳跃。"]', '[{"topic": "结构主义学习理论", "why": "视频中强调的“关系大于源头”、“结构大于细节”正是结构主义的核心体现，深入理解能帮助学习者建立系统性思维，而非孤立地记忆知识点。", "direction": "阅读皮亚杰的《结构主义》或了解建构主义学习理论相关文献。"}, {"topic": "认知风格与空间型学习者", "why": "了解自身或他人的认知风格特征，能更精准地匹配学习策略，避免用不擅长的方式低效学习，明确“空间型”思维的优势与盲区。", "direction": "学习认知心理学中关于“认知风格”的分类与特征，如场独立型与场依存型理论。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784010526, 1784116074, '263.0', '19.763603925704956', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7620002206403002996', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '成功的本质是0-1的过程 #清华学霸 #成功 #过程重要还是结果重要 #抖音精选app', '成功的本质是0-1的过程 #清华学霸 #成功 #过程重要还是结果重要 #抖音精选app', 1774170019, 'https://www.douyin.com/video/7620002206403002996', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ogXf0L8E529HBQVQXBFpArVDgaDT3AP6f6vA2s~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=uCiJntCo%2Fe12pd3GJBVk4N56DgQ%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415184409BCC657B725230A1B3E', 3693, 1882, 47, 329, 'done', 0, 'data/text/7620002206403002996.txt', 'data/summaries/7620002206403002996.md', '视频主要探讨了成功的本质以及实现成功的正确路径。作者指出，成功不是一种情绪上的爽感，也非一考定生死的瞬间结果，而是对客观世界持续性改变积累到质变的过程。学生时代常因卷面分数带来结果定生死的错觉，忽视了平时内化知识与能力的积累。步入社会后，做事的底层逻辑依然是不断积累。然而，积累的本质并非个人消耗的精力或内耗，而是每天对客观事物或自身知识状态带来的真实改变程度。因此，我们需要摒弃非黑即白的情绪化思维，认识到事物发展永远是从零到一的渐进过程，关注每日的实际改变，方能真正走向成功。', '["成功不是情绪上的爽感或一次性的结果，而是对客观世界持续性改变积累到质变的产物。", "应摒弃学生时代“一考定生死”的错觉，认识到平时内化的知识与能力才是决定性因素。", "积累的本质不是自我感动式的费力或内耗，而是每天对客观事物带来的真实改变程度。", "事物的发展永远是从零到一的渐进过程，要避免非成功即失败的情绪化二元思维。"]', '[{"topic": "量变与质变规律", "why": "视频揭示了成功是持续微小改变最终引发质变的过程，理解这一哲学规律有助于建立长期主义视角，避免急功近利。", "direction": "阅读马克思主义哲学中关于质量互变规律的内容，或学习《掌控习惯》中关于微小习惯带来巨大改变的底层逻辑。"}, {"topic": "客观成果导向思维", "why": "区分“自我感动式努力”与“客观改变量”是提升执行效率的关键，能帮助人们把注意力从情绪内耗转移到实际产出上。", "direction": "了解目标与关键结果（OKR）工作法，学习如何制定可衡量、客观的进度指标来追踪每日改变。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784010538, 1784116129, '148.0', '12.131216049194336', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7618540352723121588', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '背水一战 #清华学霸 #焦虑 #抖音精选app', '背水一战 #清华学霸 #焦虑 #抖音精选app', 1773829654, 'https://www.douyin.com/video/7618540352723121588', 'https://p3-pc-sign.douyinpic.com/tos-cn-p-0015/oAduDQUQD8tynBfDgEfhArBl4F74rpAA7sG9r0~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=E1U5L75YFKD4UQYQfZ7HnQQ2Y4U%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151846B1F8F0F627E42EFC4D71', 4872, 2415, 63, 447, 'done', 0, 'data/text/7618540352723121588.txt', 'data/summaries/7618540352723121588.md', '视频主旨探讨了如何摆脱“背水一战”状态带来的焦虑与精神内耗。讲者指出，过度透支精力并在心理上自我施压，虽能短期提升执行力，却会引发长期的神经紧张。为此，讲者提出三点解决思路：首先，将具体事务回归到整体目标中，以“战略上藐视”的态度看待当下困难，认识到其仅占总体进程的一小部分；其次，明确自身在环境中的位置，警惕自我膨胀，理解“三分看天，七分看人”的道理，学会静观其变而非过度归因于己；最后，主动相信并整合他人，通过主导合作建立支持系统，从孤立无援的状态中抽身，做掌控全局的人而非独自承受所有压力。这些方法旨在帮助人们以更从容、理性的心态面对挑战，实现可持续发展。', '["摆脱背水一战状态，需将当下事务回归到整体目标中，认清其仅占进程的一小部分。", "警惕透支精力带来的自我膨胀，理解“三分看天，七分看人”，避免将所有结果归因于自己。", "学会主动相信并整合他人，通过主导合作建立支持系统，从孤立无援转变为掌控全局。", "运用“战略上藐视、战术上重视”的思维，打破对单一事件失败的灾难化想象。"]', '[{"topic": "灾难化思维与认知解离", "why": "视频中提到“一旦失败了就会怎么样”的想象是典型的灾难化思维，探究这一心理学概念有助于从底层理解焦虑的成因。", "direction": "可以阅读认知行为疗法相关书籍，学习如何识别并纠正认知扭曲。"}, {"topic": "课题分离与系统化思维", "why": "讲者提到不再把所有事情归因于自己，并主动整合他人力量做局，涉及将个人课题与环境课题分离并建立系统化框架。", "direction": "建议阅读阿德勒心理学著作《被讨厌的勇气》了解课题分离，并学习系统工程相关概念。"}, {"topic": "战略与战术的辩证关系", "why": "视频引用了毛泽东的战略思想，这一宏大的军事理论对个人应对焦虑和目标管理具有极强的指导价值。", "direction": "阅读《毛泽东选集》中的相关军事著作，如《中国革命战争的战略问题》。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784010560, 1784116191, '207.0', '20.50036096572876', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7616694974646047978', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '西蒙学习法 #清华学霸 #我的春日搭子 #阿里千问 #阿里最强最新Qwen #西蒙学习法', '西蒙学习法 #清华学霸 #我的春日搭子 #阿里千问 #阿里最强最新Qwen #西蒙学习法', 1773478799, 'https://www.douyin.com/video/7616694974646047978', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/osBzWNunIBtstIiz8f97AZyA9bLxfgNtAbAsip~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=%2FNmBVcIoBUkGuLgRc%2F96YCC6Va8%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141518496D9F65BC4F3497FBD307', 10580, 6948, 75, 1193, 'done', 0, 'data/text/7616694974646047978.txt', 'data/summaries/7616694974646047978.md', '视频介绍了诺贝尔奖得主赫伯特·西蒙提出的“西蒙学习法”，该方法主张在有学科基础的前提下，通过六个月的集中学习即可掌握一门学问。其核心逻辑在于“烧水效应”，即放弃同时学习多门学科导致的精力分散，转而将全部精力聚焦于一门学科，实现从浅层记忆到深层底层思维的跨越。西蒙学习法包含四个关键步骤：首先，选定极其细化且有明确边界的学习目标；其次，借助AI工具拆解知识并制定计划；再次，进行每天两到三小时的沉浸式“持续攻击”，优先攻克学科核心知识，揣摩知识点间的逻辑关联；最后，通过做题、实践等方式进行及时反馈，避免机械重复。这种方法能高效建立学科框架并激发学习兴趣。', '["西蒙学习法的核心是“烧水效应”，强调将精力集中于一门学科以实现快速突破。", "学习目标的选定必须极其细化，具有明确的边界，并可借助AI工具拆解知识和制定计划。", "每天进行两到三小时的沉浸式“持续攻击”，优先攻克学科基础逻辑与核心知识。", "摒弃机械背诵，通过做题、实践等方式在第一时间进行知识掌握的及时反馈。", "深度集中的学习能促使学习者从浅层记忆跨越至底层思维的内化，建立学科逻辑框架。"]', '[{"topic": "烧水效应与认知资源分配", "why": "理解烧水效应有助于跳出“多任务并行导致低效”的陷阱，科学管理有限的认知资源和注意力，实现单点突破。", "direction": "建议阅读卡尔·纽波特的《深度工作》，或学习认知心理学中的“注意力残留”概念。"}, {"topic": "底层思维与知识结构化内化", "why": "掌握底层逻辑能打破死记硬背的局限，实现知识的跨领域迁移和系统化吸收，是高效学习的核心密码。", "direction": "建议学习“第一性原理”思维方式，或阅读《认知天性》了解知识的构建、提取与心智模型。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784011236, 1784116279, '346.0', '14.3910973072052', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7616305699866426024', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '避免精神内耗 #清华学霸 #内耗 #精神内耗的调整方法', '避免精神内耗 #清华学霸 #内耗 #精神内耗的调整方法', 1773309359, 'https://www.douyin.com/video/7616305699866426024', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oMy1QDEDYnfAL8jBjpoyASkQbfFt09As3OBZZg~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=1LRjmjyfFDubtpGy%2Bku0vFHTCHk%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151851C01D2E945DA8A0F522E2', 6348, 3700, 67, 708, 'done', 0, 'data/text/7616305699866426024.txt', 'data/summaries/7616305699866426024.md', '本视频主要探讨了如何通过将行动与思考分离来克服精神内耗。作者提出将事情分为三个阶段处理：在行动之前，需深入思考期望回报、失败代价及成功概率，以此建立行动的勇气与充分理由；在行动过程中，应停止过度思考，只专注当下步骤，避免因无结果而陷入自我怀疑和内耗；在行动结束后，则需进行客观复盘，将自己视为事情中的一个因素来寻找真实归因。此外，若中途条件发生变化，应将其视为全新事件并重新走完上述三个阶段。这套先思考、再行动、再复盘的框架，能有效斩断过程中的无意义内耗，保障事情顺利推进。', '["将行动与思考分开是克服精神内耗的核心方法。", "行动前需厘清期望回报、失败代价与成功概率，为行动建立勇气基础。", "行动过程中应专注当下步骤，避免过度思考导致自我怀疑与内耗。", "结果出现后才进行复盘，且需将自己视为事件中的一个客观因素进行归因。", "遇到条件改变时，将其视为新事件并重新走一遍行动与思考的三个阶段。"]', '[{"topic": "反刍思维与内耗的心理机制", "why": "理解为什么行动中的过度思考会导向自我怀疑，有助于从心理学层面认知内耗的本质并采取阻断措施。", "direction": "阅读心理学中关于“反刍思维”和“元认知”的相关文献，或参考《停止内耗：如何控制你的大脑》等心理学书籍。"}, {"topic": "客观归因法", "why": "在复盘中将自我剥离，有助于避免情绪化归因，找到影响事情走向的真正客观变量，提升复盘质量。", "direction": "学习管理学中的“复盘”方法论，如《复盘：对过去的事情做思维演练》，或了解组织行为学中的归因理论。"}, {"topic": "敏捷迭代思维", "why": "将条件改变前后的阶段视为两个独立事件并重新规划，体现了面对不确定性时的敏捷应对策略，能增强人生的抗风险能力。", "direction": "了解敏捷项目管理或精益创业中的“敏捷迭代”概念，学习如何应对动态变化的环境。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784011256, 1784116325, '224.0', '18.995819807052612', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7613701534124173120', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何找回独立性 #清华学霸 #失权 #独立性 #主导权 #学习方法', '如何找回独立性 #清华学霸 #失权 #独立性 #主导权 #学习方法', 1772703032, 'https://www.douyin.com/video/7613701534124173120', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oM2Fz9AfIEIbsW7AUTpApDTBqIvwDTxfgAzFG9~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=ZQqEqc7h%2FOKZm5Ij5kTLKscqzBE%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151853BB75173A313D08B3DE78', 17154, 9338, 251, 2645, 'done', 0, 'data/text/7613701534124173120.txt', 'data/summaries/7613701534124173120.md', '本视频探讨了“失权”这一心理现象及其对个人独立性的影响。主讲人指出，当一个人从小在过度照顾和带有引号的“正确”方式管控下成长时，会逐渐丧失自主决策的能力，进入“我没有”的无助状态。随着人生主导权的降低，个体会进一步陷入“我不重要”的心理困境，表现为做事缺乏干劲、找不到兴趣、感觉为别人而活、生活浑浑噩噩。视频的核心主旨在于揭示这种过度管控如何剥夺了个体的独立性，并抛出了如何从这种自主权丧失的泥潭中走出来、重新找回人生主导权的深刻命题。这不仅是对原生家庭教育模式的反思，更是对个体自我重塑与精神独立的呼唤。', '["“失权”源于从小被过度照顾和以“正确”方式管控，导致个体能力丧失。", "失权者常处于“我没有”的状态，表现为缺乏自主决策能力和对自身生活的掌控感。", "主导权丧失会进一步导致“我不重要”的心理认知，使人做事缺乏干劲、感觉为别人而活。", "找回独立性需要觉察失权状态，从小事开始刻意练习做决定，重新拿回人生主导权。"]', '[{"topic": "习得性无助与控制感", "why": "解释了过度管控下个体为何放弃尝试并产生“我没有”的无助感，是理解失权心理机制的关键。", "direction": "阅读马丁·塞利格曼关于习得性无助的理论，或心理学中“内控型人格与外控型人格”的概念。"}, {"topic": "自我决定理论", "why": "该理论探讨了人的基本心理需求（自主、胜任、归属），为如何从失权状态中恢复内在动力和独立性提供了科学路径。", "direction": "阅读爱德华·德西和理查德·瑞安的自我决定理论相关文献与著作。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784032910, 1784116412, '296.0', '4.615775108337402', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7609997178278399241', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '德西效应 #清华学霸 #内驱力 #德西效应 #正反馈#抖音精选app #2026高考 #抖音精选高考应援联盟', '德西效应 #清华学霸 #内驱力 #德西效应 #正反馈#抖音精选app #2026高考 #抖音精选高考应援联盟', 1771840638, 'https://www.douyin.com/video/7609997178278399241', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/okIARfhcxgHeByuIAn6iA3BNJAziIdzo0UHaom~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=kqfTLV9RHT%2BkCkBjxlVM3Wwyt6s%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714151856777BB7A5CB32D302353B', 68666, 34934, 1237, 14210, 'done', 0, 'data/text/7609997178278399241.txt', 'data/summaries/7609997178278399241.md', '本视频以心理学中的“德西效应”为核心，探讨了外部评价系统如何逐渐瓦解个体的内驱力与意义感。通过糖果实验和日常育儿现象，揭示了过度依赖外部奖励或评价会让人丧失做事的纯粹快乐，沦为“空心人”。针对这一问题，视频提出了找回意义感的方法，即通过主动创造而非被动消耗来重塑主体性，例如培养手工、绘画等安静爱好。此外，还介绍了反向利用德西效应戒除坏习惯的“邪修”技巧，并指出了该效应的适用边界：对于毫无兴趣且枯燥的必做任务，仍需借助外部引导系统。整体旨在帮助人们重新审视动力来源，建立健康的自我评价体系。', '["长期的外部评价系统或物质奖励会逐渐瓦解个体的内驱力，导致意义感丧失。", "真正的快乐不应是被动消耗时间，而应通过主动创造和改变世界来重塑主体性。", "可以反向利用德西效应，先对坏习惯给予奖励再撤销，利用反馈机制的落差来戒除坏习惯。", "德西效应仅适用于与个人兴趣相关的领域，对于枯燥且必须完成的任务仍需依靠外部引导系统。"]', '[{"topic": "德西效应（过度理由效应）", "why": "揭示了外部动机如何削弱内部动机的心理学机制，对于理解现代人的“空心病”现象及教育方式有重要启示。", "direction": "建议阅读理查德·德西的《内在动机》或查阅自我决定理论（SDT）。"}, {"topic": "心流体验（Flow）", "why": "视频中提到的“主动创造”和“真正的快乐”与心流状态高度相关，了解心流有助于更好地构建内在意义感。", "direction": "建议阅读米哈里·契克森米哈赖的《心流：最优体验心理学》。"}, {"topic": "主体性与异化", "why": "视频提到“被信息占有”与“占有他者”的区别，涉及哲学中主体性的构建与消费社会中的异化问题，值得深入探讨。", "direction": "建议了解马克思的异化理论或鲍德里亚的《消费社会》。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784032961, 1784116473, '323.0', '13.335282802581787', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7607022805271455330', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '在大学如何学习 #清华学霸  #大学学习 #大学学习规划', '在大学如何学习 #清华学霸  #大学学习 #大学学习规划', 1771148017, 'https://www.douyin.com/video/7607022805271455330', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o8DLUBCpgL7GZQOBfeHTGgyNTe8SpG3MIEIAAB~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=AHxNNwCwEwFtS0BhMjI64UNhAmI%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415185833C6274617B9D6788F69', 41750, 28826, 362, 5403, 'done', 0, 'data/text/7607022805271455330.txt', 'data/summaries/7607022805271455330.md', '视频主旨在于探讨大学期间如何高效学习与规划，核心论点是：大学资源虽然丰富，但都是被动存在的，学生必须从被动接受转为主动出击。作者指出，老师授课深度有限，学校资源不会主动推送到学生面前，因此学生需要通过关注公告、拓展社交网络来获取关键信息（如夏令营、创业大赛等）。同时，尽早明确未来职业目标并针对性准备，以及充分利用图书馆资源进行高效学习，是拉开与同学差距的关键。整体强调了主动获取资源、构建信息网络和清晰自我规划在大学生活中的决定性作用。', '["大学资源是被动存在的，学生必须主动挖掘获取，不能等待资源找上门。", "通过社团和跨院系社交网络打破信息差，获取保研夏令营、创业大赛等关键资源。", "尽早确立未来职业目标，并针对性地锻炼相应能力，能大幅提高成功率。", "充分利用图书馆的书籍和自习环境，避免在宿舍学习导致休息区与工作区重叠而降低效率。"]', '[{"topic": "信息差与社交资本", "why": "大学阶段的信息获取能力往往比单纯的努力更重要，理解社交网络如何转化为信息资本是提升竞争力的关键。", "direction": "建议阅读《弱关系的力量》或社会学中关于社会资本（Social Capital）的经典理论。"}, {"topic": "空间隔离与心流工作法", "why": "物理环境对心理状态有强烈的暗示作用，分离工作区与休息区是进入深度学习状态的有效策略。", "direction": "了解“环境设计学”或米哈里·契克森米哈赖的《心流：最优体验心理学》中关于注意力与环境的论述。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784032992, 1784116528, '465.0', '29.822908878326416', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7605540009635083362', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '归因 #清华学霸 #哲学思维 #归因 #抖音精选app', '归因 #清华学霸 #哲学思维 #归因 #抖音精选app', 1770802778, 'https://www.douyin.com/video/7605540009635083362', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ogOIgbjIe0xTAQpduFEaAmE8MDzlfyAn9AB3CD~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=wl6lLki0c56aGN27wW%2F3aXXDrGg%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141519007AEDCF34714EA30AB5F5', 7136, 3976, 42, 844, 'done', 0, 'data/text/7605540009635083362.txt', 'data/summaries/7605540009635083362.md', '视频探讨了如何通过正确归因从失败中走出来。首先，对于完全不可控的外部因素不应归因，以免陷入运气陷阱而丧失掌控力。对于内部可控因素，分为自我和环境两个维度：自我归因应超越浅层的努力，上升到能力范围与效率层面，且须针对实践而非人本身进行评价；环境归因则强调整合可控的资源与关系，而非个体的盲目死磕。最终指出，跳出自我的狭隘视角，理清复杂的关系结构，能让我们洞察事物本质，从而明白选择大于努力的道理。', '["正确归因是避免在失败中循环往复、实现破局的关键能力。", "对完全不可控的外部因素不应进行归因，以免陷入运气陷阱而丧失对自我的掌控力。", "自我归因应超越浅层的努力，聚焦于能力范围与效率，且须针对实践而非人本身进行评价。", "可控环境归因强调资源整合与关系协调，而非个体的盲目死磕。", "跳出自我的狭隘视角理清复杂关系后会发现，选择其实大于努力。"]', '[{"topic": "控制点理论", "why": "视频中对不可控的外部因素与内部可控因素的区分，与心理学中的控制点理论高度契合，有助于理解归因倾向如何影响个人行为与动机。", "direction": "建议阅读心理学相关书籍，深入探究内控型与外控型人格的特征及其对个人发展的长远影响。"}, {"topic": "资源依赖理论", "why": "视频提及通过整合可控环境中的资源和关系来解决问题，涉及组织社会学中的核心概念，探讨如何通过外部网络增强自身力量。", "direction": "学习管理学或社会学中的资源依赖与网络理论，探索如何构建和利用关系网来解决复杂问题。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784033010, 1784116589, '331.0', '17.207624912261963', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7601806220571428840', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '狂妄 #清华学霸 #学习动力 #抖音精选app #自信', '狂妄 #清华学霸 #学习动力 #抖音精选app #自信', 1769933439, 'https://www.douyin.com/video/7601806220571428840', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oo7CnFBWCw2f77f5oSA9A8Gf4nQBQK2lDwCDEA~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=UrIUMXbztglXLY2PM6jDoXgcdE0%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415260237BEDB5013BB2E947D14', 8615, 4301, 63, 805, 'done', 0, 'data/text/7601806220571428840.txt', 'data/summaries/7601806220571428840.md', '视频以清华学霸的视角，揭示了学习动力的深层来源。核心论点是：学习并非简单的知识积累，而是连接"现在的自己"与"未来理想自我"的桥梁。真正驱动人持续学习的，是内心那股渴望尽快成为美好、强大、有力量的自我的欲望。作者将这种内在驱动力形容为一股"狂劲儿"——一种不轻易对外言说、却在内心持续燃烧的火焰。这股力量是许多优秀者取得成就的隐秘动力，也是作者本人的真实体验。视频试图打破对"学习动力"的浅层理解，指向一种更深层的自我塑造的渴望。', '["学习的本质是连接\"现在的自己\"与\"未来理想自我\"的桥梁", "真正持久的学习动力源于对理想自我的强烈渴望，而非外在目标", "优秀者内心都有一股不轻易言说的\"狂劲儿\"，是取得成就的隐秘驱动力", "这股内在火焰在挫折中反而更旺，是自我驱动最珍贵的燃料"]', '[{"topic": "内在动机与自我决定理论", "why": "视频中提到的\"狂劲儿\"本质上是一种强大的内在动机，理解自我决定理论可以帮助系统性地认识内在动机的来源与培养方式。", "direction": "阅读德西与瑞安的《自我决定理论》，重点研究内在动机与外在动机的区别，以及自主感、胜任感、归属感如何驱动持续行为。"}, {"topic": "理想自我与现实自我的差距理论", "why": "视频核心框架是\"现在的你\"向\"未来的你\"转化，这与心理学中自我差距理论直接相关，理解它有助于认清学习动力的心理机制。", "direction": "学习Higgins的自我差距理论（Self-Discrepancy Theory），研究理想自我、应该自我与实际自我之间的差距如何产生动力。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114227, 1784116652, '350.0', '3.8229992389678955', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7599230027888512628', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '多线程学习法（一心二用） #清华学霸 #学神 #学习方法 #抖音精选app', '多线程学习法（一心二用） #清华学霸 #学神 #学习方法 #抖音精选app', 1769333623, 'https://www.douyin.com/video/7599230027888512628', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ow2BPtF6qIDkJfAAK5MAfOEMS1II7QSBG54e4C~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=jpXyZpz%2FJrDG2EF%2BeL8b%2F8rbGto%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714152604D093F3D8EB1B0AFC025E', 27232, 17426, 201, 2914, 'done', 0, 'data/text/7599230027888512628.txt', 'data/summaries/7599230027888512628.md', '视频主要讲解了“多线程学习法”（一心二用）的原理与高效应用策略。其核心本质是利用大脑不同分区的交替休息机制，通过在学习时切换不同类型的任务（如数理逻辑与语言背诵），使各脑区轮流休整，从而大幅提升学习效率。在实践上需遵循四大要点：首先，初学者应从左右脑大区划分开始，避免同类学科重复，并需大量练习以适应模式切换；其次，线程数量严格限制在二至三个，且仅能包含一个高难度任务搭配简单任务；再次，该方法仅适用于巩固已有知识，不可用于学习新知识，其本质是思维的熟练化而非初步了解；最后，因本质为透支大脑，必须循序渐进，防止宕机与脑缺氧，并配合吸氧休息。熟练掌握后可实现多任务并行，有效突破学习瓶颈期，实现成绩的几何倍提升。', '["多线程学习法的本质是利用大脑不同分区的交替休息来提升整体学习效率。", "初学者实践时应从左右脑大区划分开始，避免使用同类重复学科进行无效切换。", "学习线程数量不应超过三个，且仅限包含一个高难度任务搭配简单任务。", "该方法仅适用于巩固已有知识，不可用于学习新知识，本质是思维的熟练化。", "实施过程必须循序渐进并配合吸氧休息，以防大脑宕机和脑缺氧等负面反应。"]', '[{"topic": "大脑半球优势分工理论", "why": "多线程学习法的基础是左右脑交替休息，了解大脑的分工机制能更科学地设计学科搭配与切换任务。", "direction": "阅读《心理学与生活》或学习认知神经科学中关于大脑功能定位与左右脑差异的知识。"}, {"topic": "认知负荷理论", "why": "限制线程数量和学习难度（一难配简单、不学新知识）本质上是控制工作记忆的认知负荷，避免大脑宕机。", "direction": "学习约翰·斯威勒的认知负荷理论，探究如何优化 Instructional Design 以降低外在认知负荷。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114244, 1784116709, '439.0', '16.249178886413574', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7598150727123749474', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '寒假怎么做 #清华学霸 #抖音精选app #学习哪有不疯的 #寒假计划 #寒假来了', '寒假怎么做 #清华学霸 #抖音精选app #学习哪有不疯的 #寒假计划 #寒假来了', 1769082332, 'https://www.douyin.com/video/7598150727123749474', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oEzcAfUmBA10iZOA0yiDQGIduBDIQ7Wg17exaA~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=L8Y2pkk17YFcxGtRKKWjCLk3mnY%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141526064865377195C2401345CD', 4931, 2293, 18, 486, 'done', 0, 'data/text/7598150727123749474.txt', 'data/summaries/7598150727123749474.md', '这段视频来自一位清华学霸，核心围绕寒假时间的科学分配展开。作者提出了一个实用的判断公式：用寒假总天数减去写作业时间和过年应酬时间，看剩余天数是否大于五天。若不足五天，说明在校期间精力已被严重透支，此时最该做的不是弯道超车，而是高质量休息——选择轻社交和兴趣阅读，避免对抗性游戏带来的精力消耗。若剩余天数超过五天，则需根据时间长短分层规划：短期以预习新学期内容为主，因为复习容易与新阶段脱节；长期则应在预习基础上进行系统复盘，清理知识盲点，最终上升到行为习惯与个人成长的自我反思。整体逻辑清晰，从时间测算到分层行动方案，为不同处境的学生提供了可操作的寒假规划框架。', '["寒假规划的第一步是用总天数减去写作业和过年应酬时间，计算真正可自由支配的剩余天数", "剩余天数不足五天时应以高质量休息为主，因为在校期间精力已严重透支", "休息应选择轻社交和兴趣阅读，避免对抗性游戏带来的额外精神消耗", "短期假期优先预习新内容而非复习旧知识，避免新旧知识衔接断层", "长期假期可在预习基础上进行系统复盘和自我反思，实现从知识到行为的全面提升"]', '[{"topic": "精力管理与恢复理论", "why": "视频提到剩余天数不足五天时精力已透支，这背后涉及精力管理的科学原理，了解后能更科学地安排学习与休息的节奏。", "direction": "阅读吉姆·洛尔《精力管理》一书，了解精力四维度模型及恢复策略"}, {"topic": "预习与复习的认知科学原理", "why": "视频中主张短期假期预习优于复习，这涉及遗忘曲线与知识建构的底层逻辑，值得深入理解其神经科学依据。", "direction": "学习艾宾浩斯遗忘曲线与建构主义学习理论，了解前后摄抑制概念"}, {"topic": "系统复盘方法", "why": "视频中提到长期假期应做系统知识复盘，这不仅是学习技巧，更是一种通用的高效认知工具，适用于任何领域的知识整理。", "direction": "学习费曼学习法与思维导图法，了解如何将碎片知识结构化并识别盲点"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114256, 1784116770, '133.0', '11.796816110610962', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7596637276856377704', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '休息羞耻 #清华学霸  #学习 #工作 #休息 #抖音精选app', '休息羞耻 #清华学霸  #学习 #工作 #休息 #抖音精选app', 1768729949, 'https://www.douyin.com/video/7596637276856377704', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oM7QGQWoAAlyBOwe7LeCVSGCe82RcIBdrQp7BZ~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=q2iqXLYx4A%2BYai%2FcXlPkWMXZrGc%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141526090420ABAC9A0547028556', 2646, 1028, 41, 350, 'done', 0, 'data/text/7596637276856377704.txt', 'data/summaries/7596637276856377704.md', '本视频深入剖析了“休息羞耻症”这一现象的心理与社会根源。作者指出，休息羞耻的本质是个体将自身异化为工具，用创造金钱和利润的“有用性”来衡量生命价值。这种金钱等于生命的逻辑是资本主义社会运转的要求，对个体而言是一种被迫参与社会劳动的行为。作者强调，个体生命的核心在于生命体验，而非单纯服务于社会化生产。休息羞耻源于社会与个人关系的倒错，误将服务社会置于个体生命之上。最终得出结论：工作和学习只是利用工具属性获取生存的手段，而休息才是把握生命时间、无需理由的最重要之事，不应为此感到羞耻。', '["休息羞耻的本质是个体将自身异化为工具，用创造金钱的有用性来衡量生命价值。", "金钱等于生命的逻辑是资本主义社会运转的要求，对个体而言是被迫参与社会劳动的行为。", "个体的核心价值在于生命体验，而非单纯地服务于社会化大生产。", "休息羞耻源于社会与个人关系的倒错，误将服务社会置于个体生命之上。", "工作和学习只是生存的手段，休息才是把握生命时间、无需理由的最重要之事。"]', '[{"topic": "人的异化理论", "why": "视频中提到将个体异化为工具，这一概念源自马克思的异化劳动理论，理解它有助于看清现代人在职场中如何丧失主体性。", "direction": "建议阅读马克思《1844年经济学哲学手稿》或了解社会学中关于异化与劳动的基本概念。"}, {"topic": "工具理性与价值理性", "why": "用金钱和有用性评判生命属于典型的工具理性，反思这一点有助于我们在效率至上的社会中找回个体存在的真正价值。", "direction": "建议阅读马克斯·韦伯《新教伦理与资本主义精神》或学习社会学中关于工具理性与价值理性的区分。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114270, 1784116830, '178.0', '13.258244752883911', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7595888322350863587', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '立志 #清华学霸 #涨知识 #立志 #抖音精选app', '立志 #清华学霸 #涨知识 #立志 #抖音精选app', 1768555568, 'https://www.douyin.com/video/7595888322350863587', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/owf3BgIwDQRD4qqOAoFBDS9LbBfopHAQE2g2Aa~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=uTNZs4CWVpmc8xTQ7yGZpF92PDA%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415261114E73234B179E91EC48A', 8265, 4504, 124, 843, 'done', 0, 'data/text/7595888322350863587.txt', 'data/summaries/7595888322350863587.md', '本视频以"立志"为主题，阐述立志是一切进步的起点。视频引述王阳明"持志如心痛"的思想，指出立志的本质是不甘于平凡命运，追求在极限内体验最高的生命存在。立志之初志向要大，甚至需要一种藏于心底的狂妄与笃定，相信自己能实现遥远目标。但立志后并非自我膨胀，而要时刻觉察与目标间的差距，保持一种痛苦的清醒。一旦确立明确志向，便会形成强大的目标感，帮助屏蔽外界批评打压与信息时代的纷扰干扰，让人在喧嚣中保持定力、坚定前行。', '["立志是一切进步的起点，其本质是不甘于平凡命运，追求在极限内体验最高的生命存在", "志向要大，要有野心甚至藏于心底的狂妄，同时笃定地相信自己能够实现", "真正的立志会带来\"持志如心痛\"的状态，时刻反省自己与目标之间的差距", "明确的志向形成强大的目标感，能屏蔽外界批评打压与信息时代的纷扰干扰"]', '[{"topic": "王阳明心学与立志思想", "why": "视频中多次引用王阳明关于立志和\"持志如心痛\"的思想，理解其心学体系有助于深入把握立志的哲学内涵与实践方法", "direction": "可阅读《传习录》了解王阳明心学思想，特别是\"致良知\"\"知行合一\"等核心概念"}, {"topic": "内在驱动力与目标心理学", "why": "立志后的\"心痛\"感本质是一种强大的内在驱动力，理解其心理学机制有助于更有效地设定和坚持目标", "direction": "可学习自我决定理论、目标设置理论等心理学概念，阅读《驱动力》等相关书籍"}, {"topic": "注意力管理与信息过滤", "why": "立志带来的目标感能帮助在信息时代有效过滤干扰，理解注意力管理原理对现代人的专注力培养至关重要", "direction": "可阅读《深度工作》或《心流》等书籍，了解专注力与目标管理的系统方法"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114279, 1784116882, '319.0', '7.424883127212524', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7594021335292496354', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '视觉空间学习者 #清华学霸 #学习方法 #涨知识 #视觉空间学习者 #抖音精选app', '视觉空间学习者 #清华学霸 #学习方法 #涨知识 #视觉空间学习者 #抖音精选app', 1768120877, 'https://www.douyin.com/video/7594021335292496354', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oQQwZBCIy6ibAV2fAg1jxD0jYRetsAFDiIQBAA~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=E2lMja8%2FV3biMJsi0Ckppey3XCw%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714152614BB7355385E24A21A750F', 99468, 52633, 3639, 16836, 'done', 0, 'data/text/7594021335292496354.txt', 'data/summaries/7594021335292496354.md', '视频将学习者分为听觉序列型与视觉空间型两类，揭示了两种截然不同的认知加工模式。序列型学习者擅长点对点的符号连接，能快速建立如"present=礼物"的对应关系，反应敏捷、背诵准确，在传统评价体系中表现突出。而视觉空间型学习者面对信息时无法直接存储，必须先将混乱的信息在大脑中整理成完整的逻辑体系才能理解。这一内在重组过程导致他们外在表现为反应迟缓、背诵困难——他们记住的是"理解后的意义"而非"原始符号"，因此背古文时常用自己的语言重写，默写频频出错。视频指出，空间型学习者被提问时卡顿、做题时无从下手，根源并非能力不足，而是知识体系尚未构建完成。这一分类为理解个体学习差异提供了重要视角，提示教育者和学习者应关注认知风格的匹配，而非用单一标准评判学习效果。', '["学习者可分为听觉序列型与视觉空间型，两者在信息加工方式上存在本质差异", "序列型学习者通过点对点符号连接快速记忆，反应敏捷、背诵准确", "视觉空间型学习者必须先将信息整理成逻辑体系才能理解，否则无法存储", "空间型学习者背诵时常用自己的理解重述内容，导致默写失真", "空间型学习者反应慢的根源是知识体系尚未构建完成，而非能力不足"]', '[{"topic": "认知风格理论", "why": "视频中的分类基于认知风格理论，深入了解有助于理解个体学习差异的心理学基础，避免用单一标准评判学习者。", "direction": "阅读 Riding & Cheema 的认知风格综述，或研究 Kolb 学习风格模型、VARK 感官学习偏好理论"}, {"topic": "工作记忆与信息加工模型", "why": "视觉空间型学习者需要\"整理大脑\"的过程，本质上涉及工作记忆的容量限制与信息加工策略，理解这一机制有助于设计更有效的学习方法。", "direction": "学习 Baddeley 的工作记忆模型，或阅读 Sweller 的认知负荷理论相关文献"}, {"topic": "视觉空间型学习者的学习策略", "why": "视频仅描述了困境但未给出解决方案，探索针对空间型学习者的具体方法具有很高实用价值。", "direction": "研究思维导图法、概念图教学法，或阅读 Linda Silverman 关于视觉空间学习者的著作《Upside-Down Brilliance》"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114287, 1784116931, '264.0', '7.981717109680176', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7593285043235488500', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '四象限工作法 #清华学霸 #学习方法 #实用小技巧', '四象限工作法 #清华学霸 #学习方法 #实用小技巧', 1767949450, 'https://www.douyin.com/video/7593285043235488500', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o4YxJBDN0lAyAW8gB9iigIBOAsAeZVAIIEfgDG~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=I49TuQ1IrjzBuvnQiAjbBJtaQL4%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714152616B24F1731578F4B0752F7', 4269, 2253, 68, 405, 'done', 0, 'data/text/7593285043235488500.txt', 'data/summaries/7593285043235488500.md', '在快节奏的现代生活中，如何高效分配精力是每个人面临的难题。本视频介绍了经典的“四象限管理法”，指导我们在计划启动阶段，根据任务的“紧急”与“重要”程度进行分类与精力分配。视频指出，重要且紧急的任务需立即执行但不占过高精力；重要不紧急的任务是核心，应占据大部分精力并通过拆解计划逐步完成；不重要不紧急的任务需尽量削减；而紧急不重要的任务则要警惕其造成的精力损耗，严格限制投入。通过结合个人实际案例，作者强调了认清任务本质、将重心前置到“重要不紧急”象限，是避免焦虑与低效的关键。', '["四象限管理法适用于计划启动阶段，通过“紧急”与“重要”两个维度对任务进行分类。", "重要且紧急的任务需立即执行不思考，精力分配占比约20%-25%。", "重要不紧急的任务是精力分配的核心（70%-80%），需通过计划拆解为每日定量任务。", "不重要不紧急的事务应尽量削减，仅保留对核心目标有辅助作用的部分。", "紧急但不重要的事务需警惕精力损耗，严格限制投入。"]', '[{"topic": "艾森豪威尔矩阵", "why": "视频中提到的四象限管理法正是源自艾森豪威尔矩阵，了解其背后的管理学理论有助于更深刻地理解优先级划分的底层逻辑。", "direction": "阅读《高效能人士的七个习惯》中“要事第一”章节，或查阅斯蒂芬·柯维对艾森豪威尔矩阵的深度解读。"}, {"topic": "目标拆解与量化管理（WBS）", "why": "视频提到对重要不紧急任务要“定量的逻辑”进行拆解，这涉及到工作分解结构(WBS)的概念，是长期目标落地的核心技术。", "direction": "学习项目管理体系中的工作分解结构（WBS）概念，了解如何将宏观目标科学转化为可执行的微观任务。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114301, 1784117047, '278.0', '13.222177743911743', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7591801018347784040', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '课件学习法 #清华学霸 #讯飞智文助力表达升级 #AI #讯飞智文 #学习方法', '课件学习法 #清华学霸 #讯飞智文助力表达升级 #AI #讯飞智文 #学习方法', 1767691805, 'https://www.douyin.com/video/7591801018347784040', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/osQ2QBAj9fIWACDpRF6wfzt3y40AREwgDa3tBI~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=wqwH2kfKadGwkIx70WWybx%2FAD70%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714152618087DDB2602908500C2CF', 1182, 552, 17, 107, 'done', 0, 'data/text/7591801018347784040.txt', 'data/summaries/7591801018347784040.md', '本视频探讨了如何利用课件进行高效学习，以构建系统性的知识结构。视频指出，学习的核心在于将传统的被动输入转化为主动输出。通过整理思路文档并借助讯飞智文等AI工具生成课件，学生可以尝试自我讲解。同时，利用AI的智能演练功能进行讲解评分，检查表达流畅度与思维清晰度，或通过语音播报功能生成专属讲课音频进行反向输入。在具体的学习方法上，视频建议在脑内先建立整体印象，接着精准把握概念关键词并构思实例，最后理清各章节内容切换时的因果逻辑，避免死记硬背。当学习者找到流畅自然的表达欲望时，知识便能彻底内化归己。', '["课件学习的核心在于将被动输入转化为主动输出，构建系统化知识结构。", "借助AI工具整理文档生成课件，并通过智能演练功能进行自我讲解和评分，查漏补缺。", "自学讲述时应先建立宏观印象，再精准把握概念关键词并构思实例。", "理清各章节之间的因果逻辑关系，避免死记硬背导致的碎片化记忆。", "找到流畅自然的表达欲望并大声输出，是实现知识内化的关键。"]', '[{"topic": "费曼学习法", "why": "视频中提到的自我讲述和给AI讲解本质上是费曼学习法的应用，探究其原理能更深刻理解为何输出能提升输入效率。", "direction": "阅读理查德·费曼的相关传记或学习《别闹了，费曼先生》，深入研究以教代学的认知心理学基础。"}, {"topic": "认知负荷理论", "why": "视频强调脑内生成整体印象再抓关键词，这涉及如何合理分配大脑的认知资源，降低学习时的认知负荷。", "direction": "研读约翰·斯威勒的认知负荷理论，学习如何设计教学材料以优化工作记忆的处理效率。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114315, 1784117111, '145.0', '13.350852966308594', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7590701171632067304', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '在大学如何交朋友 #清华学霸 #朋友', '在大学如何交朋友 #清华学霸 #朋友', 1767347841, 'https://www.douyin.com/video/7590701171632067304', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o4oeFBqKIADBWEAA3AliiEU2bIZegOiM0XB2oP~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=0z3o9XE4KHZR5mWQnuhPiK4qHY8%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714152621500739FCBBC7B0FAA9CD', 11081, 6453, 95, 1257, 'done', 0, 'data/text/7590701171632067304.txt', 'data/summaries/7590701171632067304.md', '大学阶段交友不仅是为了情感需求，更是个人成长与做事的底层逻辑。视频指出，个人的力量由自身能力和可整合的外部资源共同构成，想要做成大事必须突破单打独斗的局限。同时，每个人都有认知偏见和性格短板，需要通过他人来补齐人格，从而更完整地认知世界。交友的本质在于交流与交互，强调在听与说的互动中实现社会性共存。在实践中，可以通过请客吃饭等低成本方式营造轻松氛围，在沟通中放下对错成见，寻找认同感。同时，交流需遵循不迎合、不否认的原则，在尊重他人的基础上保持自身个性。只有具备鲜明的个性，才能在人际网络中实现人格互补，维持自身不可替代的价值。', '["个人力量由自身能力和可整合资源共同构成，交友是突破个体局限、获取外部资源的关键途径。", "每个人都有认知局限，交友能通过他人补齐人格短板，打破偏见以更完整地认知世界。", "交流的本质是听与说的双向交互，需要放下对错成见，在意见碰撞中寻找认同感。", "在人际交往中应坚持不迎合、不否认的原则，保持独立个性是实现人格互补的前提。"]', '[{"topic": "社会资本理论", "why": "视频中提到个人力量由自身能力和可整合的资源构成，这与社会资本理论中通过人际网络获取资源的核心观点高度契合，值得深入理解其运作机制。", "direction": "建议阅读罗伯特·帕特南的《独自打保龄》，学习社会资本的积累与运作概念。"}, {"topic": "主体间性", "why": "视频提到交流的本质是自我与主体在环境中彼此尊重、共同存在，这触及了哲学中主体间性的核心探讨，有助于理解人际交往的深层逻辑。", "direction": "建议了解胡塞尔或哈贝马斯关于主体间性与交往行为理论的哲学概念。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114424, 1784117210, '313.0', '93.90897464752197', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7589952957676834083', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '自媒体半年心得 #清华学霸 #忽然知己 #年度总结', '自媒体半年心得 #清华学霸 #忽然知己 #年度总结', 1767173671, 'https://www.douyin.com/video/7589952957676834083', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oY3D5UlId9I3qzjSAGAI77eL4eNm2zBGBGeCA1~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=QJD2U%2F%2Bh7z25IfVhtZVZTsWlAU0%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714152623B9CCBA6F72D0B7FE6413', 1334, 363, 52, 75, 'done', 0, 'data/text/7589952957676834083.txt', 'data/summaries/7589952957676834083.md', '本期内容主要分享了作者作为清华学霸从事自媒体半年来的心路历程与深刻反思。核心论点在于，自媒体创作不应仅仅依赖学历等外在标签获取短期流量，而应通过真诚的自我表达与高质量的内容输出，寻找精神层面的同频共振。作者经历了从数据焦虑到放下包袱的转变，最终领悟到自媒体的终极价值不在于粉丝数量的堆砌，而在于跨越屏幕建立忽然知己般的深度连接，这是一场从迎合外界到回归自我的内容修行。', '["学历等外在标签虽能带来初始流量，但过度依赖会成为创作枷锁并导致数据焦虑。", "放下精英视角的包袱，真诚分享个人的迷茫与思考，是建立受众信任和深度共鸣的关键。", "自媒体的核心价值在于寻找忽然知己般的精神同频，其带来的满足感远胜于单纯的流量数据。", "内容创作本质上是一场强迫自我输入与反思的修行，需回归真实表达。"]', '[{"topic": "个人IP定位与标签管理", "why": "创作者常常陷入标签反噬的困境，理解如何剥离表层标签并建立核心价值，是维持内容生命力的关键所在。", "direction": "建议阅读《定位》或研究内容营销中的人格化塑造理论，探索如何构建具有持久生命力的个人IP。"}, {"topic": "数字时代的孤独与弱连接心理学", "why": "忽然知己的体验反映了现代人对深度情感连接的渴望，探究这种现象有助于理解社交媒体用户的心理需求。", "direction": "建议阅读社会学著作《孤独的城市》或研究网络心理学中的弱连接与情感共鸣机制。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114430, 1784117259, '592.0', '5.05699896812439', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7588094249734026319', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '看书困怎么办？ #清华学霸 #学习方法 #看书', '看书困怎么办？ #清华学霸 #学习方法 #看书', 1766740870, 'https://www.douyin.com/video/7588094249734026319', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ooaBAwUp55B0i4qIHSOZMw5OPUUIAviIJQqig~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=2HT%2Bg7W3HaRSK4dQ%2BOYiFJzQmJo%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141526255F7A929499A964FE65FF', 4925, 2760, 94, 588, 'summarize_failed', 1, 'data/text/7588094249734026319.txt', NULL, NULL, NULL, NULL, NULL, NULL, 1783932814, 1784114449, NULL, '403.0', '18.107376098632812', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7584702670499384576', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '长期在家学习 #清华学霸 #灵工打卡 #居家学习', '长期在家学习 #清华学霸 #灵工打卡 #居家学习', 1766304001, 'https://www.douyin.com/video/7584702670499384576', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ocKEnjCgQkkAD9QB0EdDfAM9VxAFBDkgVUepQF~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=qOSjzxgB1NbXLKl5akuHailIjBo%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714152628C9AB9BD0BC53EA045031', 62895, 39472, 424, 8649, 'done', 0, 'data/text/7584702670499384576.txt', 'data/summaries/7584702670499384576.md', '视频探讨了长期居家学习导致的自制力失衡与目标失调问题，指出其本质在于工作与生活空间的重叠，以及个体时间与社会化时间的失衡。为解决这一问题，视频提出了两种方案：一是物理空间分离，离开家庭去图书馆或咖啡厅等环境学习；二是借助外力系统，如参与灵活的零工打卡工作，通过适度接触社会来获取价值感并缓解重复学习的疲劳。结合柏格森的哲学时间观，文章进一步分析了空间重叠引发的精神内耗和时间感知失衡导致的自我过剩现象，强调通过增加社会接触来平衡身心状态，最终帮助学习者走出困境。', '["居家学习困境的本质是工作与生活空间重叠及社会化时间失衡。", "解决方式一是改变物理环境，离开家去图书馆或咖啡厅等地学习。", "解决方式二是借助外力系统，通过灵活的零工工作获取价值感并缓解重复学习的疲劳。", "空间重叠会导致身体在休息和学习状态间来回拉扯，造成严重的精神内耗。", "增加社会接触能够化解自我感觉过剩，避免孤独感和消极情绪的放大。"]', '[{"topic": "柏格森的时间理论（绵延）", "why": "视频引用此哲学概念解释了为什么纯主观时间会导致情绪放大和孤独感，深入理解有助于从哲学层面认知自我内耗的本质。", "direction": "建议阅读柏格森的《时间与自由意志》或了解“绵延”概念。"}, {"topic": "环境心理学中的空间边界效应", "why": "视频中提到空间重叠导致身体无法区分休息与工作区域，这涉及环境心理学中的空间暗示与行为锚定原理。", "direction": "学习环境心理学，了解场依存性、行为背景理论等概念。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114464, 1784117421, '289.0', '13.603205680847168', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7584749089398738228', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '成功就是重复做简单的小事 #清华学霸 #抖音知识年终大赏', '成功就是重复做简单的小事 #清华学霸 #抖音知识年终大赏', 1765962036, 'https://www.douyin.com/video/7584749089398738228', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ownpBCc5E5TFeJcAbgrIQXxL9BFWDAA2AfZIxD~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=VPudxelexbRtta3n8sk5iqTPOpU%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415263056639EB78203F20798D5', 12425, 6430, 94, 1332, 'done', 0, 'data/text/7584749089398738228.txt', 'data/summaries/7584749089398738228.md', '视频深入剖析了“成功就是重复做简单的小事”这一理念，指出宏大的目标往往是不真实的理想化形态，容易让人产生畏难情绪并丧失自信。真正的现实是由无数个小事情构成的。很多人无法静下心做事，是因为试图用遥远的大目标来衡量当下的努力。为此，视频提出了一种“进度条式反馈”机制，建议将大目标拆解为可量化的小任务，通过完成具体的小事获得每日的正向反馈。这种方法能有效克服焦虑，让人在持续的小成就中重建自信，最终稳步推进并实现大目标。', '["宏大的目标在现实中是不真实的理想化形态，容易让人产生畏难情绪并丧失自信。", "事情的真实形态是由无数个具体的小事和知识点构成的，认清这一点是静下心做事的前提。", "将大目标拆解为可量化的小任务，并通过进度条式反馈机制给予自己每日的正向激励。", "避免用遥远的大目标直接衡量当下的努力，以免在看不到尽头的过程中消耗自信心。"]', '[{"topic": "目标拆解与任务管理", "why": "将宏大抽象的目标转化为具体可执行的行动步骤是克服拖延和焦虑的核心能力，直接决定了执行力的高低。", "direction": "学习 WBS（工作分解结构）方法，或阅读《搞定：无压工作的艺术》了解任务拆解的具体操作。"}, {"topic": "正向反馈与游戏化机制", "why": "利用进度条等可视化反馈机制能够有效激活大脑的奖励回路，帮助人们在长期目标中维持动机和自信心。", "direction": "了解心理学中的“操作性条件反射”与“即时满足”机制，或阅读《游戏改变世界》探索如何将游戏化思维应用到生活和学习中。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114479, 1784117467, '126.0', '14.944523572921753', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7584079041843842344', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '知识年终盘点｜2025 #清华学霸 #抖音知识年终大赏 #学霸私藏学习小抄大赏 #北大科学夜', '知识年终盘点｜2025 #清华学霸 #抖音知识年终大赏 #学霸私藏学习小抄大赏 #北大科学夜', 1765806030, 'https://www.douyin.com/video/7584079041843842344', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/okQrASfBOCBbYA7qgQQA6LIB2HG6HgDjRe8teG~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=vJ%2BskavIQD5cNSUYWArTCvSvuSc%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141526336846F539ED16DB0186A6', 7199, 2264, 74, 459, 'transcribe_failed', 1, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1783932814, NULL, NULL, NULL, NULL, 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7583618820088270120', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '宣告 #清华学霸 #抖音知识年终大赏 #宣告', '宣告 #清华学霸 #抖音知识年终大赏 #宣告', 1765698868, 'https://www.douyin.com/video/7583618820088270120', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o8AHAATpDEGBS9SQzoefBFbPJDZivmQ1asBDIg~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=rjYQTIl4BLh%2FKIg21EO5NGLeJCI%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714152635580D6154ADE0398377B5', 3664, 1620, 47, 341, 'summarize_failed', 1, 'data/text/7583618820088270120.txt', NULL, NULL, NULL, NULL, NULL, NULL, 1783932814, 1784114518, NULL, '290.0', '11.827777862548828', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7582157787569687848', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '脑雾 #清华学霸 #脑雾 #每天跟我涨知识 #创作人计划 #抖音年终知识大赏', '脑雾 #清华学霸 #脑雾 #每天跟我涨知识 #创作人计划 #抖音年终知识大赏', 1765358705, 'https://www.douyin.com/video/7582157787569687848', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o8gpOADfIABE0A3ifAAgIgBFJT5qKsuqHjI9DP~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=ObcwpDyKiRJuOsJLMmMxaTxBoHw%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141526371856CE616D0C41235499', 279125, 154187, 2350, 37073, 'done', 0, 'data/text/7582157787569687848.txt', 'data/summaries/7582157787569687848.md', '本视频探讨了学习或工作时常见的一种认知障碍状态——脑雾。当人们感到头晕、记忆力下降、注意力难以集中且思维模糊时，往往是大脑进入了脑雾状态。视频指出，脑雾并非单纯的缺乏学习技巧或方法不当，而是大脑在能量耗尽时采取的一种自我保护机制，表现为大脑功能的暂时退化。作者将大脑比作电池，当能量彻底耗干时，大脑为了维持基本生存运转，会主动降低认知和记忆功能。因此，解决脑雾不能仅靠调整学习策略，而必须从身体调节入手，通过恢复身体机能和补充能量来让大脑重新焕发活力，从而摆脱这种迷糊懵懂的困境。', '["脑雾表现为头晕、记忆力减退、注意力难以集中和思维模糊等认知障碍。", "脑雾的本质是大脑能量耗尽时采取的暂时退化与自我保护机制。", "解决脑雾问题不能依赖学习技巧，而需要从身体调节入手恢复大脑能量。", "可以将大脑比作电池，脑雾即是电池彻底耗干的状态，需要重新充电。"]', '[{"topic": "脑雾的神经生物学机制", "why": "了解脑雾背后的神经递质变化和炎症反应，有助于更科学地制定干预策略。", "direction": "查阅神经科学相关文献，研究神经炎症以及多巴胺、乙酰胆碱等神经递质耗竭对认知功能的影响。"}, {"topic": "认知负荷理论", "why": "探究大脑处理信息的能量分配模式，理解为何大脑在超载时需要自我保护机制。", "direction": "阅读约翰·斯威勒的认知负荷理论，学习如何在工作学习中科学分配脑力，避免过度消耗。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114545, 1784117666, '370.0', '26.05458402633667', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7581051326428864192', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '豆包学习法 #清华学霸 #豆包', '豆包学习法 #清华学霸 #豆包', 1765185614, 'https://www.douyin.com/video/7581051326428864192', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oIA9IijxTTIhATBwNQwa1DPAOssV8v5I4IiPg~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=PJ5uxmm86JEqFK1ypp6HGHwp5xg%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714152640B103B0A397C1582A975C', 1962, 1039, 192, 274, 'done', 0, 'data/text/7581051326428864192.txt', 'data/summaries/7581051326428864192.md', '本文介绍了一款名为“豆包”的AI软件在学习中的应用方法，旨在通过其四大核心功能大幅提升学习效率。首先，豆包的语音对话功能可作为英语口语陪练，提供沉浸式语言练习环境。其次，其作业批改功能不仅能识别对错，更能讲解解题思路并自动生成专属错题本，解决学生整理难题。第三，在论文写作方面，豆包能充当“一对一导师”，帮助整理论文结构、搜索素材、润色文笔并规范格式。最后，凭借记忆与成长能力，豆包可化身智能管家，根据个人需求制定并动态优化学习与生活计划。通过这些功能的深度运用，学习者能获得全方位的智能辅助，实现高效学习与成长。', '["豆包的语音对话功能可充当英语口语陪练，提供沉浸式对话练习环境。", "拍照批改作业不仅能讲明解题思路，还能自动生成并动态调整专属错题本。", "上传论文文档后，豆包能充当一对一导师，协助整理结构、润色文笔与规范格式。", "凭借记忆与成长能力，豆包可根据个人需求制定并持续优化学习与生活计划。"]', '[{"topic": "AI辅助语言习得与即时反馈机制", "why": "口语陪练功能背后的核心在于大语言模型的自然交互能力，探究其如何通过即时反馈降低情感过滤，有助于理解AI时代语言学习的最佳路径。", "direction": "了解“情感过滤假说”以及大语言模型在情境化教学中的应用机制。"}, {"topic": "数据驱动的个性化错题管理", "why": "自动生成和优化错题本本质上是基于学习数据的个性化推荐，了解其背后的认知心理学原理能帮助学习者更好地构建自我知识体系。", "direction": "学习“间隔重复”理论及知识图谱在自适应学习系统中的应用。"}, {"topic": "大语言模型的上下文记忆与用户画像", "why": "豆包能作为成长型管家的关键在于其记忆与持续优化能力，探究这一机制有助于理解AI如何从通用工具演变为个性化助手。", "direction": "阅读关于大模型长文本记忆机制、RAG（检索增强生成）技术与个性化智能体构建的文献。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114559, 1784117720, '163.0', '13.609241962432861', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7579565077440624884', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '应该 #清华学霸', '应该 #清华学霸', 1764755022, 'https://www.douyin.com/video/7579565077440624884', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/okAi570Aiww7aIMI0AP89FBAyIPIATBBOQZlt~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=NZv8J8meA66JfXbBecuakmfBero%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714152642573DCBCF937BDA090DE4', 1841, 623, 60, 195, 'done', 0, 'data/text/7579565077440624884.txt', 'data/summaries/7579565077440624884.md', '视频从日常用语"应该"入手，揭示其背后的权力运作逻辑。"应该"本质上指涉规则服从性，起源于家庭和社会的强制性要求，具有权利与义务脱节的特征——只规定义务，不承诺回报。这种指令逻辑会被内化，使人对自己发号施令，但由于主体唯一性，自我命令实际上指向一个想象中的"大他者"——父母精神的内化或社会规训的投射。其后果是主观能动性被压制、主体性缺失，人即便获得实际成果也无法从中感知快乐，最终走向"摆烂"。更深层地，大他者的不断强化使个人无法从自身生活中获得反馈和满足，转而依附虚幻的集体认同或网络纷争，进一步偏离真实生活轨道。', '["\"应该\"本质是对规则的服从，源于家庭的强制性要求，具有权利与义务脱节的特征——只规定义务，不承诺回报。", "\"应该\"逻辑被内化后，人在自我命令时想象出\"大他者\"，导致主观能动性被压制、主体性缺失。", "长期处于只有义务没有权利的状态，使人即便获得实际成果也无法感知快乐，最终走向\"摆烂\"。", "大他者的强化使个人无法从自身生活中获得快乐和反馈，转而依附虚幻的集体认同或网络纷争，进一步偏离真实生活。"]', '[{"topic": "大他者（Big Other）", "why": "它是拉康精神分析理论的核心概念，精准揭示了社会规训如何内化为个体的自我命令，是理解\"应该\"逻辑运作机制的关键。", "direction": "阅读拉康《研讨班》或齐泽克《意识形态的崇高客体》，理解象征界与大他者的关系。"}, {"topic": "异化与主体性", "why": "视频融合了马克思主义哲学的异化概念与心理学的主体性缺失，两者交汇揭示了现代人\"做而不乐\"的深层结构。", "direction": "阅读马克思《1844年经济学哲学手稿》中关于劳动异化的论述，结合拉康的主体理论对照理解。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114583, 1784117826, '278.0', '11.44595193862915', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7578438922695832128', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何划重点 #清华学霸 #边画边写讲知识 #抖音知识年终大赏 #抖音校园 #盘点2025年我get到的重要学习技巧', '如何划重点 #清华学霸 #边画边写讲知识 #抖音知识年终大赏 #抖音校园 #盘点2025年我get到的重要学习技巧', 1764492816, 'https://www.douyin.com/video/7578438922695832128', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/osiFvBtSwCxPBIIiFCABa22MQidImIAwsmi03~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=3HIAQEKRjRXLjPvlUJ5oxMPE2n8%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714153255897731D4286695087A60', 7911, 4801, 73, 801, 'done', 0, 'data/text/7578438922695832128.txt', 'data/summaries/7578438922695832128.md', '本视频系统讲解了读书学习时如何划重点的方法，核心框架围绕三种逻辑展开：记忆逻辑、理解逻辑和思考逻辑。记忆逻辑侧重梳理知识点之间的结构关联，建议跳着画关键词而非整句，以减轻背诵负担；理解逻辑强调通过圈注例子来攻克难懂概念，用不影响原文的标记方式辅助复习；思考逻辑则要求在书旁写备注，将知识与自我关联，形成发散性思维，让教材的思考体系成为个人工具。三者层层递进，从记住知识到理解知识再到内化知识，构成完整的读书划重点方法论，并与笔记整理形成呼应。', '["读书划重点应围绕记忆、理解、思考三种逻辑分别采用不同策略", "记忆逻辑下应跳着画关键词而非整句，减轻记忆负担并强化知识点关联", "理解逻辑下用括号或符号标注帮助理解的例子，方便复习时快速定位", "思考逻辑下在书旁写个人备注，将知识与自我关联形成发散性思维", "三种标记方式应与笔记整理系统配合使用，形成完整学习闭环"]', '[{"topic": "发散性思维与知识内化", "why": "将书本知识转化为个人思考工具是学习的终极目标，发散性思维是连接外在知识与内在认知的关键桥梁。", "direction": "可阅读《如何阅读一本书》（莫提默·艾德勒），重点研究「主题阅读」章节中关于将多本书知识体系化的方法。"}, {"topic": "记忆中的组块化策略", "why": "跳着画关键词本质上是利用组块化减少认知负荷，大脑通过主动重建词间关系来强化记忆，这背后有认知科学的支持。", "direction": "学习认知心理学中的「组块化」与「主动提取」概念，可参考《认知天性》中关于检索练习的论述。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114603, 1784117854, '428.0', '18.625452995300293', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7578095962518949795', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '', '', 1764412968, 'https://www.douyin.com/video/7578095962518949795', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oIUAQIkwIzSiO1IAlayiPLuvlBRBnArSiaqjL~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=t6a36VpfIgudJZngx8wFAC2ZBjE%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714153257A9BBBA227655878E8AE4', 11532, 2192, 193, 1157, 'done', 0, 'data/text/7578095962518949795.txt', 'data/summaries/7578095962518949795.md', '视频深刻剖析了“听话”这一常见教育要求的本质，指出盲目的服从会剥夺个体的主体性与现实权利，使其沦为受苦的客体或被利用的机器。作者认为，要求个体“荣誉给集体、责任归自己”的背后往往隐藏着权威对个体的控制。这种听话文化不仅让人失去快乐，还让本该承担教育引导责任的成年人逃避了责任。最终，视频提出“懂事”而非“听话”才是真正应该追求的品质，懂事意味着拥有独立思考和理解事物的能力，不盲从权威，从而真正确立人的主体性。', '["盲目要求“听话、服从”会剥夺个体的主体性，使其沦为受苦的工具或奴才。", "哲学上的主体性在现实中对应人的权利，要求听话本质上是要求权利的让渡。", "“听话”的真正作用是为父母和老师省事，掩盖了教育者逃避责任的事实。", "真正优良的品格是“懂事”，即具备独立思考和认知能力，不盲从权威。"]', '[{"topic": "主体性与人的权利", "why": "探讨个体在现实中的自主性、权利以及被异化的过程，对理解人的自由本质与社会权力结构至关重要。", "direction": "建议阅读康德关于启蒙与自主理性的论述，或马克思的异化理论。"}, {"topic": "服从心理与权威机制", "why": "分析权威如何通过要求“听话”来塑造顺从者，有助于揭示日常教育与社会控制背后的心理学动因。", "direction": "建议阅读埃里希·弗洛姆《逃避自由》或斯坦利·米尔格拉姆的服从权威实验。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114607, 1784117900, '43.0', '3.0929830074310303', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7577721028311932835', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '家庭：传承与发展 #清华学霸 #边画边写讲知识 #抖音知识年终大赏 #抖音校园 #盘点2025年我get到的重要学习技巧', '家庭：传承与发展 #清华学霸 #边画边写讲知识 #抖音知识年终大赏 #抖音校园 #盘点2025年我get到的重要学习技巧', 1764325671, 'https://www.douyin.com/video/7577721028311932835', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/osG4EiSKggx9AQbTp4QJvGFBAZASDXfeBCBCDP~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=TzANwpo6eAR4GCkQa7Cob5gy%2FyI%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415330008DD60147A5D00FF42B0', 1111, 426, 32, 204, 'done', 0, 'data/text/7577721028311932835.txt', 'data/summaries/7577721028311932835.md', '本文探讨了家庭教育的核心在于传承与发展。视频指出，父母的经验传承在快速变化的现代社会中常常失效，导致子女因对家庭的情绪化忠诚而陷入不理性的行为模式。为了实现真正的发展，子女必须理性克服这种忠诚。面对由此引发的家庭排斥，视频反对当下流行的逃离原生家庭的做法，认为这是下下策。相反，子女应在具备足够的理性和能力后，接过家庭的领导权，体谅并包容长辈，用自身的发展证明自己已具备应对新时代的能力。这种方式既摒弃了传统农业社会盲目服从长辈的封建观念，也拒绝了极端的原生家庭割裂，主张在传承的基础上实现家庭的发展与超越。', '["家庭教育的核心是传承与发展，父母的经验传承为子女发展提供了基础。", "出于对父母的爱与忠诚，子女容易在时代变迁中陷入回归原生状态的非理性困境。", "家庭教育的真正目的是实现发展，必须理性克服与目标相悖的情绪化忠诚。", "面对代际冲突，逃离或割裂原生家庭是下下策，正确做法是接过家庭领导权并包容长辈。", "子女应用自身的发展证明能力，摒弃盲目顺从与极端割裂两种错误的处理方式。"]', '[{"topic": "原生家庭与代际传承", "why": "探讨原生家庭对个体行为模式的塑造机制，有助于理解为何在时代变迁中会产生代际冲突和心理困境。", "direction": "阅读阿德勒的《自卑与超越》或学习家庭系统理论，了解家庭动力对个人成长的影响。"}, {"topic": "家庭生命周期与领导权交接", "why": "家庭领导权的代际交接是家庭发展的重要环节，理解这一过程有助于化解代际冲突，实现家庭良性发展。", "direction": "学习家庭生命周期理论，探讨家庭在不同阶段的结构变化与权力重构。"}, {"topic": "情绪化忠诚与理性决策", "why": "剖析情感羁绊如何干扰理性决策，对于个体在复杂社会环境中保持独立思考与行动力至关重要。", "direction": "阅读丹尼尔·卡尼曼的《思考，快与慢》，研究认知偏差与情绪在决策中的作用机制。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114620, 1784117955, '497.0', '12.603631734848022', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7576238563580660608', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何高效听课 #清华学霸 #边画边写讲知识 #抖音知识年终大赏 #盘点2025年我get到的重要学习技巧', '如何高效听课 #清华学霸 #边画边写讲知识 #抖音知识年终大赏 #盘点2025年我get到的重要学习技巧', 1763980508, 'https://www.douyin.com/video/7576238563580660608', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oM78NpkkfABNBKDiAN2kRWQgbF92DJpf5DEQA2~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=q3G2sge13U528dSOe%2FTkPaSKeag%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415330280FF41C17A8339FD0AC2', 20546, 10781, 120, 2050, 'done', 0, 'data/text/7576238563580660608.txt', 'data/summaries/7576238563580660608.md', '本视频围绕如何高效听课展开，指出无论是课堂听课还是网课，预习都是最核心的环节。预习分两个阶段：第一阶段是提前了解内容、锁定自己不会的重点；第二阶段是尝试自己表述知识点并与老师思路对比，形成高阶学习能力。在记笔记方面，不应照搬板书，而要用词与词的连接提炼重点及其延伸方向，甚至构建问题域，同时把联想到的参考书和关联内容写在旁边。针对网课，视频揭露了机构刻意增加时长以转嫁责任的套路，建议通过预习教材后跳着听，跳过反复讲解和趣事闲聊，只听有效内容。整体主张预习是决定听课效率的根本。', '["预习是高效听课的核心，分两个阶段：先锁定盲区重点，再进行思路对比", "记笔记应提炼关键词并构建连接，而非照搬板书，同时记录联想到的参考内容", "网课普遍存在刻意拉长时长的套路，应通过预习教材后跳着听，只听有效内容", "能预判老师讲解内容甚至判断优劣，说明预习已达到高阶水平"]', '[{"topic": "费曼学习法与思路对比", "why": "视频中提到的「自己先讲一遍再对比老师讲法」本质上是费曼学习法的应用，理解其原理能显著提升预习和听课的深度。", "direction": "阅读《费曼学习法》（作者：尹红心、李伟），或研究「自我解释效应」相关认知科学文献"}, {"topic": "概念图与笔记结构化方法", "why": "视频强调词与词的连接和问题域设计，这与概念图、思维导图等知识可视化工具高度相关，掌握后能系统性提升笔记质量。", "direction": "学习 Joseph Novak 的概念图理论，或研究 Cornell 笔记法和 Zettelkasten 卡片盒笔记法"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114636, 1784117987, '424.0', '14.787566900253296', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7575838109645166504', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '混沌 #清华学霸  #边画边写讲知识 #抖音知识年终大赏 #抖音校园 #盘点2025年我get到的重要学习技巧', '混沌 #清华学霸  #边画边写讲知识 #抖音知识年终大赏 #抖音校园 #盘点2025年我get到的重要学习技巧', 1763887265, 'https://www.douyin.com/video/7575838109645166504', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o0D8dEmBLQkI9FJA7Dffhq7UXQW6B9g0FpQsAA~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=uBImFQqykgfJ6Ld4hV%2F%2BPz8XlRs%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714153305DEB778B72C6864F23908', 158861, 89343, 2530, 15963, 'done', 0, 'data/text/7575838109645166504.txt', 'data/summaries/7575838109645166504.md', '本视频分享了一种被称为“混沌”的思维状态，英文为 Chaos。作者指出，混沌原本指代宇宙中无序、杂乱且模糊不清的状态，但这种状态在个人成长与学习中具有极大的价值。作者从蝙蝠侠中的小丑以及英雄联盟中的金克斯等带有“疯狂”属性的角色身上获得启发，提炼出这种打破常规、拥抱不确定性的思维方式。混沌思维帮助作者在漫长的人生实践中实现了巨大改变，它鼓励人们跳出既定框架，在无序中寻找新的秩序与创造力。这不仅仅是一种应对复杂世界的策略，更是一种底层的人生哲学，揭示了如何在混乱与模糊中建立自我适应与突破的能力。', '["混沌思维指代一种无序、杂乱、模糊不清的状态，原本用于描述宇宙的原始形态。", "作者从蝙蝠侠中的小丑和英雄联盟中的金克斯等带有“疯狂”属性的角色身上获得了混沌思维的启发。", "混沌思维打破了固有的规则与框架，鼓励人们拥抱不确定性和模糊性，在无序中寻找新秩序。", "将混沌思维应用于个人成长，能够有效打破精神内耗，接纳试错，从而激发创造力与心理韧性。"]', '[{"topic": "混沌理论", "why": "理解科学意义上的“混沌”有助于我们在复杂无序的现实系统中发现潜在的规律，提升对不确定性的认知与适应力。", "direction": "建议阅读《混沌：开创新科学》或深入了解“蝴蝶效应”与非线性动力学的基本概念。"}, {"topic": "解构主义哲学", "why": "视频中提到的“小丑”角色本质是对既有秩序的解构，探究此概念能帮助我们理解如何通过打破常规逻辑来重塑思维框架。", "direction": "建议了解雅克·德里达的解构主义哲学思想，或阅读有关逆向思维策略的心理学书籍。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114641, 1784118040, '309.0', '3.831292152404785', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7574379526572123747', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '运气 #清华学霸 #边画边写讲知识 #抖音知识年终大赏 #抖音校园', '运气 #清华学霸 #边画边写讲知识 #抖音知识年终大赏 #抖音校园', 1763547665, 'https://www.douyin.com/video/7574379526572123747', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/osMAkhD5FeIsHmdms9AoABXArnAQQDBfgpZltE~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=kFNmAFZkRDUXvkn2PzOZF0pnfXw%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714153307CBFACAE4228CAA8BD40D', 25686, 11709, 181, 2404, 'summarize_failed', 1, 'data/text/7574379526572123747.txt', NULL, NULL, NULL, NULL, NULL, NULL, 1783932814, 1784114654, NULL, '331.0', '12.915962934494019', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7573293147753946767', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何写草纸 #清华学霸 #标记万物 #边画边写讲知识 #抖音知识年终大赏 #抖音校园', '如何写草纸 #清华学霸 #标记万物 #边画边写讲知识 #抖音知识年终大赏 #抖音校园', 1763294720, 'https://www.douyin.com/video/7573293147753946767', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oYfbiUggN0hnIgiLvOjiyAEBB8q8jIeZ61DAAA~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=HBQjmtYeb8f3eaVXAMFFT30glhs%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141533093A73E6C0404A32F2F991', 22124, 16846, 182, 5751, 'done', 0, 'data/text/7573293147753946767.txt', 'data/summaries/7573293147753946767.md', '视频主旨探讨了草稿纸在学习和考试中的关键作用，打破了“心算快就是聪明”的认知误区。作者提出，将草稿纸书写规范化、步骤化，是提升数学成绩的有效策略。核心论点在于：通过为每道题标明序号并极度细化演算步骤，虽然前期书写看似耗时，但能为后期检查提供清晰逻辑链，大幅缩短复查时间。配合“不会的题直接画圈跳过”的技巧，学生可以留出充足时间对已做题目进行反复检查，确保会做的题百分之百正确。这种“慢即是快”的方法，本质上是将隐性思维显性化，从而降低认知负荷，减少失误，最终实现成绩的突飞猛进。', '["摒弃过度依赖心算的习惯，将草稿纸的演算过程视为提升准确率的关键步骤。", "为每道题在草稿纸上标明序号，保持演算区域清晰有序，避免不同题目相互混淆。", "即使是简单的计算也要强制拆解步骤，将隐性思维外化为显性文字，方便后续检查。", "遇到不会的题直接画圈标记并跳过，利用草稿纸上的清晰步骤对已做题目进行反复检查。", "通过前期看似耗时的详细书写，换取后期高效的复查时间，确保会做的题百分之百得分。"]', '[{"topic": "认知卸载", "why": "将大脑中的运算过程转移到外部媒介（如草稿纸）上，可以释放工作记忆容量，降低认知负荷，从而减少高压下的计算错误。", "direction": "建议阅读《思考，快与慢》中关于系统1和系统2的运作机制，了解如何通过外部工具辅助理性思考。"}, {"topic": "检查清单机制", "why": "视频中提到的标号、写细步骤、画圈标记，本质上是在构建一套自我检查清单，能有效对抗人类在疲劳或高压环境下的认知盲区。", "direction": "学习阿图·葛文德的《清单革命》，探索流程化如何保障高可靠性。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114667, 1784118200, '185.0', '12.557788133621216', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7572136957695318208', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '读书有没有用 #清华学霸 #读书有用 #为什么要读书#边画边写讲知识 #抖音知识年终大赏', '读书有没有用 #清华学霸 #读书有用 #为什么要读书#边画边写讲知识 #抖音知识年终大赏', 1763025525, 'https://www.douyin.com/video/7572136957695318208', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oAnAEftVZgleBF9IAx0iAKBDoAiiIIul0aCwsk~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=Yl8raprT%2B5C%2BgcLLkCNNzkFCntE%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141533124F2D55A79F2F4B00F3B7', 3210, 1229, 73, 378, 'summarize_failed', 1, 'data/text/7572136957695318208.txt', NULL, NULL, NULL, NULL, NULL, NULL, 1783932814, 1784114693, NULL, '273.0', '7.292816877365112', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7568042920956642112', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '批判性思维之观点与事实 #清华学霸 #批判性思维 #观点与事实 #边画边写讲知识 #抖音校园', '批判性思维之观点与事实 #清华学霸 #批判性思维 #观点与事实 #边画边写讲知识 #抖音校园', 1762072310, 'https://www.douyin.com/video/7568042920956642112', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oQwHfx0EAF7pBQyQjCFSAFsDAwGIeBivfiDB48~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=vJCOgxOgbyYvTNHry8Y05CTV%2FeE%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714153314EAD57382D1578A78F179', 4449, 2067, 103, 471, 'done', 0, 'data/text/7568042920956642112.txt', 'data/summaries/7568042920956642112.md', '本视频探讨了批判性思维的基础逻辑，即严格区分事实与观点。事实属于真理范畴，是对客观规律的反映，具有明确的是非对错；观点则是基于个体主观能动性的价值判断，没有绝对的对错之分，观点的分歧本质上是立场与利益的差异。日常生活中常见的抬杠，往往是因为人们将个人观点偷换为事实，并试图以此否认他人。这种混淆不仅导致无意义的争论，还会在批判事实时演变成对个体主体性的人身攻击。因此，批判性思维要求我们在真理范畴内进行否定之否定的螺旋式上升，坚持实事求是，在指出问题时做到对事不对人，避免将针对事实的否定扩大为对个人的全盘否定。', '["事实属于真理范畴，是对客观规律的反映，具有明确的是非对错标准。", "观点属于价值判断，基于个体主观能动性，无绝对对错，分歧源于立场与利益的不同。", "日常争论中的抬杠本质上是将个人观点偷换为事实，并试图以此否认他人观点的逻辑混淆。", "否定他人的观点等同于否定其主体性，因此在进行批判时应严格区分对事实的质疑和对人的攻击。", "批判性思维要求在真理范畴内进行否定之否定，通过发现问题、承认问题、解决问题实现螺旋上升。"]', '[{"topic": "事实与价值的二分法", "why": "这是哲学和逻辑学中的经典命题，厘清二者界限是进行理性讨论和批判性思考的基石，能有效避免生活中的无谓争端。", "direction": "学习休谟的“是与应该”问题，阅读大卫·休谟的《人性论》或相关伦理学基础教材。"}, {"topic": "否定之否定规律", "why": "它是唯物辩证法的核心规律之一，揭示了事物发展的前进性与曲折性，对理解批判性思维中如何通过试错和反思实现认知跃迁至关重要。", "direction": "阅读《马克思主义哲学原理》中关于唯物辩证法基本规律的篇章，或研究黑格尔的辩证法思想。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114707, 1784118367, '333.0', '13.020963907241821', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7565455276674764032', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '唯物与唯心 #清华学霸 #马克思哲学 #唯物主义 #唯心主义', '唯物与唯心 #清华学霸 #马克思哲学 #唯物主义 #唯心主义', 1761469824, 'https://www.douyin.com/video/7565455276674764032', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ocpFvkEQQCAjeeefCyFM7LPwYwnRUDAHDE82B8~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=F8nyzPPPJanHYZiEq4irrJSyzj8%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714153317C02BFD707157E3E8C621', 1349, 454, 30, 152, 'done', 0, 'data/text/7565455276674764032.txt', 'data/summaries/7565455276674764032.md', '本视频从马克思主义哲学的基本问题——唯物主义与唯心主义出发，剖析了人们在日常学习与工作中常见的心理困境。许多人在做事受挫时习惯于自我否定或指责他人，即“对人不对事”；而在对待自己的休息和主观感受时，却又“对事不对人”，将自己当作纯粹的学习工具，忽略自身感受。视频指出，这种现象本质上是混淆了唯物与唯心的边界。唯物主义强调客观物质决定意识，这意味着我们的计划与目的应紧紧围绕“事情”本身展开，而非被主观情绪所左右。主观感受无法直接改变客观现实，想要成事就必须去改造世界。因此，最好的做事状态并非刻意寻找某种心理准备，而是将全部注意力投入到具体的事情中。越是不在意自我状态，越容易在改造世界的过程中形成身体的惯性，从而自然而然地进入专注的心流之中。', '["人们在受挫时常“对人不对事”，在休息时又“对事不对人”，本质是混淆了唯物与唯心的边界。", "唯物主义强调客观物质决定意识，计划与行动应围绕“事情”本身而非主观情绪。", "主观感受无法改变客观现实，改变事情的唯一途径是去改造客观世界。", "做事最好的状态是不在意状态，全神贯注于事情本身，让身体在实践中形成惯性。"]', '[{"topic": "哲学的基本问题", "why": "理解思维与存在的关系是把握唯物主义与唯心主义区分的钥匙，能帮助人们在日常中正确区分主观感受与客观现实。", "direction": "建议阅读恩格斯《路德维希·费尔巴哈和德国古典哲学的终结》中关于哲学基本问题的论述。"}, {"topic": "马克思主义的实践观", "why": "马克思强调通过实践改造客观世界，深入理解这一概念有助于破除心理内耗，将注意力从寻找“好状态”转移到具体的行动上。", "direction": "建议学习《关于费尔巴哈的提纲》中关于实践是感性的人的活动、客观物质活动的论述。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114716, 1784118427, '376.0', '8.712376832962036', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7565090515714067712', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '笛卡尔逻辑法 #清华学霸 #学习方法', '笛卡尔逻辑法 #清华学霸 #学习方法', 1761384899, 'https://www.douyin.com/video/7565090515714067712', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ocCnBaBbQ8IuwL7LjIPAcm3YJPZmIATiPiayU~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=8aqlQhRGg7n4uNL4tnrllhO4nq8%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141533197C7685E973CE5E0865B8', 18665, 10403, 116, 2123, 'done', 0, 'data/text/7565090515714067712.txt', 'data/summaries/7565090515714067712.md', '视频主旨在于介绍一种名为“笛卡尔逻辑法”的基础思维方法。该方法受笛卡尔哲学中寻找第一起点并不断派生推导的逻辑启发，是一种从微小起点不断生长的思考方式。其核心在于面临选择或不同方案时，通过“如果……那么……”的假设逻辑，将所有相关因素以及不同选项的后果逐一罗列在纸面上。这种方法的最大价值在于排除主观情绪的干扰，将模糊的感觉转化为理性的可行性分析，将注意力集中在事情本身。通过把一切摊开，个体能够清晰地看到各种情况，进行权重考量，把自我视为众多因素之一，从而做出最有利的现实选择。', '["笛卡尔逻辑法是一种从微小起点不断派生推导的生长型思维方法，适用于面临选择或多方案决策时。", "该方法通过“如果选择A”与“如果不选A”的假设逻辑，全面罗列不同选择对健康、时间、成长等因素的影响。", "核心价值在于排除情绪干扰，将模糊感觉转化为理性的可行性分析，强调事情大于主观自我。", "通过将所有选项及后果摊开在纸面上，将自我降维成众多因素之一，从而进行权重考量并做出最有利的决策。"]', '[{"topic": "笛卡尔的“我思故我在”与理性主义", "why": "了解笛卡尔逻辑法的哲学源头，有助于更深刻地理解“从第一起点派生推导”的思维底层逻辑。", "direction": "建议阅读笛卡尔的《第一哲学沉思集》或学习西方理性主义哲学基础概念。"}, {"topic": "决策模型与权重分析法", "why": "视频中提到的将因素罗列后进行“权重考量”是决策科学的核心，深入探究能提升复杂决策的科学性。", "direction": "学习决策树分析、多属性效用理论，或阅读《聪明人的魔法箱》等工具书。"}, {"topic": "认知行为疗法中的认知解离", "why": "视频中提到将自我变成诸多因素之一以排除情绪干扰，与心理学中拉开自我与情绪/念头距离的技术高度相关。", "direction": "了解认知行为疗法（CBT）中的“认知解离”概念，阅读接纳承诺疗法（ACT）相关书籍。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114730, 1784118508, '272.0', '12.725107908248901', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7564379060072287523', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何保持专注 #清华学霸  #专注 #学习方法', '如何保持专注 #清华学霸  #专注 #学习方法', 1761219249, 'https://www.douyin.com/video/7564379060072287523', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ocLPxDMR9Ad5BoBEI0lCP7SCGeoegedwB68AgG~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=w9zMn3rE7qqiCtlb8LJbiH78Png%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714153321D5EC2A6F8140EB8DD317', 79133, 49216, 759, 9088, 'done', 0, 'data/text/7564379060072287523.txt', 'data/summaries/7564379060072287523.md', '这段视频探讨了如何在确定目标后保持专注力的方法。作者从大脑的注意力机制入手，介绍了两种注意力：刺激运动注意（对周围环境的感应）和目标导向注意（对目标投入的精力）。核心论点是：两种注意力同时存在，无法只保留一种，因此提高专注力的关键不是削减分心对象，而是用目标填满注意力空间。当注意力分散时，跳转到下一个目标而非放任。具体方法是通过信息提取（输入）和信息输出（思考）的循环来填满注意力，以读书为例，边读边思考就是同时进行输入输出，思考方向包括上下文关系、知识点关联性和与自我的关系。', '["大脑存在两种注意力：刺激运动注意（环境感应）和目标导向注意（目标投入），两者同时存在无法割裂", "提高专注力的核心策略是填满注意力，而非削减分心对象", "注意力分神时跳转到下一个目标，而非放任流向无关事物", "填满注意力的基本方式是信息提取与信息输出（输入与思考）的持续循环", "好的读书习惯是边读边思考，思考方向包括上下文关系、知识点关联性和与自我的关系"]', '[{"topic": "刺激运动注意与目标导向注意的神经机制", "why": "理解两种注意力的神经科学基础，有助于从生理层面认识专注力有限的原因，而非简单归因于意志力不足", "direction": "建议阅读认知神经科学相关书籍，如《注意力经济学》或迈克尔·波斯纳关于注意力网络的研究"}, {"topic": "主动阅读与信息输出策略", "why": "视频提到的边读边思考只是入门，系统掌握主动阅读法能显著提升信息吸收率和专注持续时间", "direction": "建议阅读莫提默·艾德勒《如何阅读一本书》，学习检视阅读、分析阅读和主题阅读的分层方法"}, {"topic": "多目标注意力切换与心流状态", "why": "视频中提到的「跳到下一个目标」与心理学中的心流理论有交集，深入理解有助于设计个人化的专注方案", "direction": "建议阅读米哈里·契克森米哈赖的《心流：最优体验心理学》，了解挑战与技能匹配对专注的影响"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114754, 1784118645, '454.0', '9.04391622543335', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7562484684024204544', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何看待努力 #清华学霸 #学习方法 #努力 #学习效率', '如何看待努力 #清华学霸 #学习方法 #努力 #学习效率', 1760778180, 'https://www.douyin.com/video/7562484684024204544', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o0LYIIPIQiw2VOzQ1NasPw8XLPPBAiBIvEwBA~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=Y8w6cn37ChSwFvlo7%2BwQR%2BR%2Fzrk%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141533246B8B8B710C8C480A865E', 22432, 9052, 387, 2382, 'done', 0, 'data/text/7562484684024204544.txt', 'data/summaries/7562484684024204544.md', '视频探讨了“努力到底有没有用”这一话题，指出盲目强调付出代价的努力存在根本性的逻辑错误。作者认为，回报不应等于单纯的代价付出，而应是代价乘以效率。如果缺乏效率，一味自我损耗，只会导致无效学习和“越努力越笨”的恶性循环。这种模式会让人陷入以“惨”为荣的自我感动中，最终成为成绩平平的中等生，甚至延伸到工作中导致自我封闭。相反，真正优秀的人不谈努力，而是从持续的正反馈中获得“爽”感。视频进一步拆解了效率的内涵，强调其在于对自身和目标的规划能力，以及对外部资源的整合利用能力。作者呼吁摒弃自我献祭式的努力，转向提升效率和资源整合。', '["努力的实质如果是单纯付出代价和自我损耗，就犯了忽视效率的根本性逻辑错误。", "回报等于代价乘以效率，效率是乘法因子，低效的努力会导致与他人的差距越拉越大。", "缺乏效率的人容易陷入“越惨越成功”的自我感动中，导致成绩或业绩长期停滞在中等水平。", "真正优秀的人不强调努力，而是通过持续的正反馈获得成就感，无需通过吃苦来感动自己。", "提升效率的核心在于对自我和目标的规划能力，以及整合外部资源的能力，而非单纯的自我消耗。"]', '[{"topic": "效率公式与无效努力", "why": "理解效率作为乘法因子的作用机制，有助于诊断个人学习或工作中是否存在“假性勤奋”和无效损耗。", "direction": "建议阅读《刻意练习》中关于有效反馈与心智模型构建的内容。"}, {"topic": "资源整合与自我效能感", "why": "摒弃单打独斗的思维，学会识别和调动身边资源，是突破个人能力瓶颈、实现跨越式成长的核心。", "direction": "了解社会资本理论，学习如何建立个人资源网络体系。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114770, 1784118693, '336.0', '14.38309383392334', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7561749422247136552', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '拿到卷子后做什么 #清华学霸 #学习方法 #应试技巧', '拿到卷子后做什么 #清华学霸 #学习方法 #应试技巧', 1760606993, 'https://www.douyin.com/video/7561749422247136552', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oQiMIDIfFxhIJ1A9hueo3Bi0bIuB7vgAAc2hwB~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=Dtu5luLJ8Rraey2Ag1lwPXAT7ts%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415332667EE0D4145116580AA5E', 95837, 59235, 499, 13034, 'done', 0, 'data/text/7561749422247136552.txt', 'data/summaries/7561749422247136552.md', '考试发卷后的三到五分钟不仅是用于检查试卷漏印、错印的时间，更是决定整场考试策略的关键时期。在这段时间内，考生应快速浏览试卷结构，判断整场考试的难度是偏高还是偏低。针对不同难度的试卷，需采取截然不同的应试策略。如果面对的是简单的试卷，核心策略是“反复”，即拆解题目结构并在草稿纸上保留计算过程，通过二次验算确保简单题百分之百正确，避免粗心丢分。而面对难题较多的试卷，核心策略则是“挑”，即优先解决能快速拿分的题目，将难题圈出，若遇卡壳果断跳过，最终目标是把会做的题全部做对。抓住这开考前的几分钟，合理规划答题节奏与策略，能有效提升考试成绩。', '["发卷后的三到五分钟是制定考试策略的关键时期，可用于预判试卷难度。", "面对简单试卷，策略是“反复”，在草稿纸保留计算步骤以便二次验算，确保百分百正确。", "面对难题试卷，策略是“挑”，先快速解决容易题，把难题圈出，遇卡壳果断跳过。", "无论试卷难易，核心目标都是把会做的题全部做对，避免无谓失分。"]', '[{"topic": "元认知策略在考试中的应用", "why": "考试不仅是做题，更是对自身认知过程和任务难度的评估，元认知能力决定了策略调整的效率。", "direction": "阅读《认知天性》或学习元认知相关概念，了解如何在学习任务中进行自我监控与策略调整。"}, {"topic": "草稿纸管理与规范书写", "why": "科学规划草稿纸书写不仅有助于二次验算，更能理清逻辑步骤，减少粗心导致的失分。", "direction": "研究理科考试中的草稿纸分区与规范书写法，将其作为一项专门的应试技能进行刻意练习。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114779, 1784118794, '337.0', '8.304381847381592', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7560237713204628776', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何面对挫折 #清华学霸 #挫折 #学习方法', '如何面对挫折 #清华学霸 #挫折 #学习方法', 1760255018, 'https://www.douyin.com/video/7560237713204628776', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oQrQMrRE1bI06SCoAtBI9XeFmfv201ADADTBgO~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=UrQ5DU5aigaWJ2%2B8r5eqxsJ4Hg4%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141533295ADB65EEC213C7FAB8F6', 35320, 16837, 285, 3399, 'done', 0, 'data/text/7560237713204628776.txt', 'data/summaries/7560237713204628776.md', '本视频以马克思主义实践论为基础，探讨了如何正确面对挫折与失败。讲者指出，挫折本质上是客观实践的失败，应当从人、行为、客体三个维度进行拆解分析。面对失败，切忌进行自我人身攻击，而应将注意力转向行为层面的计划与方法，以及客体层面的要素拆解、横向普遍联系与纵向历史参考。通过将细化后的内容填入时间计划，并善用外力与工具，实现人、行为与对象的统一，最终达成实践的成功。', '["挫折本质是客观实践的失败，应从人、行为和客体三个维度进行拆解分析。", "面对失败应停止对自己的人身攻击，避免陷入身份降低的无意义内耗。", "长期行为的核心在于计划与方法，需将目标分化拆解并填入时间计划中。", "攻克客观对象需借助横向的普遍联系和纵向的历史经验参考，避免固步自封。"]', '[{"topic": "马克思主义实践论", "why": "视频以实践论为基础框架，将实践拆解为主体、行为和客体，理解这一哲学概念有助于建立科学的问题分析与解决框架。", "direction": "建议阅读毛泽东《实践论》，深入了解认识与实践的辩证关系，以及如何通过实践改造客观世界。"}, {"topic": "普遍联系与概念外延", "why": "通过寻找事物的外延和横向联系来辅助学习，是一种打破认知瓶颈的高效思维模型，能够帮助我们在复杂系统中找到破局点。", "direction": "学习逻辑学中关于概念外延的定义，以及哲学中普遍联系的观点，探索如何将其应用于跨学科学习和复杂问题拆解。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114794, 1784118855, '354.0', '14.705070734024048', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7558746029488475426', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '短期计划VS长期计划 #清华学霸 #学习 #知识分享  #制定计划', '短期计划VS长期计划 #清华学霸 #学习 #知识分享  #制定计划', 1759907710, 'https://www.douyin.com/video/7558746029488475426', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/okbm7ok0EFngAF7PNBDIygADHmJ5BwDeAI4f9a~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=Yy%2BSnRjb1%2BqAWm7%2BqtXSjH6qWO0%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714153331F42B2054D64917069C33', 71467, 41171, 318, 8511, 'done', 0, 'data/text/7558746029488475426.txt', 'data/summaries/7558746029488475426.md', '本视频以毛主席“战略上藐视敌人，战术上重视敌人”的经典论断为切入点，深入探讨了长期计划与短期计划如何协调配合的问题。视频指出，长期目标的核心在于前期的可行性评估，在确立目标前需经过充分的调研与分析。一旦确认目标可行，就必须培养并具备“坚定信心”这一关键能力。在后续执行过程中，无论遇到何种挫折与负面反馈，都要在战略上保持乐观，坚信自己必定能成功。这种将理性的前期可行性分析与感性的后期坚定信念相结合的方法，是确保长期规划顺利推进的关键。', '["长期目标的制定首要任务是深入评估其现实可行性，需投入充分时间进行论证。", "坚定信心是一种可以通过理性分析支撑起来的关键能力，而非单纯的情绪状态。", "在目标执行过程中，无论遇到何种反馈，都应在战略上保持乐观，坚信最终必胜。"]', '[{"topic": "战略与战术的辩证关系", "why": "将军事战略思想迁移到个人成长领域，能帮助理解长期规划与短期执行的互补性，避免眼高手低或丧失信心。", "direction": "建议阅读毛泽东《中国革命战争的战略问题》，或学习OKR（目标与关键结果）管理法中的战略拆解逻辑。"}, {"topic": "自我效能感与信念强化", "why": "理解信心是如何作为一种能力被培养和维持的，有助于在长期目标的执行中建立心理防御机制，对抗负面反馈。", "direction": "建议学习阿尔伯特·班杜拉的《自我效能：控制的实施》，深入探究心理学层面的信念驱动机制。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114801, 1784118901, '314.0', '6.338284730911255', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7556917112112237858', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '复盘的底层逻辑。#清华学霸 #复盘 #学习方法 #复习 #思维方式', '复盘的底层逻辑。#清华学霸 #复盘 #学习方法 #复习 #思维方式', 1759481880, 'https://www.douyin.com/video/7556917112112237858', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ok7CCLBrBfJe2MvhBRIvA6GfhqQBQqExGxkLIA~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=m4pZ5OUMNJIrVI%2FT%2FSTVs4W7Ghs%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714153333101D167A3670B608D3AF', 221583, 161756, 1033, 31245, 'done', 0, 'data/text/7556917112112237858.txt', 'data/summaries/7556917112112237858.md', '视频深入探讨了复盘的底层逻辑与具体实践方法，指出复盘的根本目的在于将外部的客观知识或事件逻辑内化到大脑的思维系统中。复盘主要分为事件复盘与学习内容复盘两个维度。事件复盘要求从外部成长与结果两方面评估，并在内部通过拆解多元因果链条来定位关键步骤的成败原因。学习内容复盘则强调知识结构的内化，建议通过填充关键词、寻找核心重点、理解知识推导逻辑三个步骤，将书本知识重新生成并融入自身思维。整个复盘过程旨在通过细化拆解与逻辑重建，提升个人的学习效率与解决实际问题的能力，达到以不变应万变的内化境界。', '["复盘的根本目的是将客观事物和逻辑链条内化为大脑的思维系统。", "事件复盘需从成长与结果两方面评估外部影响，并拆解多元因果链条定位关键步骤。", "学习内容复盘需先构建知识框架填充关键词，再寻找能串联全局的核心重点。", "最高阶的学习复盘要求理解知识的推导过程与衍生系统，使知识完全融入自身思维。", "记录关键节点的状态变化有助于拆解和发现导致成败的深层原因。"]', '[{"topic": "多元决定论与因果链条拆解", "why": "掌握多元决定论能帮助人们跳出单线思维，在复杂事件中精准定位导致成败的多重因素，是深度复盘的核心工具。", "direction": "建议阅读《系统之美》了解系统思考与因果回路图，学习如何拆解复杂系统的反馈机制。"}, {"topic": "知识图谱与认知内化", "why": "理解知识的衍生系统能够极大提升学习效率，将碎片化信息转化为可调用的结构化知识，是从应试到知识创新的必经之路。", "direction": "学习“费曼技巧”和“概念图”相关理论，探究如何将书本知识进行二次重构与深度输出。"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114824, 1784118945, '431.0', '21.38108801841736', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7556186887531138354', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何找状态 #清华学霸  #学习方法 #抖音知识年终大赏 #抖音校园 #盘点2025年我get到的重要学习技巧', '如何找状态 #清华学霸  #学习方法 #抖音知识年终大赏 #抖音校园 #盘点2025年我get到的重要学习技巧', 1759311865, 'https://www.douyin.com/video/7556186887531138354', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/owfLgELfh7IjZRrzCEGAg7ct2njA3EtDgeIHeL~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=qtwUZiuncLZFnUSBieQxskqRk8Q%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714153336565C1F87547E9D635842', 478060, 298190, 3387, 54156, 'done', 0, 'data/text/7556186887531138354.txt', 'data/summaries/7556186887531138354.md', '视频主要探讨了如何迅速进入学习或做事的状态，核心在于将漫游的注意力转移到具体事务上。作者提出了两种有效方法。第一种是视频输入法，通过观看与目标任务相关的有趣且具逻辑性的视频，引导自我向客体转化，利用代入感在短时间内将情绪和注意力带入状态。第二种是计划法，强调设定具体的时间、内容以及反馈机制。通过明确具体任务并严格遵守不随意更改计划的正反馈原则，唤醒计划内状态。同时，加入结果反馈以避免应付状态，在客体世界扔下知识之锚。两种方法结合，经过一到三个月的练习，能帮助大脑快速切换并找到理想状态。', '["视频输入法通过观看有趣且具逻辑性的相关视频，能在三到十分钟内将漫游的注意力代入到目标状态中。", "计划法要求明确具体的时间与内容，并在提前完成任务时继续执行以建立正反馈，唤醒计划内状态。", "设置结果反馈机制能有效避免应付状态，通过总结或教授他人使学习成果在知识体系中锚定。", "时间、内容与反馈三位一体，配合一到三个月的长期练习可快速实现大脑状态的切换。"]', '[{"topic": "心流理论", "why": "视频中提到的将自我转化为客体并进入忘我状态，本质上就是心理学中的心流体验，理解它能更好掌握状态切换的底层逻辑。", "direction": "建议阅读米哈里·契克森米哈赖的《心流：最优体验心理学》"}, {"topic": "正反馈与习惯养成", "why": "视频强调不随意更改已完成计划以强化大脑认知，这涉及行为心理学中的操作性条件反射与正反馈机制。", "direction": "学习B.F.斯金纳的行为主义理论或查阅习惯养成的闭环模型"}]', 'volc_glm_5_2', 'glm-5.2', 1783932814, 1784114843, 1784119020, '436.0', '18.01529598236084', 1783932811, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7549824343682452751', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何面对情绪 #清华学霸 #情绪管理 #焦虑 #紧张', '如何面对情绪 #清华学霸 #情绪管理 #焦虑 #紧张', 1757830467, 'https://www.douyin.com/video/7549824343682452751', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oYzxDflIAEWDQUXqcCogFB1GQo9lACDufAvxpD~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=c1Cmxhx3iuPbUDHq0seLj0rgQfw%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415392786AEF76528FDCF8F0904', 8384, 3984, 196, 1285, 'done', 0, 'data/text/7549824343682452751.txt', 'data/summaries/7549824343682452751.md', '视频主要探讨了如何正确面对和处理紧张、焦虑等负面情绪，特别是在考试或遇到困难的高压情境下。核心论点是反对将情绪视为表现不佳的借口，指出这种身心分离的紧张状态才是个人真实实力的反映。因此，我们应当像解决学业或工作难题一样，直面并解决情绪问题。通过持续的心理觉察和疏导，在长期实践中逐步缓解情绪扭曲，最终接纳真实自我并提升实际能力。', '["紧张和焦虑是真实的自我状态，不应作为考试失利或工作失误的借口。", "评估自身实力时，必须将高压环境下的情绪反应和生理表现纳入考量。", "应当像解决学业和工作难题一样，去直面、分析并解决自身的情绪问题。", "情绪的觉察与疏导是一个长期过程，通过每次认真的心理梳理，一到两个月可有效缓解。"]', '[{"topic": "身心分离现象", "why": "帮助理解为何人们在压力下的自我认知与实际表现存在巨大落差，是接纳真实自我和提升抗压能力的关键切入点。", "direction": "建议阅读心理学关于“具身认知”或“应激反应”的相关书籍，如《身体从未忘记》。"}, {"topic": "情绪的觉察与接纳", "why": "了解如何将情绪作为客观任务去处理，而非压抑或逃避，是提升心理韧性和情绪管理能力的核心方法。", "direction": "学习正念减压疗法（MBSR）或阅读《接纳承诺疗法》（ACT）相关书籍，掌握情绪疏导的实操技巧。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114903, 1784119318, '605.0', '8.644737005233765', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7548410394383256884', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '读书就是借命 #清华学霸 #读书 #为什么要读书 #读书的意义', '读书就是借命 #清华学霸 #读书 #为什么要读书 #读书的意义', 1757501253, 'https://www.douyin.com/video/7548410394383256884', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oA4aE27wgao9AII0oUIXfqFFA7ABDVfVBWB9Dx~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=QqbvhzC7jtMVi33ofOp8g1ucR%2Bw%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415393002AE20D25E185787500C', 9543, 4062, 282, 1596, 'summarize_failed', 1, 'data/text/7548410394383256884.txt', NULL, NULL, NULL, NULL, NULL, NULL, 1784032681, 1784114913, NULL, '120.0', '9.670692920684814', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7547277005512625423', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '阿尔都塞——征候阅读法 #清华学霸 #思维工具 #认知升级 #学习方法 #阅读技巧 #开学的精选', '阿尔都塞——征候阅读法 #清华学霸 #思维工具 #认知升级 #学习方法 #阅读技巧 #开学的精选', 1757237367, 'https://www.douyin.com/video/7547277005512625423', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oA7pnAfmDvQD2U9uAhgkQIFEpoXPeo9HD5AUBF~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=izAuZd3qrQXKD5K%2FWXRNcb%2FucUM%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141539327D8836151CCE3E6E2A4E', 47002, 33884, 671, 6618, 'done', 0, 'data/text/7547277005512625423.txt', 'data/summaries/7547277005512625423.md', '法国哲学家阿尔都塞的症候阅读法是一种高级且极具挑战性的阅读策略，其核心逻辑是将书籍视作病人进行诊断。该方法不仅要求读者理解文本表面的可见结构，更要敏锐捕捉作者的“不可见结构”、“空白与沉默”以及“矛盾与断裂”。通过发掘作者为了系统化而遗漏的关键信息、因时代或个人局限而回避的内容，以及文本中自相矛盾的逻辑断裂点，读者能够洞穿作者的真实立场与所处时代的深层背景。这种阅读法能帮助我们在阅读中找到理论突破口，实现对知识的批判性重构与认知升级。', '["症候阅读法的核心逻辑是将书籍视作病人，通过诊断文本中的症候来挖掘深层逻辑。", "识别“不可见结构”，寻找作者为了系统化而遗漏的关键信息，以此作为理论突破口。", "关注文本中的“空白与沉默”，借此反推出作者的知识储备及所处时代的政治、学术背景。", "捕捉论述中的“矛盾与断裂”，透过作者的自相矛盾反推其真实立场与行为逻辑。", "马克思正是运用此方法洞察了亚当·斯密《国富论》中的矛盾，进而创立了剩余价值学说。"]', '[{"topic": "阿尔都塞的结构主义马克思主义", "why": "症候阅读法是阿尔都塞哲学思想的核心方法之一，理解其哲学背景有助于掌握该方法在意识形态批判中的真正威力。", "direction": "阅读阿尔都塞的《读<资本论>》或了解其“多元决定论”概念。"}, {"topic": "结构主义文本分析法", "why": "症候阅读法深受结构主义影响，强调通过文本表层结构揭示深层不可见的支配性结构，这为所有人文社科类阅读提供了范式。", "direction": "学习索绪尔的语言学理论或福柯的知识考古学方法。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114940, 1784119450, '422.0', '14.221240043640137', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7546539966030925108', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '寄生式爱情 #清华学霸 #爱情观 #主体性缺失', '寄生式爱情 #清华学霸 #爱情观 #主体性缺失', 1757065762, 'https://www.douyin.com/video/7546539966030925108', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oYk6B66Q7G08ELessACWSQcdQAfRf1MrhniBXC~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=9iVD6JVv%2BUUCxVwPSp%2BV%2FeKxwdk%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714153935BE0076C8E0D2E90A4FED', 2846, 1308, 112, 388, 'done', 0, 'data/text/7546539966030925108.txt', 'data/summaries/7546539966030925108.md', '本视频探讨了“寄生式爱情”这一错误的爱情模式。主讲人指出，爱情本质上是双方平等的交互，但当一个人在成长过程中长期遭受打压与否定，便会产生“自我失位”——将攻击与批评误认为爱的表达，并根深蒂固地感到自卑与不配得。这类人在亲密关系中会一方面寻求伴侣补齐自己的缺失（如没钱找有钱的），另一方面又因恐惧分离而不停地PUA、打压对方，陷入“没有不行、有了也不行”的矛盾循环。其根本错误在于逃避自我责任，不填补自身缺口却要求伴侣改变。主讲人认为，解决之道在于意识到人生是自己的，活出自我，以“顶峰相见”的姿态面对爱情，同时警惕旧有创伤模式的复发。最终以舒婷《致橡树》作结，强调既交付又独立才是最好的爱情状态。', '["爱情本质是双方平等交互，寄生式爱情则是一方将自我缺失转嫁到伴侣身上的错乱模式", "童年长期遭受打压会导致“自我失位”，使人将攻击和否定误认为爱的表达形式", "自我失位的人不填补自身缺口，而是寻找伴侣来补齐自己，同时因恐惧分离而反复打压对方", "破局关键在于意识到人生是自己的，活出自我，以“顶峰相见”的姿态面对爱情", "舒婷《致橡树》中“既交付又独立”是理想亲密关系的隐喻"]', '[{"topic": "自我失位与依恋理论", "why": "视频中提到的“自我失位”现象与心理学中不安全依恋模式高度相关，深入理解可以帮助识别童年创伤如何在成年亲密关系中复演。", "direction": "阅读鲍尔比的依恋理论经典著作，或学习“焦虑型依恋”“回避型依恋”的概念框架"}, {"topic": "PUA与煤气灯效应的关系机制", "why": "视频中描述的打压、否定、让对方觉得自己有问题的行为模式，与煤气灯效应的心理操控机制一致，理解其运作原理有助于识别和干预。", "direction": "阅读罗宾·斯特恩《煤气灯效应》，了解情感操控的三个阶段及其心理基础"}, {"topic": "主体性与自我分化", "why": "视频核心主张“活出你自己”，对应的心理学概念是自我分化——即在亲密关系中保持独立自我而不被情绪融合吞没，这是健康关系的基础能力。", "direction": "学习默里·鲍恩的家庭系统理论中关于“自我分化”的论述"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114956, 1784119526, '329.0', '15.264494895935059', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7545788825734810914', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '零和博弈 #清华学霸 #零和博弈 #九三阅兵', '零和博弈 #清华学霸 #零和博弈 #九三阅兵', 1756890875, 'https://www.douyin.com/video/7545788825734810914', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oQfyBRWapkGJeO9ABKMAAycR7bRANC3BVAQt8e~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=CY2jHoz4PFwIZnY4B%2BY7nM9TS4Y%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141539378A5DE867A7210117A2D9', 3261, 1019, 105, 331, 'done', 0, 'data/text/7545788825734810914.txt', 'data/summaries/7545788825734810914.md', '视频以博弈论中的“零和博弈”为切入点，探讨了其在现代社会中的局限性与危险性。零和博弈指双方收益总和恒为零，一方的收益必然意味着另一方的等量损失，这种模式假定资源总量不变，双方处于你死我活的掠夺状态。然而，现代社会的发展依赖于分工与合作，资源是可以通过协作实现增值与共赢的。因此，零和博弈在绝大多数情况下都不应发生，一旦有人采用这种逻辑，其本质目的往往是为了彻底消灭对手。视频中还指出，日常生活中很多人陷入“他人所得即己所失”的错误认知，这种封闭思维违背了经济学常识。最终，视频落脚于宏观视野，指出杜绝零和博弈正是构建人类命运共同体的基本前提。', '["零和博弈的核心特征是双方收益总和恒为零，一方的收益必然意味着另一方的损失。", "零和博弈假定资源总量永不增加，双方处于你死我活的纯粹掠夺关系。", "现代社会的经济发展依赖于分工与合作，资源可以通过协作实现增值与共赢。", "陷入零和思维的人往往认为“他人所得即己所失”，这种认知违背了经济学常识。", "杜绝任何形式的零和博弈是构建人类命运共同体的基本前提。"]', '[{"topic": "非零和博弈", "why": "理解非零和博弈有助于打破资源固定的静态思维，认识到合作如何创造增量价值，从而在现代经济与社会交往中寻求共赢。", "direction": "建议阅读罗伯特·赖特的《非零和时代》，或学习博弈论中的“双赢”与“纳什均衡”概念。"}, {"topic": "比较优势与分工理论", "why": "视频提到分工合作能带来增值，深入探究该理论能从经济学底层逻辑解释为何合作优于对抗，如何通过专业化提升整体资源总量。", "direction": "建议阅读亚当·斯密的《国富论》中关于分工的论述，或学习大卫·李嘉图的“比较优势理论”。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114971, 1784119594, '120.0', '14.723769187927246', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7544677304275701032', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '聊一下记忆宫殿 #清华学霸 #记忆宫殿 #学习方法', '聊一下记忆宫殿 #清华学霸 #记忆宫殿 #学习方法', 1756632078, 'https://www.douyin.com/video/7544677304275701032', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/okW8FB12DQeBC0iEAMFDDn9FTBfdoEAQE7g1At~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=15SMt4cUPsS7Ld4%2FZiNepjwRoLs%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415394008CC31D479E9198B8F0F', 38176, 22185, 817, 4033, 'done', 0, 'data/text/7544677304275701032.txt', 'data/summaries/7544677304275701032.md', '本视频主要探讨了记忆宫殿记忆法及其关联的右脑开发陷阱。主讲人明确表示不推荐使用记忆宫殿，原因在于该方法对大脑的透支较强，且往往与伪科学右脑开发紧密相连。视频深入剖析了右脑开发的荒谬性，指出人类右脑的图像记忆优势仅存在于十二岁前的儿童期，成年后大脑功能会自然向左脑转移，且社会化程度越高左脑越发达。那些宣称通过开发右脑能提升记忆宫殿能力、实现量子波动速读的说法，实为源自日本的诈骗手段，毫无科学依据。主讲人强调，个别人记忆宫殿能力强是因为其本身基础记忆力好，而非得益于右脑开发。整体上，视频旨在打破记忆法相关的认知误区，提醒大众警惕伪科学陷阱。', '["记忆宫殿对大脑透支较强，不推荐作为常规学习方法。", "右脑开发是伪科学陷阱，人类右脑图像记忆优势仅在十二岁前的儿童期存在。", "成年人社会化程度越高，左脑越发达，成年后进行右脑开发毫无意义。", "记忆宫殿使用能力强源于本身基础记忆力好，与右脑开发完全无关。", "量子波动速读等概念源自日本某教授的诈骗手段，缺乏科学依据。"]', '[{"topic": "左右脑功能单侧化与年龄的关系", "why": "理解左右脑功能的真实差异及其随年龄演变的科学规律，有助于破除右脑神话，避免被伪科学课程误导。", "direction": "阅读认知神经科学相关书籍，如《认知神经科学》或查阅大脑功能偏侧化相关学术文献。"}, {"topic": "记忆的认知负荷与记忆策略的适用性", "why": "探究不同记忆方法在认知资源消耗与长期知识保持上的差异，能指导我们科学选择适合自身的学习策略。", "direction": "学习认知心理学中的工作记忆模型与精细复述概念，了解《认知天性》中的高效学习策略。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114981, 1784119644, '403.0', '8.36113715171814', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7543932826119949620', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '王阳明的贪嗔痴 #清华学霸 #王阳明 #贪嗔痴 #阳明心学', '王阳明的贪嗔痴 #清华学霸 #王阳明 #贪嗔痴 #阳明心学', 1756458739, 'https://www.douyin.com/video/7543932826119949620', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/owXBLIrjxw0ALqubULilBiWAeAvBSgcD5IfC2Q~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=cDNFkssnA1sKuazNo%2BKfo82DIlM%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714153942CFD606E46999CD83A5A4', 2477, 956, 42, 215, 'done', 0, 'data/text/7543932826119949620.txt', 'data/summaries/7543932826119949620.md', '视频探讨了王阳明心学语境下的贪嗔痴问题。虽然贪嗔痴本是佛教概念，但在阳明心学中，它们被视作蒙蔽人本真心智的私欲与杂念。王阳明认为，人心本具良知，无需外求，但往往被贪婪、嗔怒和无明所遮蔽。要破除这些心魔，并非依靠单纯的禁欲或逃避，而是要通过致良知的功夫，在日常生活的点滴中事上磨炼。当人能够时刻觉察自己的起心动念，做到知行合一时，贪嗔痴的迷雾便会自然消散，从而恢复内心的澄明与自由。', '["阳明心学将贪嗔痴视作遮蔽人本心良知的私欲与杂念。", "人的痛苦源于内心被外物牵绊产生执念，而非外物本身。", "破除贪嗔痴的核心方法是致良知，在起心动念时保持觉知。", "修行不能脱离现实，必须在具体的事务中事上磨炼，做到知行合一。"]', '[{"topic": "致良知", "why": "它是阳明心学的核心功夫，直接决定了如何剥离贪嗔痴等私欲以恢复本心。", "direction": "研读《传习录》，理解良知作为本体与功夫的双重含义。"}, {"topic": "事上磨炼", "why": "阳明心学区别于佛家枯坐禅修的关键，强调在现实入世中检验和提升心境。", "direction": "了解王阳明平定宁王之乱等生平事迹，结合知行合一概念探究其实践应用。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114997, 1784119748, '470.0', '4.301671028137207', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7543208274478353704', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '失眠怎么办。#清华学霸 #睡不着怎么办 #失眠 #神游', '失眠怎么办。#清华学霸 #睡不着怎么办 #失眠 #神游', 1756290044, 'https://www.douyin.com/video/7543208274478353704', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/os9YEbxrgMk9AQ2foiQt46FIAxAdDtftBYCCDv~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=5HKGQK7ZXl8jrGSZpSb2W3Mri9A%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141539454436E450E1404E89DB5F', 2652, 1111, 84, 346, 'done', 0, 'data/text/7543208274478353704.txt', 'data/summaries/7543208274478353704.md', '视频主要探讨了失眠的成因及应对策略。作者指出，多数失眠源于焦虑，包括对过去错误的不原谅和对未来不确定性的恐惧，这导致身体强制进入工作状态而无法放松。对此，需明白活在当下的意义，接纳不可改变的过去和无法预知的未来。针对焦虑型失眠，可通过觉察念头并与之告别的方法让身心统一于睡眠。对于因极度兴奋导致的失眠，作者提出“不在意”的心态，并分享了一种道家修行般的“神游”方法，即否认身体束缚、放飞精神、任由思绪自由流动。这种方法即便未入睡也能让人保持充沛能量。整体强调以接纳和放松的心态面对失眠。', '["失眠多源于对过去的纠结和对未来的焦虑，导致身体强制进入工作状态而拒绝休息。", "缓解焦虑型失眠需活在当下，接纳过去与未来，并通过觉察念头、与念头告别来清空大脑。", "面对兴奋型失眠应采取“不在意”的态度，不强迫入睡，也不起身做具体工作。", "“神游”法通过否认身体束缚、任由思绪自由不设限地流动，能达到类似睡眠的放松与恢复精力的效果。"]', '[{"topic": "正念觉察与念头剥离", "why": "视频中提到的“看见念头、描述它、和它说再见”是经典的正念技巧，能有效打破思维反刍。", "direction": "建议阅读《当下的力量》或了解正念冥想中的“标签化”技巧。"}, {"topic": "庄子哲学与“神游”境界", "why": "视频中提到的“神游”概念源自道家思想，体现了超越肉体束缚、精神自由流动的哲学观。", "direction": "建议阅读《庄子·逍遥游》及探讨道家内丹修行中的坐忘与心斋概念。"}, {"topic": "唤醒状态与交感神经系统", "why": "视频中提到的“兴奋型失眠”和“焦虑工作状态”在生理学上对应交感神经的过度活跃。", "direction": "建议了解自主神经系统的工作原理，以及如何通过激活副交感神经来促进睡眠。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115014, 1784119820, '296.0', '15.323472023010254', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7542076673639517474', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '基础差如何背单词 #清华学霸 #背单词 #备考 #学霸秘籍 #学习方法', '基础差如何背单词 #清华学霸 #背单词 #备考 #学霸秘籍 #学习方法', 1756026570, 'https://www.douyin.com/video/7542076673639517474', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oMOArtB8iy8HV1q4tevnABVA96UIIDBfg0WlXi~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=EEdEKG6p3LuzNmIUbfyVQwUVy%2FQ%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415394717D43242140CE272B327', 200634, 127343, 2168, 32950, 'done', 0, 'data/text/7542076673639517474.txt', 'data/summaries/7542076673639517474.md', '针对英语基础薄弱的学习者，背单词常常成为备考路上最大的拦路虎。本文结合学霸的实战经验分享，探讨了如何打破死记硬背的低效循环，建立科学的词汇记忆体系。文章指出，基础差的学习者不应盲目追求词汇量的瞬时扩张，而应从核心高频词入手，利用词根词缀与语境结合的方法理解记忆。同时，通过制定合理的复习计划并利用碎片化时间巩固，能够有效抵抗遗忘曲线。学习单词不仅是记忆符号，更是构建英语思维的基础。只要方法得当并坚持执行，基础薄弱者同样能实现词汇量的突破，为英语综合能力的提升打下坚实基石。', '["基础薄弱者应从核心高频词汇切入，避免盲目追求全面而陷入挫败感。", "结合词根词缀法理解构词逻辑，并将单词放入真实语境中记忆其用法。", "利用艾宾浩斯遗忘曲线规律，通过间隔重复和碎片化时间巩固记忆。", "将背单词转化为日常习惯，用长期的坚持战胜遗忘与学习瓶颈期。"]', '[{"topic": "艾宾浩斯遗忘曲线", "why": "理解遗忘规律是制定高效复习计划的理论基础，能有效对抗背单词过程中的高遗忘率问题。", "direction": "阅读《记忆心理学》相关章节，了解间隔重复效应，学习如何设计个人的词汇复习周期。"}, {"topic": "英语词根词缀学", "why": "掌握词根词缀能将机械记忆转化为逻辑推理，大幅降低生词记忆难度并提高猜词能力。", "direction": "学习《英语词汇的奥秘》等经典词根词缀书籍，系统掌握常见前缀、后缀和核心词根。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115032, 1784119881, '872.0', '16.291719913482666', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7541344707973598479', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '聊一聊自律 #清华学霸 #自律', '聊一聊自律 #清华学霸 #自律', 1755856148, 'https://www.douyin.com/video/7541344707973598479', 'https://p3-pc-sign.douyinpic.com/tos-cn-p-0015/ocgqDfkYAENDIRP55BogFBeoIG9DAyYLKAYANs~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=N%2FLmnHuPv06A9WhgASPjmZ7IfrM%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141539502A51C68230040CF36239', 6723, 3245, 111, 786, 'done', 0, 'data/text/7541344707973598479.txt', 'data/summaries/7541344707973598479.md', '这段视频以清华学霸的视角，深入剖析了自律的本质。演讲者认为自律并非值得推崇的美德，而是一种被迫的自我异化——将人变成工具，通过主体意识强制身体和潜意识服从。自律的核心方法是感觉隔离，即在做不想做的事情时，切断对情绪和感觉的反馈，让行动大于一切。演讲者指出，自律是非知行合一的状态，是扭曲的自我压迫。但长期坚持后，痛苦的对抗会因惯性而消失，转化为习惯。然而，过度自律可能成为心理焦虑的来源。最终，演讲者提出知行合一是更优的境界，但极难达到，因此自律可作为过渡手段使用。', '["自律的本质是自我异化，将人变成工具，用主体意识强制身体和潜意识服从", "自律的实践方法是感觉隔离，切断对情绪的反馈，让行动大于情绪", "自律是非知行合一的扭曲状态，是因不理解目标而被迫进行的自我压迫", "长期强迫自律会因身体惯性转化为习惯，痛苦消失，但可能成为心理焦虑的来源", "知行合一是更优的境界，但极难达到，自律可作为过渡手段"]', '[{"topic": "知行合一", "why": "王阳明哲学的核心概念，理解知与行的关系有助于区分真正的自觉行动与强迫性自律，是超越自律的更高境界", "direction": "阅读《传习录》或了解王阳明心学中关于知行合一的论述"}, {"topic": "自我异化", "why": "理解自我异化有助于认识自律的心理代价，避免过度自律导致自我奴役和心理焦虑", "direction": "了解马克思的异化理论或存在主义哲学中关于人的本质与异化的讨论"}, {"topic": "习惯形成与神经科学", "why": "理解大脑如何通过惯性形成习惯，有助于科学地实现从痛苦自律到自动化行为的转化", "direction": "阅读《习惯的力量》或了解基底神经节在习惯形成中的神经科学机制"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115062, 1784120008, '314.0', '14.310508728027344', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7540563074673462568', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何理解完美主义 #清华学霸 #完美主义 #学习状态', '如何理解完美主义 #清华学霸 #完美主义 #学习状态', 1755674159, 'https://www.douyin.com/video/7540563074673462568', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o4ZkIaQiaPTP8B1RLW1jtAIclzKBIwVqAdiKn~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=9Mbs7wvnt%2B5e4iLKozWQ8bRlgBU%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714153952BBC9EDB102131402E805', 5812, 2681, 89, 595, 'done', 0, 'data/text/7540563074673462568.txt', 'data/summaries/7540563074673462568.md', '这段视频深入探讨了完美主义的本质及其正确应用场景。核心论点指出，完美主义本身并非缺陷，而是一种被颠倒使用的优秀品质。在事物已经完成后，完美主义能驱使人们不断对客观结果进行拆解和修正，使其更趋完善；然而，在从零开始创造尚未存在的事物时，完美主义却会让人陷入头脑中无休止的修正，因缺乏实际客体而导致行动力瘫痪。因此，真正的执行力需要反转驱动方式，由手开始，在模糊中行动并逐步生成客观事物，待事物成型后再用完美主义进行优化。理解这一先后关系，是打破行动困境、释放创造力的关键。', '["完美主义适合用于事后修正，是驱使已完成事物不断完善的核心驱动力。", "在从零开始创造新事物时，完美主义会因缺乏客体而导致行动力瘫痪。", "真正的执行力要求从手开始，关注事物当下的客观形态并逐步改变。", "完美主义本身是一种被颠倒的优秀品质，需要配合先行动的逻辑才能发挥价值。"]', '[{"topic": "行动力与构思的先后关系", "why": "理解构思与行动的先后顺序能帮助克服拖延和行动瘫痪，将完美主义用在正确的阶段，从而提高执行力。", "direction": "阅读《精益创业》中的MVP（最小可行性产品）概念，学习如何快速试错与迭代。"}, {"topic": "主观思虑与客观客体的脱节", "why": "深入探究能明白为何在缺乏实际客体时过度思考会产生焦虑、内耗和停滞，有助于调整认知模式。", "direction": "了解认知行为疗法（CBT）中关于“过度思虑”的应对策略，或学习存在主义哲学中关于行动先于本质的论述。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115075, 1784120097, '126.0', '12.08400297164917', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7539502052696821027', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '学习的本质：重复性法则 #清华学霸 #重复性法则 #学习方法', '学习的本质：重复性法则 #清华学霸 #重复性法则 #学习方法', 1755427121, 'https://www.douyin.com/video/7539502052696821027', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oY8pKPwv11hAihKG1IwBaATPQH0IIndBisAJG~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=Opl%2BtwBzE%2BeHkdyQ23qjdRgX4I4%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141539548CFE617DE118B91C9CFC', 14693, 8562, 240, 2006, 'new', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7538726842061180194', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '复活一下林老师曾经讲的历史学科系统 #学习 #清华学霸 #历史学科', '复活一下林老师曾经讲的历史学科系统 #学习 #清华学霸 #历史学科', 1755247230, 'https://www.douyin.com/video/7538726842061180194', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oECEQ6LUK9GBzQHeBBGAQ9Pf7sRA8C0B7dI3es~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=iZbmhZbRN9ezma%2B%2BkPMF%2FFtEiBc%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714153957E8F45227339EA20A3CC3', 982, 520, 27, 144, 'done', 0, 'data/text/7538726842061180194.txt', 'data/summaries/7538726842061180194.md', '这段视频主要讲述了高中历史学科的底层学习逻辑与解题系统。主讲人首先以“根本本质类题型”为例，揭示了唯物史观中“经济大于政治大于文化大于具体事件”的层级排序原则，并进一步细化了经济内部生产力、生产关系与具体经济现象的优先级。随后，视频升华了主题，指出高中历史的本质是“学术语言系统下的知识结构”。学生应当通过拆解句型、积累学术词汇内涵，运用逻辑推导和理性思维来排除错误选项，而非依赖“语感”或感悟式做题。掌握了这套语言系统拆解能力后，无论是选择题还是大题，都能拨开迷雾，实现成绩的突破。', '["解答“根本本质类”历史试题需遵循唯物史观中“经济>政治>文化>具体事件”的逻辑层级。", "在复杂情境下，需进一步区分内部层级，如经济层面的“生产力>生产关系>具体经济现象”。", "高中历史的本质是学术语言系统下的知识结构，需通过拆解句型和积累词汇内涵来掌握。", "历史大题的底层逻辑与选择题一致，但在语言推导的基础上增加了材料转述能力的考查。", "掌握语言系统拆解能力后，可用理性思维替代感悟式做题，实现成绩突破。"]', '[{"topic": "唯物史观与社会发展阶段论", "why": "视频中提到的“经济>政治>文化”逻辑层级是唯物史观的核心应用，深入理解其哲学基础有助于在复杂情境中灵活运用。", "direction": "建议阅读马克思《政治经济学批判》序言，或学习高中政治哲学部分的唯物史观内容。"}, {"topic": "学术语言系统的拆解方法", "why": "历史学科考查的不仅是史实，更是学术表达能力，掌握句型拆解是应对高考材料题的关键技能。", "direction": "学习史料学基础或学术写作规范，尝试在日常练习中对历史材料进行主谓宾拆解与核心词提取。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115094, 1784120248, '372.0', '7.891839265823364', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7537993301702610210', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '看透名利权的杨朱 #清华学霸 #中国哲学 #杨朱 #贵己', '看透名利权的杨朱 #清华学霸 #中国哲学 #杨朱 #贵己', 1755075837, 'https://www.douyin.com/video/7537993301702610210', 'https://p3-pc-sign.douyinpic.com/tos-cn-p-0015/o8SEqV5RIreADlnBVcQDfAa9QJAFBRFgROYoIr~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=scWayzbtJlXAd1tiTkxUsBCkYPg%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415395952CEA71BAD6D2806ACAC', 1849, 666, 85, 162, 'done', 0, 'data/text/7537993301702610210.txt', 'data/summaries/7537993301702610210.md', '本视频讲述了中国古代哲学家杨朱的思想及其历史命运。杨朱核心主张是“贵己”与“全性保真”，强调重视个体生命本真的快乐，反对在名利权中过度迷失自我。他批评当时君王为彰显身份而沉迷山珍海味、声色犬马，认为这会使人丧失天性。杨朱的“不损一毫以利天下”被孟子简化为“一毛不拔”并长期抹黑，其实质是倡导一种不被外物裹挟的平静生活方式。由于过于强调个体感受，杨朱思想遭到儒、法、墨多家攻击，最终未能成为显学，却在后世融入道家，并暗中被历代君王作为个人修持之学。视频认为杨朱思想具有超前性，若得以延续，可能推动社会走向更具个体自由的发展方向，堪称中国哲学史上的一大遗憾。', '["杨朱的核心思想是“贵己”与“全性保真”，强调重视生命本真的快乐，而非追逐名利权", "“一毛不拔”被孟子断章取义地抹黑，杨朱原意是不为外物过度牺牲自身天性", "杨朱批评君王为身份地位而消费山珍海味，认为这丧失了生命的本真快乐", "杨朱追求赏雪、散步、读书、交谈等平静的生活方式，被儒法墨三家攻击为失礼失法", "杨朱思想因过于超前而与战国时代脱节，成为君王暗中的修持之学，后融入道家"]', '[{"topic": "杨朱与先秦诸子的思想论争", "why": "杨朱被孟子批评“一毛不拔”，同时被墨家攻击为利己主义，了解这场论争能帮助我们理解先秦哲学中个体与群体的核心张力。", "direction": "建议阅读《孟子·尽心中》关于杨墨的论述，以及《列子·杨朱篇》，对比不同学派对杨朱的记载与评价。"}, {"topic": "全性保真与道家修养传统的融合", "why": "杨朱思想后来融入道教传统，成为道家养生与修心理论的源头之一，揭示了中国哲学中个体修养思想的演变脉络。", "direction": "可研究《庄子》中关于“保身”“全生”的论述，以及道教内丹学中“全真”概念的思想渊源。"}, {"topic": "先秦个体主义思想与现代性的关联", "why": "杨朱强调个体感受和主体性自由，与西方近代以来的个体权利思想有对话空间，探讨这一关联有助于重新评估中国传统的多元性。", "direction": "可对比研究杨朱与古希腊伊壁鸠鲁学派的快乐论，或阅读以赛亚·伯林关于消极自由与积极自由的论述。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115113, 1784120292, '636.0', '17.475158214569092', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7534262261532200232', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '聊一下心流 #清华学霸 #心流 #暑假生长计划#抖音校园', '聊一下心流 #清华学霸 #心流 #暑假生长计划#抖音校园', 1754644800, 'https://www.douyin.com/video/7534262261532200232', 'https://p3-pc-sign.douyinpic.com/tos-cn-p-0015/oQZPIYYHAXE7AQm8ReQGCNLmBfBPaieECXBuG7~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=1QFSWSzj2KNFNdEXGCmrey%2F7iZY%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415400103E5E9CEE0C4A380B840', 8989, 4112, 137, 837, 'done', 0, 'data/text/7534262261532200232.txt', 'data/summaries/7534262261532200232.md', '该视频主要探讨了“心流”这一高效学习与工作的理想状态，并剖析了其本质与实现条件。心流不仅是一种高度专注、高效且伴随强烈正反馈的体验，其本质更是时间维度与自我维度的高度统一，即过去、现在与未来的自我全然聚焦于当下的单一目标。视频中指出，人们平时难以专注的原因在于大脑思绪混乱，常常受困于过去的自我怀疑与未来的目标焦虑，从而削弱了当下的行动力。要进入心流状态，核心要求在于回归此时此刻，并将全部精力倾注于一件事情上，拒绝三心二意。视频最后留下了如何做到专注不二的思考，引导观众进一步探索专注力的培养方法。', '["心流是一种高度专注、高效且伴随强烈正反馈的学习与工作状态。", "心流的本质是时间与自我的双重统一，要求将全部精力投入当下的单一目标。", "难以专注的原因在于大脑思绪混乱，常受困于过去的自我怀疑与未来的目标焦虑。", "进入心流的核心要求是锚定此时此刻，并做到绝不三心二意。"]', '[{"topic": "米哈里·契克森米哈赖的心流理论", "why": "视频提及了心流的状态，但系统了解心流需要追溯其心理学源头，掌握触发心流的清晰条件与系统模型。", "direction": "阅读米哈里的著作《心流：最优体验心理学》"}, {"topic": "正念与当下觉察", "why": "视频中强调心流的第一个要求是此时此刻，这与正念疗法中“不带评判地关注当下”的核心概念高度重合，是克服思绪游走的实操方法。", "direction": "学习正念减压疗法（MBSR）的基础概念或阅读《正念的奇迹》"}, {"topic": "认知负荷理论与多任务处理", "why": "视频指出不能三心二意，从认知科学角度理解为何大脑无法同时处理复杂信息，有助于建立科学的单任务专注机制。", "direction": "了解认知心理学中的“认知负荷理论”及注意力残留效应"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115123, 1784120353, '511.0', '9.361786842346191', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7534261253972282624', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '天赋 #清华学霸 #天赋#暑假生长计划#抖音校园', '天赋 #清华学霸 #天赋#暑假生长计划#抖音校园', 1754559000, 'https://www.douyin.com/video/7534261253972282624', 'https://p3-pc-sign.douyinpic.com/tos-cn-p-0015/oElBXfRQPTYDPC2EAdashfEAFBA7qBHpwivbfQ~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=0cXIPBT435Rs0NMX83YSHDCLU6o%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714154004DE92239A01070508A9B6', 33718, 13073, 459, 3747, 'summarize_failed', 1, 'data/text/7534261253972282624.txt', NULL, NULL, NULL, NULL, NULL, NULL, 1784032681, 1784115129, NULL, '466.0', '5.386702060699463', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7534586282454830370', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何制定暑期计划 #清华学霸 #暑假生长计划 #制定计划 #学习规划#抖音校园', '如何制定暑期计划 #清华学霸 #暑假生长计划 #制定计划 #学习规划#抖音校园', 1754299800, 'https://www.douyin.com/video/7534586282454830370', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oMACgLrLJIJOGdSf7ecCHlBsAaIfBc8gQRWhgI~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=cnr3P5ocy%2F6Dksh83jD4uMnulko%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141540065BC30A603ADF3298A6EA', 8819, 5094, 183, 1346, 'new', 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7533563101447785728', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '简单聊一下中庸 #中国哲学 #中庸', '简单聊一下中庸 #中国哲学 #中庸', 1754044347, 'https://www.douyin.com/video/7533563101447785728', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oMBtX0QGBBPiM9MyM1vlWIAAIIa7WWixSw2NI~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=%2BwqZUwa50WfRLNJap7l%2FTyyQj84%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141540094BB2925F6C2F6707FF1F', 873, 288, 36, 71, 'done', 0, 'data/text/7533563101447785728.txt', 'data/summaries/7533563101447785728.md', '本视频深入浅出地讲解了儒家核心概念“中庸”的内涵及其在现代生活中的应用价值。中庸并非简单的折中主义，而是要求人们在不偏不倚的状态下踏实做事，与天地运行规律达成共振。视频指出，人们在学习和生活中常陷入“零一逻辑”的认知陷阱，即非黑即白、追求绝对完美。然而现实事物多处于从零到一的动态发展过程中，很难找到绝对的完美状态。以“快速读书法”为例，该方法虽以牺牲文学韵味为代价，却满足了特定人群快速积累知识的实用需求，体现了现实中权衡取舍的动态平衡。通过中庸的智慧，我们能够跳出二元对立的思维局限，在动态发展与不完美中寻找最适合当下的实践路径。', '["中庸并非折中妥协，而是不偏不倚地做事并维持状态，与天地运行规律达成共振。", "人们在认知中常陷入非黑即白的“零一逻辑”，忽略了现实事物是从零到一动态发展的过程。", "现实中不存在绝对的完美，快速读书虽有损韵味但能满足特定实用需求，体现了实践的权衡取舍。", "运用中庸智慧能够帮助人们跳出二元对立的思维局限，在动态发展中寻找最合适的平衡点。"]', '[{"topic": "朱熹与汉儒对《中庸》的注解差异", "why": "了解宋代理学与汉代经学在解释儒家经典时的不同视角，有助于更全面地理解“庸”字从平常心到实干的内涵演变。", "direction": "阅读朱熹《中庸章句》及郑玄《礼记注》，对比不同时代对“庸”字的具体注释及其哲学偏向。"}, {"topic": "二元对立思维与实用主义哲学", "why": "探究人类为何容易陷入“零一逻辑”的认知陷阱，以及实用主义哲学如何指导我们在现实中做出权衡取舍。", "direction": "了解威廉·詹姆斯的实用主义哲学思想，或学习认知行为疗法中关于“认知扭曲”与“非黑即白”思维的心理机制。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115174, 1784120563, '235.0', '33.51743292808533', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7532808209103588623', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '为什么不能容忍马虎 #清华学霸 #学习习惯#注意力不集中 #马虎', '为什么不能容忍马虎 #清华学霸 #学习习惯#注意力不集中 #马虎', 1753868585, 'https://www.douyin.com/video/7532808209103588623', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ok7J8XhEew7dCQ2QRCFRA6mDAAGFFBzSfeEBbi~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=VB3Gm4s1f6klMwvF6Fbm0UoySPw%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714155200120161E99AEC000354F1', 62975, 44982, 1784, 32997, 'done', 0, 'data/text/7532808209103588623.txt', 'data/summaries/7532808209103588623.md', '视频从应试教育对马虎的零容忍态度切入，指出中考本质上是一场筛选马虎学生的考试。核心论点是：马虎并非粗心大意这么简单，其本质是思维连贯性不足。当一个人明明会做某道题却做错时，说明他在解题过程中没有形成完整的逻辑链条。如果思维在每一个瞬间都能清晰浮现，就不会出现任何错误。这一观点将马虎从态度问题重新定义为思维能力问题，为理解学习中的粗心现象提供了更深层的认知视角，也暗示了提升思维连贯性是克服马虎的关键路径。', '["中考本质上是筛选马虎学生的考试，应试教育对马虎零容忍", "马虎的本质是思维连贯性不够，而非简单的粗心态度问题", "明明会做却做错，说明解题时没有形成完整的逻辑链条", "若思维每个瞬间都能清晰浮现，就不会出现任何错误"]', '[{"topic": "工作记忆与思维连贯性", "why": "马虎的本质是思维链条断裂，这直接关联到工作记忆容量和注意力分配的认知机制，理解它能从根源上改善学习效率", "direction": "阅读认知心理学相关书籍，重点学习工作记忆模型（如Baddeley的多成分模型）和注意力控制理论"}, {"topic": "元认知监控", "why": "思维每个瞬间都能浮现实际上是一种元认知监控能力，即对自身思维过程的觉察与调节，这是克服马虎的核心心理机制", "direction": "学习元认知理论，可阅读《认知天性》中关于自我检测和反思实践的章节"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115194, 1784120641, '400.0', '6.574254035949707', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7531697127305039156', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何与自己的身体相处 #清华学霸 #爱自己 #调整状态 #精力管理', '如何与自己的身体相处 #清华学霸 #爱自己 #调整状态 #精力管理', 1753609894, 'https://www.douyin.com/video/7531697127305039156', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oIQjLRRBhCfMeA75r3QAcFEBW7DT7CCY1fA6XG~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=ywzg1NczM%2FY5j%2FKIDdAgDpy4fko%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714155203C751DA57A5FA4A0227FF', 15328, 6716, 216, 2344, 'done', 0, 'data/text/7531697127305039156.txt', 'data/summaries/7531697127305039156.md', '视频探讨了人与身体之间应建立的伙伴关系，而非单向的控制关系。核心观点是：身体不是意志的附属品，而是一个需要被倾听、被尊重的伙伴。当头脑与身体通过协调而非胁迫来互动时，身体会给出及时反馈，避免疾病积压，同时带来更高的满足感。爱自己既是爱身体也是爱灵魂，需要摆脱外在要求的禁锢。在制定计划时，应将休息、睡眠、饮食等基本需求纳入考量，寻找并满足内心深处未被满足的欲望。作者以动物为例，强调欲望的满足应当短平快，不压抑、不扭曲。当感到压抑时，应回归更基础的生活状态，用简单的行动填补内心空缺。最终提醒人们不要用精神强迫身体，因为每一次强迫都伴随隐性代价。', '["人与身体应建立伙伴关系而非控制关系，通过协调让身体及时反馈，避免疾病积压。", "爱自己既是爱身体也是爱灵魂，需要摆脱外在要求的禁锢，关注真实需求。", "制定计划时必须将睡眠、饮食、休息等基本生理需求纳入考量，而非一味压制。", "欲望的满足应短平快，像动物一样不压抑不扭曲，用简单行动填补内心空缺。", "精神不可强行战胜身体，每一次用意志强迫身体都伴随隐性代价。"]', '[{"topic": "身心关系与具身认知", "why": "视频涉及身体与意识的伙伴关系，触及了哲学和认知科学中关于身心一体的核心命题，理解这一点有助于打破身心二元的思维误区。", "direction": "建议阅读梅洛-庞蒂的《知觉现象学》或了解具身认知理论，深入探究身体如何参与塑造我们的思维与情感。"}, {"topic": "精力管理与身体反馈机制", "why": "视频强调制定计划需考虑身体休息，这直接关联到精力管理这一实用方法论，理解身体反馈机制有助于科学调节状态。", "direction": "建议阅读吉姆·洛尔的《精力管理》一书，学习如何从体能、情感、思维、意志四个维度系统化管理个人精力。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115205, 1784120698, '564.0', '10.245963096618652', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7530939885575752995', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '聊一聊尖子生 #清华学霸#内容太过真实 #优等生 #学习习惯', '聊一聊尖子生 #清华学霸#内容太过真实 #优等生 #学习习惯', 1753433584, 'https://www.douyin.com/video/7530939885575752995', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ooSIGIRrAAYGBRgT7W8NoRMCb6BneQBfgteFAD~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=3YskyeLiG%2FUhYth1rLJ6lEmnbAE%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141552053746A603FD4DDE9CBF70', 51553, 30228, 842, 9298, 'done', 0, 'data/text/7530939885575752995.txt', 'data/summaries/7530939885575752995.md', '视频深刻剖析了尖子生思维的底层逻辑与行为模式。尖子生将学习视为残酷的战争，根本目的在于取得成绩并淘汰他人，而非单纯获取知识。为实现这一目标，他们对外极致抢占学习资源，对内实行精密的精力管理，通过舍弃社交与娱乐，将自身高度异化为学习机器。然而，这种模式需要极强的内驱力作为支撑，并非通过外部管教就能达成。视频提醒普通学生与家长，冲击顶尖名校需反推自身精力管理与学科把握是否极致，并呼吁家长理性看待差距，不要盲目逼迫孩子追求前百分之一的极致目标，因为很多时候人们严重低估了这之间的遥远距离。', '["尖子生思维的底层逻辑是对精力和资源的极度规划，目的是在有限时间内达到最高结果。", "尖子生将学习定义为残酷的战争，根本目的是取得成绩并淘汰他人，而非单纯获取知识。", "尖子生通过极致的计划、执行、回馈循环和舍弃社交娱乐来实现目标，呈现高度自我异化。", "冲击顶尖名校需要极其强大的内驱力，不是外部管教能逼迫出来的。", "家长往往严重低估了普通水平与顶尖水平之间的真实差距，不应盲目让孩子追求前百分之一。"]', '[{"topic": "自我异化", "why": "尖子生在追求极致效率的过程中将自身工具化，了解这一概念有助于审视过度目标导向对个体心理和情感连接的潜在破坏。", "direction": "建议阅读马克思的异化理论相关著作，或心理学中关于过度竞争与情感抽离的研究。"}, {"topic": "精力与资源管理闭环", "why": "尖子生的高效不仅源于努力，更源于精密的计划、执行与反馈系统，这套方法论具有普适性的迁移价值。", "direction": "可以阅读《精力管理》或《掌控习惯》，学习如何建立科学的个人闭环反馈系统。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115224, 1784120754, '756.0', '16.747217893600464', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7529077207374236963', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '考试如何不紧张 #清华学霸 #学习方法 #紧张 #考试紧张', '考试如何不紧张 #清华学霸 #学习方法 #紧张 #考试紧张', 1752999897, 'https://www.douyin.com/video/7529077207374236963', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ocEmATReELTQeDUCQhIG1eeIQVi6A6rHCM5TX2~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=IkFsVtJzeyXwINlT8gPevpb18Kk%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714155210B79AEEB045B119FF2832', 3903, 2024, 87, 484, 'done', 0, 'data/text/7529077207374236963.txt', 'data/summaries/7529077207374236963.md', '本视频探讨了考试紧张的根本原因及应对策略。作者指出，人受两种力量驱动：内在的自我膨胀与外在的规则规训。考试紧张源于外界压力过大而自我力量不足。作者提供了一个全新的认知视角：学习是向内吸收力量的过程，而考试则是这一吸收过程终止的时刻。在考场上，外界不再提供能量，压力随之失去意义，此时只需自我对外界进行单纯的改造。若难以立刻转变心态，可通过行为矫正法，如考前设定仪式性动作或心理暗示来切换状态，重获自我掌控感，从而从容应考。', '["考试紧张的根本原因是外界规训的压力超过了自我扩张的力量。", "考试是学习吸收过程的终止，此刻外界不再提供能量，压力失去意义。", "考场上唯一有意义的力量是自我对外界（试卷）的单纯改造。", "可通过考前仪式性动作或心理暗示等行为矫正法，切换状态并重获掌控感。"]', '[{"topic": "内驱力与外驱力的博弈机制", "why": "理解个人行为动力源头的博弈，有助于在压力情境下识别自我力量的消长，从而进行有效干预。", "direction": "建议阅读心理学书籍《内在动机》或了解自我决定理论"}, {"topic": "行为矫正与心理暗示技术", "why": "认知层面的觉醒难以瞬间改变长期的情绪习惯，需要借助具体的行为技术来实现状态切换。", "direction": "学习行为心理学中的经典条件反射应用，或了解NLP（神经语言程序学）中的心锚技术"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115262, 1784120939, '382.0', '13.024802923202515', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7528359164185464079', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何打破信息茧房 #清华学霸 #信息茧房 #认知差 #认知破局', '如何打破信息茧房 #清华学霸 #信息茧房 #认知差 #认知破局', 1752832715, 'https://www.douyin.com/video/7528359164185464079', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oI6QgPBBZI0SiZazoDfBeQ25tx65GQATAiAMBI~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=9kXQIOs3Ey0vjc68cIRblKQj3xQ%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714155212842A082FCCB6CF0D6C71', 26495, 12555, 542, 4593, 'done', 0, 'data/text/7528359164185464079.txt', 'data/summaries/7528359164185464079.md', '本期视频探讨了信息茧房的本质及打破它的实用方法。信息茧房并非不可逾越，它其实是对个人现有认知甚至愚蠢的保护机制，通过不停迎合喜好来排斥外在知识攻击。要突破这一困境，核心在于重塑主体性与运用辩证思维。具体方法包括：遇到认知冲突时进行多源检索与反向搜索，以打破算法标签；主动接触带来不适感与痛点的信息，将其视为认知扩展的契机；学会“摘帽子”去标签，跳出固有身份局限，从更宏观的经济、社会结构审视问题；最后，理性剖析信息背后的目的，识别情绪照顾与认知攻击的真实逻辑。通过不断的自我否定与辩证成长，实现认知层级的跃升，最终让信息茧房失去束缚力。', '["信息茧房的本质是对个人现有认知和立场的保护，使人排斥异己观点。", "遇到认知冲突时应进行多源检索与反向搜索，以打破算法的喜好排序。", "学会“去标签化”，跳出固有身份局限，从宏观结构角度审视问题。", "理性剖析信息背后的目的，识别情绪照顾与认知攻击的真实逻辑。", "拥抱带来不适感和痛点的信息，通过否定之否定实现认知扩展。"]', '[{"topic": "信息茧房与算法推荐机制", "why": "了解算法如何通过标签和喜好排序构建信息壁垒，是突破茧房的技术前提。", "direction": "阅读《信息乌托邦》或学习计算广告学与推荐系统基础概念。"}, {"topic": "辩证否定与认知重构", "why": "视频提到的“否定之否定”是黑格尔辩证法的核心，掌握它能实现深层次的思维跃升。", "direction": "学习黑格尔的辩证法思想及马克思主义哲学中的否定之否定规律。"}, {"topic": "媒介素养与信息意图分析", "why": "在信息时代，识别信息背后的情绪操纵与利益变现逻辑是必备的生存技能。", "direction": "阅读尼尔·波兹曼的《娱乐至死》或学习媒介素养相关课程。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115282, 1784121002, '538.0', '18.893543004989624', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7526426899096112419', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '费曼学习法 #清华学霸#学习方法 #费曼学习法 #记忆力', '费曼学习法 #清华学霸#学习方法 #费曼学习法 #记忆力', 1752382826, 'https://www.douyin.com/video/7526426899096112419', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oE8fMhVABECQ6iA3yeM4GQgt5giZ1e7InWgBnp~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=Qm3TarXifKewDEysbJray7HquCI%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714155215CAD838C629195BFE50B0', 14314, 8548, 145, 1666, 'done', 0, 'data/text/7526426899096112419.txt', 'data/summaries/7526426899096112419.md', '本视频围绕费曼学习法展开，首先引入了信息循环这一前提逻辑，指出学习如同做事，不应一开始就预设过于完美的目标，而应通过行动中的反复调整来逐步达成。在此基础上，视频详细拆解了费曼学习法的三个核心步骤：学习知识点、讲解知识点、在讲解中发现盲点后重新学习。费曼学习法的优势在于通过输出倒逼输入，帮助学习者在大脑中构建系统化的知识结构；讲解本身就是知识的应用与实践；而大量举例的过程则能拓展思维边界，形成立体理解。此外，通过自我讲解或向他人讲解并接受质疑，可以验证知识体系的合理性，最终实现活学活用。', '["学习不应预设完美目标，而应通过行动中的反复调整逐步达成，这是信息循环的核心逻辑", "费曼学习法包含三个步骤：学习知识点、讲解知识点、发现盲点后重新学习", "讲解的过程能在大脑中重新生成知识结构，比反复阅读书本更高效", "讲解本身是知识的应用与实践，需要大量举例来拓展思维边界", "通过自我讲解和向他人讲解接受质疑，形成双重验证闭环"]', '[{"topic": "信息加工深度理论", "why": "费曼学习法中讲解输出能加深记忆的本质原因，可以用认知心理学中的信息加工深度理论来解释——深度加工的信息比浅层重复的信息更容易被长期保留。", "direction": "阅读《认知天性》或学习 Craik & Lockhart 的深度加工理论，理解不同记忆编码方式的差异。"}, {"topic": "输出驱动的学习模型", "why": "费曼学习法强调以讲促学，这与教育心理学中输出导向学习的研究相关，探讨为什么教别人比自己学更有效。", "direction": "了解 protégé effect（门生效应）相关研究，或阅读《让大脑自由》中关于输出与记忆关系的章节。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115301, 1784121029, '251.0', '17.564019918441772', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7525752081875209524', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何提高大脑转速和学习强度 #清华学霸 #学习方法 #专注力练习 #高效学习', '如何提高大脑转速和学习强度 #清华学霸 #学习方法 #专注力练习 #高效学习', 1752225705, 'https://www.douyin.com/video/7525752081875209524', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o4BaGBu87QQ2pGBnCeMwe1XaZ7z4AALIfd1nIB~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=6ViIASn0qkEaTyeTuMkGEaAgNQU%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071415521781617BB25674DA1A5FFA', 137881, 94115, 2738, 17669, 'done', 0, 'data/text/7525752081875209524.txt', 'data/summaries/7525752081875209524.md', '视频主要探讨了如何通过后天训练提高大脑的运转速度和强度，指出这是优等生与普通学生之间的核心区别，而非天赋所致。在时间固定的情况下，增加学习内容是逼迫大脑变强、提升运转速度的根本途径。具体而言，增加学习内容分为两种类型：一是提升学习强度，即在单位时间内增加信息处理密度和任务量，逼迫大脑适应高负荷运转；二是增加知识深度，不只停留在表面记忆，而是深挖原理、联系和应用，构建系统化的知识网络。通过这两种维度的持续训练，大脑能够突破原有的运转瓶颈，实现学习效率和思维速度的质的飞跃。文章据此进行了逻辑拆解与深度延展。', '["大脑转速并非天赋，而是可以通过后天有针对性的训练来提高的。", "在时间固定的情况下，增加学习内容是逼迫大脑变强、提升运转速度的根本途径。", "提升学习强度，即在单位时间内提高信息处理密度和任务完成率，能直接锻炼大脑反应速度。", "增加知识深度，深挖知识点背后的原理与联系，能构建知识网络，提升大脑逻辑推理能力。"]', '[{"topic": "认知负荷理论", "why": "该理论探讨了人类认知资源在处理信息时的分配机制，理解它能帮助科学合理地安排学习强度，避免大脑过载并实现效率最大化。", "direction": "建议阅读约翰·斯维勒的相关论文或了解认知负荷理论的基础模型，学习如何优化信息输入。"}, {"topic": "神经可塑性", "why": "它解释了大脑如何通过后天的训练和环境的刺激在结构和功能上发生改变，是“大脑强度可训练”的科学依据。", "direction": "学习神经科学基础，了解大脑突触可塑性的机制，可阅读《运动改造大脑》或相关神经科学教材。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115343, 1784121146, '397.0', '28.795017957687378', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7523866284989025551', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何保持学习动力2（实践版）#清华学霸#学习动力 #学习方法', '如何保持学习动力2（实践版）#清华学霸#学习动力 #学习方法', 1751786635, 'https://www.douyin.com/video/7523866284989025551', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oMRU7QHJ1DbIBSjfBAQTltReDeuArLQGCwGCOE~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=nznWGI90dH8sUtkTxn8kpk1wQ3E%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141552205E0A09C7C6436C7B8B85', 24341, 13522, 208, 3003, 'done', 0, 'data/text/7523866284989025551.txt', 'data/summaries/7523866284989025551.md', '视频探讨了如何持续保持学习动力，核心论点是：学习动力来源于自我认知与理想目标之间的差距，由自我提高的激情和环境压力共同驱动。当目标过于遥远时，人无法感知进步，容易陷入自我否定，压力也会转化为负能量。解决方法是制定详细具体的计划，让自己随时能判断是否在成长，从而维持自我提高的正向反馈。同时，要与同学、朋友保持沟通，从环境中获得认同与激励，避免封闭孤立。两者结合——有事可循、有人可参照——学习动力便能持续。', '["学习动力源于当前自我认知与理想目标之间的差距，由自我提高的激情和环境压力共同驱动", "目标过于遥远会导致无法感知进步，进而引发自我否定，使压力从动力变为负能量", "制定详细具体的计划是维持自我提高正向反馈的关键，每完成一步都能确认自己在成长", "与同学朋友保持沟通和联系，从环境中获取认同与激励，避免封闭孤立", "计划（事）加上人际参照（人）共同构成持续学习动力的双重支柱"]', '[{"topic": "目标设定理论", "why": "视频中提到的远大目标导致动力丧失，本质上涉及目标距离与反馈频率之间的关系，理解目标设定理论有助于科学拆解目标。", "direction": "阅读 Locke & Latham 的目标设定理论，重点学习「近端目标」与「远端目标」的区分及其对动机的影响"}, {"topic": "自我效能感", "why": "视频强调通过完成具体计划来确认自我提高，这与班杜拉提出的自我效能感概念高度相关，是维持内在动力的心理学基础。", "direction": "学习 Bandura 的自我效能感理论，关注「掌握经验」如何提升效能感并形成正向循环"}, {"topic": "社会比较理论", "why": "视频中提到从他人身上获取认同和参照，涉及社会比较对自我认知和动机的影响，理解这一点能帮助合理利用环境因素。", "direction": "阅读 Festinger 的社会比较理论，探索如何将向上比较和向下比较转化为正向激励"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115367, 1784121297, '406.0', '13.889558792114258', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7523175777429622068', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '庄子的逍遥与坐忘 #清华学霸 #庄子 #逍遥', '庄子的逍遥与坐忘 #清华学霸 #庄子 #逍遥', 1751625861, 'https://www.douyin.com/video/7523175777429622068', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/okF9R5eoZAAwAgQCE3U6T9YBDbPfQIJAArGgQD~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=J89iAy3%2BYLHHR%2FBdJH6fMjKwew0%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714155222DCB0198B53F0E30ADE4E', 992, 323, 80, 76, 'done', 0, 'data/text/7523175777429622068.txt', 'data/summaries/7523175777429622068.md', '该视频主要探讨了庄子“逍遥”思想的哲学基础。通过溯源老子的道家理念，指出万事万物皆由“道”化生且本质同一。庄子据此提出“齐物”之论，主张在天地大道的宏大视角下，世人所执着的得失遭际犹如落叶归根般寻常与自然。这种破除分别心、将个体境遇置于宇宙大道中审视的思维方式，正是通往庄子所谓精神逍遥的必经之路。', '["庄子“逍遥”思想的哲学基础是道家的“齐物”理念。", "老子认为万物皆由“道”化生，故本质同一且无差别。", "在天地大道的视角下，个体的得失遭际犹如落叶般寻常自然。"]', '[{"topic": "齐物论", "why": "“齐物”是庄子哲学的核心，破除以人类自我为中心的偏见，是理解道家相对主义与逍遥境界的关键。", "direction": "阅读《庄子·内篇·齐物论》，研究其关于“天地与我并生，而万物与我为一”的论述。"}, {"topic": "老子之“道”", "why": "老子的“道生万物”是整个道家宇宙观的基础，为庄子等后学提供了形而上的逻辑起点。", "direction": "研读《道德经》中关于“道生一，一生二，二生三，三生万物”的章节，理解道的本源属性。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115375, 1784121368, '496.0', '6.849895000457764', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7521222128432221475', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '如何获得主体性 #清华老公 #主体性思维 #主体性', '如何获得主体性 #清华老公 #主体性思维 #主体性', 1751170993, 'https://www.douyin.com/video/7521222128432221475', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o8XBiB7QFA0vm5egIBj7ivd3DvMT0IAkZA3egq~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=RJKLsfBrv%2F9HQE9tUu%2BKqniUwfQ%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714155224641E3EA35E3562FC682C', 8194, 4238, 123, 1181, 'done', 0, 'data/text/7521222128432221475.txt', 'data/summaries/7521222128432221475.md', '本视频深入探讨了如何构建个人主体性的问题。主体性本质上是人与世界的关系，即马克思主义哲学中的主观能动性。当外界的规则与大他者过于强大且个体选择被动服从时，就会导致主体性缺失，表现为缺乏动力、逃避冲突甚至躺平。视频指出，主体性的建立必须通过斗争性来实现，即在与客观世界的阻力对抗中不断重新划定边界并达成新的妥协。在日常实践中，恢复主体性的有效途径是敢于表达愤怒与不满，拒绝自我归因，积极争取个人利益。然而，主体性也并非越多越好，主体性过剩会导致缺乏边界感、推卸责任和丧失反思能力。因此，理想的个体应通过恰当的斗争恢复生命动力，同时保持自我反思，找到与世界相处的合适边界。', '["主体性的本质是人与世界的关系，即人改造客观世界的主观能动性。", "主体性缺失源于外界规则与大他者的过度规训，导致个体丧失主导权而选择被动躺平。", "主体性的建立必须通过斗争性，在与客观世界的阻力对抗中重新划定边界并达成新规则。", "在日常生活中，敢于表达愤怒与不满、拒绝自我归因是恢复主体性的有效实践方法。", "主体性过剩会导致缺乏边界感和反思能力，需要在争取主导权与自我反思之间寻找平衡。"]', '[{"topic": "费希特的“ A与非A ”哲学理论", "why": "视频中提及该概念作为理解主体与客体关系的基础，深入探究有助于从哲学本源上理解自我与外部世界的对立与互动关系。", "direction": "建议阅读费希特的《全部知识学的基础》，了解其知识学体系中关于自我设定非我的哲学论述。"}, {"topic": "精神分析中的“大他者”概念", "why": "视频将社会规则比作大他者，它是导致主体性缺失的重要客体，理解这一概念有助于认清个体如何被社会符号秩序所规训。", "direction": "建议学习拉康的精神分析理论，特别是关于象征界与大他者欲望的哲学探讨。"}, {"topic": "马克思主义的主观能动性与斗争性", "why": "视频将主体性等同于主观能动性，并强调通过斗争改造世界，这是马克思实践观的核心体现，具有深刻的方法论意义。", "direction": "建议重温《关于费尔巴哈的提纲》，深入理解实践作为主体改造客体的对象性活动。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115408, 1784121507, '378.0', '17.125810861587524', 1784018346, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7520537155027881250', 'MS4wLjABAAAAxIFxCc7GbORVk16hLf77GZxEW4l7KseaCFKEPEcNOwXpPPtKt4kO2mMUjF44jOBf', '具体制定计划（实战版） #清华学霸 #学习方法 #制定计划 #学习规划', '具体制定计划（实战版） #清华学霸 #学习方法 #制定计划 #学习规划', 1751011524, 'https://www.douyin.com/video/7520537155027881250', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oQ3aUeeEJwQJvdNQAXCQ7UMFVfaD1gBGBDICAd~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785222000&x-signature=iqABYKJFGyaOLtViFjwdylgrqOQ%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141552275497A96B32B08F098F14', 86246, 63699, 498, 14095, 'done', 0, 'data/text/7520537155027881250.txt', 'data/summaries/7520537155027881250.md', '本视频围绕如何具体制定学习或读书计划展开，核心论点是计划的结构必须完整，且应包含从输入到输出再到关联的完整链条。视频指出，基础阶段的复习完成后，需要培养输出能力作为检验标准；而对于难度更高或理解要求更深的学习目标，还需进一步建立知识关联性，即能够对不同知识体系进行比较和评价，如将王阳明思想与佛陀思想对比、将中西哲学家思想横向比较。只有做到自如关联，才说明知识被彻底吃透，无论应用于实际还是应对考试都能游刃有余。此外，复习阶段应预留约半小时专门回顾前面的关联性，以保持知识的连贯与系统，最终将知识彻底掌握在自己手中。', '["学习计划的首要要求是结构完整，需包含从输入到输出的完整环节", "输出能力是检验知识理解程度的关键标准，能讲清楚才算真懂", "知识关联——即在不同知识体系间进行比较和评价——是彻底吃透知识的终极标志", "复习阶段应预留约半小时专门回顾新旧知识之间的关联性", "最终目标是让知识为己所用，无论应用还是考试都能游刃有余"]', '[{"topic": "费曼学习法与输出导向学习", "why": "视频中强调的\"输出能力\"本质上是费曼学习法的核心思想，即能够用简单语言讲清楚才算真正掌握，这一方法论值得系统学习以提升学习效率", "direction": "阅读《别闹了，费曼先生》或学习\"费曼技巧\"的相关课程，理解\"以教代学\"的底层逻辑"}, {"topic": "知识图谱与认知网络构建", "why": "视频提到的\"关联性\"学习要求在不同知识间建立比较和联系，这正是认知心理学中\"有意义学习\"的核心，研究知识图谱有助于系统化地建立跨领域知识关联", "direction": "学习奥苏贝尔的\"有意义学习理论\"，或阅读《认知天性》中关于检索练习与知识连接的章节"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115418, 1784121608, '585.0', '7.9873669147491455', 1784018346, 1784032677);
