INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7662023402873737902', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '个人出路#还看个啥书 
@冯志BodyTemple 老师在此', '个人出路#还看个啥书 
@冯志BodyTemple 老师在此', 1783953841, 'https://www.douyin.com/video/7662023402873737902', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/os1xIVYAABiWBgl8FoNBfii5BADyWIUDetKliA~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=SacSsWcXIJ%2BLL8DZU3EKOpshxBM%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714195845814ED864B715F52AB372', 51201, 15970, 1626, 9255, 'done', 0, 'data/text/7662023402873737902.txt', 'data/summaries/7662023402873737902.md', '视频通过师生对话，探讨个人在时代剧变中的出路。老师指出，工业时代向新时代转型时，过去有效的周期思维、考公和买房执念都已失效。考公是工业时代筛选专家的产物，买房依赖于土地财政。影响力即权力，网红代表新世界的权力，能跨越旧规则。历史类比表明，地理大发现使欧洲摆脱了有限资源竞争，如今技术突破同样可能使经济学假设过时。个人能力需求从专家转向适应AI时代的勇气和新学习能力。核心观点是拥抱变化，放弃旧路径依赖，面向未来重塑能力。', '["考公和买房是工业时代与土地财政的产物，时代结构变化后不再可靠。", "影响力即权力，网红代表能跨越旧规则的新世界权力。", "经济学基于资源稀缺，但技术突破可能让稀缺假设失效。", "AI时代需要的能力不再是专家，而是终身学习和引领连接的能力。"]', '[{"topic": "范式转移", "why": "理解时代变化的底层逻辑，看清单个事件背后的结构转型，能帮助个人做出顺应趋势的决策。", "direction": "阅读托马斯·库恩的《科学革命的结构》，了解范式概念如何应用于社会变迁。"}, {"topic": "资源稀缺性与经济学边界", "why": "当前许多经济学争论源于稀缺假设，探讨丰裕时代的经济逻辑能刷新个体投资和职业思维。", "direction": "学习杰里米·里夫金的《零边际成本社会》或探讨后稀缺经济学的相关文章。"}, {"topic": "影响力经济", "why": "影响力作为新资本形式，正在重塑财富分配，理解其运行机制是个人在新世界立足的关键。", "direction": "研究网红经济、个人品牌建设，可参考《巴拉巴西成功定律》或《影响力》等书。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1784032681, 1784032694, 1784033063, '131.0', '12.393627882003784', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7656102779984059058', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '工会弊端#工会 #学习 #知识分享', '工会弊端#工会 #学习 #知识分享', 1782575340, 'https://www.douyin.com/video/7656102779984059058', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oc9R08BtOAleCtvTAQW0f8YMR8lf8OeQEHI5fQ~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=2AtkYGsidtIa%2Fm9U08GdyBm5srg%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071419584796F1566F20E755230E9E', 6868, 899, 369, 550, 'done', 0, 'data/text/7656102779984059058.txt', 'data/summaries/7656102779984059058.md', '视频探讨了工会在美欧的弊端：美国工会因企业打压、法律执行滞后及产业结构变化而衰落，甚至被称为“黑社会”；欧洲工会则因高福利难以为继和老龄化等问题频繁罢工，让社会承担成本。针对竞争力担忧，指出高端制造强国往往拥有成熟工会，长期依赖廉价劳动力会损害创新。衡量工资是否合理的客观指标是劳动者报酬占GDP比重，该数据下降反映工会衰落与分配不公，最终导致内需不足和恶性竞争。对普通人而言，减少在劳资争议大的商家消费、培养不可替代的技能才是关键。', '["美国工会的“黑社会”化源于法律允许强制收费，以及企业打压和产业结构变化导致工会衰落。", "欧洲罢工频发是高福利传统与老龄化、通胀等现实压力的冲突，且罢工成本常由社会承担。", "高工资未必削弱竞争力，德国等高端制造强国拥有成熟工会，而长期依赖廉价劳动力会损害创新。", "劳动者报酬占GDP比重是衡量工资合理性的重要指标，该比重下降反映了工会衰落和分配不公。", "普通人应对劳资困境的出路在于减少支持争议大的商家，并提升自身不可替代的技能。"]', '[{"topic": "劳动者报酬占GDP比重", "why": "该指标能客观衡量国民收入中劳动与资本的分配关系，有助于理解工会力量变迁、内需不足和竞争力演变的深层经济逻辑。", "direction": "可阅读《21世纪资本论》或关注国际劳工组织、OECD的相关数据库，比较各国劳动份额变化趋势。"}, {"topic": "工会与竞争力的关系", "why": "打破“低工资=高竞争力”的简单认知，探究德国、北欧等地的劳资协同模式如何助推产业升级，对理解经济高质量发展有启发。", "direction": "学习德国“共决制”和丹麦“灵活保障”模式，参考《比较政治经济学》相关章节。"}, {"topic": "集体行动的成本外部化", "why": "欧洲罢工让社会承担成本却无决策权，折射出公共利益与团体利益的冲突，是理解现代社会运动伦理的重要切口。", "direction": "研究“俱乐部物品”与外部性理论，可阅读曼瑟尔·奥尔森的《集体行动的逻辑》。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1784032681, 1784032712, 1784033096, '205.0', '16.32077383995056', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7653701627077870835', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '爸比 祝爸爸父亲节快乐 #父亲节 #父亲节快乐', '爸比 祝爸爸父亲节快乐 #父亲节 #父亲节快乐', 1782016277, 'https://www.douyin.com/video/7653701627077870835', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oY3w6ALB7IgATGDfiYIC3fDUV4pFEBjsCAlfab~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=OB1CerGDVZKRR0lf56DKdY2JC%2Bg%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141958507FC5F544A23563304460', 17903, 1788, 1189, 1379, 'done', 0, 'data/text/7653701627077870835.txt', 'data/summaries/7653701627077870835.md', '本文以父亲节为背景，通过一系列生活片段，展现了父亲在子女成长过程中角色的演变。从童年时在银行工作的父亲用双簧游戏逗乐孩子，到高中毕业强制安排银行实习，再到子女成年后面对职业困境时父亲从固执到理解的转变，故事折射出两代人在时代变迁中的互动。父亲最初以“稳定工作”为基本盘，用自身经验指导子女，但当子女身心俱疲时，又转而将健康放在首位。随着经济环境变化，曾经的金饭碗银行工作不再稳固，父亲最终支持子女追求自我。通过“双簧”这一意象的再现，作者强调了亲子间默契与共同成长，揭示了父爱深沉而灵活的本质：它不是一成不变的规则，而是随着子女需要不断调整的守护。全文以温情笔触，探讨了代际沟通、个人选择与时代局限，并最终落脚于相互理解与支持。', '["父亲最初以工作稳定为首要考量，但最终将子女的身心健康放在第一位。", "银行业的兴衰表明，依赖过往经验进行职业规划可能因时代变迁而失效。", "亲子间的有效沟通需要家长学会倾听、让步与支持，而非单向控制。", "“双簧”式互动象征了亲子关系中从指导到配合的成长与默契。"]', '[{"topic": "代际沟通与教育方式", "why": "视频通过父子冲突与和解的案例，展示了传统权威式教育向协商式支持的转变，对现代家庭教育具有借鉴意义。", "direction": "建议阅读《非暴力沟通》和《如何说孩子才会听》，学习平等对话与情感联结的技巧。"}, {"topic": "职业发展中的时代机遇", "why": "博主经历揭示了个人努力与时代红利的复杂关系，有助于理解经济周期对职业选择的影响。", "direction": "可参考《异类》或《随机漫步的傻瓜》，探究时势与个人成就的关联，培养宏观职业视野。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1784032681, 1784032745, 1784033234, '225.0', '32.375235080718994', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7648497157217660786', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '伊朗-世界地图系列🗺️ Tim Marshall < the power of geography> #伊朗 #地理 #地理知识', '伊朗-世界地图系列🗺️ Tim Marshall < the power of geography> #伊朗 #地理 #地理知识', 1780805714, 'https://www.douyin.com/video/7648497157217660786', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/osU7kAfKODBGOEIqgJFfABg8Y6JJl3I099DpAS~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=8kgOGfJzKvXQbWtl%2FObLgr5cw2k%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141958520DAD32A1D016B75B567C', 10289, 1867, 623, 709, 'done', 0, 'data/text/7648497157217660786.txt', 'data/summaries/7648497157217660786.md', '视频聚焦伊朗的地缘政治与宗教根源，指出什叶派信仰使其难以与外界妥协。伊斯兰教因先知继承问题分裂为逊尼派和什叶派，伊朗作为什叶派核心，将宗教权威融入政治体制。1979年霍梅尼领导伊斯兰革命，推翻巴列维王朝，建立神权政体，以最高领袖代理隐遁伊玛目治理国家。革命过程中，社会抗议与罢工瘫痪经济，最终迫使国王流亡。此后伊朗视美国为“大撒旦”，以色列为“二撒旦”，延续对抗姿态。然而，这场革命并未带来承诺中的公正，只是将王冠换成了头巾，权力压迫的本质依然延续。', '["伊斯兰教先知继承分歧导致逊尼派与什叶派千年对立，伊朗作为什叶派核心将宗教权威融入政治体制", "1979年伊斯兰革命始于报纸攻击霍梅尼，通过什叶派四十日悼亡仪式的循环动员最终瘫痪全国经济", "霍梅尼创立法基赫监护神权政体，最高领袖代行隐遁伊玛目权力，形成凌驾于一切机构之上的绝对权威", "伊朗以对抗''大撒旦''美国和''二撒旦''以色列为外交基调，源于神学上代表正道秩序与不信者必然冲突的预设", "革命承诺无压迫无独裁，但实际只是将君主制的王冠换成了教士政权下的头巾，权力集中本质未变"]', '[{"topic": "什叶派与逊尼派的教义分歧及政治影响", "why": "理解伊朗内外政策的原点，其宗教合法性与权力结构皆源于此，是解读中东地缘政治的关键钥匙", "direction": "阅读《伊斯兰教史》《什叶派伊斯兰教》等专著，或观看耶鲁大学公开课《全球宗教冲突》相关章节"}, {"topic": "伊朗伊斯兰革命的历史进程", "why": "这场革命塑造了现代伊朗的政体与社会，展示宗教力量如何推翻世俗王朝，对比较政治学有深远启示", "direction": "研读《伊朗四十年革命》《霍梅尼传》，结合纪录片《伊朗：革命后的四十年》深入学习"}, {"topic": "地缘政治中的宗教意识形态", "why": "伊朗案例表明宗教不仅是信仰，更可作为凝聚民族主义、输出影响力的工具，有助于分析其他宗教国家外交行为", "direction": "参考Tim Marshall《地理的囚徒》与《力量的地理》，比较沙特、以色列等国的政教互动模式"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1784032681, 1784032758, 1784033278, '670.0', '11.446371078491211', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7644799962127869833', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '气候如何塑造国家-世界地图系列🗺️气候专题#气候 #中国气候 #碳减排#3060 #双碳', '气候如何塑造国家-世界地图系列🗺️气候专题#气候 #中国气候 #碳减排#3060 #双碳', 1779943697, 'https://www.douyin.com/video/7644799962127869833', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/osR80DFjIAD52PBAfAyEpPgoYIM9gOFTqXBiOf~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=NFXIZxEl9W8pyztj3fFhOOLkxik%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141958555DD44CCE5FFBA323006C', 5664, 1061, 190, 379, 'done', 0, 'data/text/7644799962127869833.txt', 'data/summaries/7644799962127869833.md', '视频从气候角度重新审视国家发展，以中国、美国和俄罗斯为例，剖析气候如何影响古代王朝周期、现代经济格局及当代碳减排战略。核心论点是：气候作为基础变量，既通过农业、水资源和灾害塑造了中央集权等政治制度，又通过温差、降水划分经济区域并引发冲突。在现代，气候挑战促使各国基于资源禀赋采取不同应对行动，如中国的“3060”目标意在产业升级与能源安全，美国的通胀削减法案则服务于新能源产业竞争。', '["季风气候的不稳定性让中国古代必须通过强力中央调度来应对灾害，从而巩固了集权体制。", "美国南北经济差异源于气候分区，由此引发的利益冲突是南北战争的深层根源。", "俄罗斯的严寒既是抵御外敌的天然屏障，也长期拖累其经济发展和民众生活。", "现代国家应对气候变化的策略并非单纯环保，而是与本国资源禀赋、产业安全和地缘经济深度绑定。", "中国的“3060”目标本质上是产业升级和能源安全战略，而美国的新能源补贴意在掌控绿色产业主导权。"]', '[{"topic": "小冰河期与中国王朝更替", "why": "理解气候变化如何通过农业减产、饥荒和社会动荡触发历史周期，是分析文明兴衰的重要维度。", "direction": "参考竺可桢《中国近五千年来气候变迁的初步研究》及相关历史气候史著作，探究明末小冰期与社会崩溃的关联。"}, {"topic": "碳达峰与碳中和（3060目标）的经济逻辑", "why": "碳减排背后涉及能源转型、技术竞争和全球产业链重构，是理解未来十年国际政经格局的关键。", "direction": "学习能源经济学基础，阅读《第三次工业革命》等作品，关注各国绿色新政的具体政策设计。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1784032681, 1784032773, 1784033330, '357.0', '14.613057136535645', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7639393316836855706', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '工会制度 卡尔·马克思 《工资、劳动和资本》 #工会 #正能量 #读书', '工会制度 卡尔·马克思 《工资、劳动和资本》 #工会 #正能量 #读书', 1778686155, 'https://www.douyin.com/video/7639393316836855706', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/osil8Kt1AAAgA9eBi5gkQekBDWEPIRuBATMgIB~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=ZsvTxih4w2ul6ebe8Rt73%2BbJyX4%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141958574B17992D4ADD7734F628', 29567, 4450, 1797, 5663, 'done', 0, 'data/text/7639393316836855706.txt', 'data/summaries/7639393316836855706.md', '视频以马克思《工资、劳动和资本》为理论基础，探讨工会制度的深层价值。指出两个常见误区：一是市场可自发调节薪资，实则工人缺乏议价能力；二是可靠资本道德保障薪酬，但企业竞争如同囚徒困境，必然选择压榨工人，导致恶性内卷。工会能增强工人议价能力，使收入增加，消费扩大，进而拉动内需，推动企业利润增长和研发投入，实现产业升级，形成劳资共赢的正向循环。通过回顾英国工会历经百年争取合法地位的历史，凸显制度保障对于公平竞争的重要性。在AI时代，普通劳动力议价能力下降，需发挥专长培养特殊技能。视频论点在于：工会不仅是维护权益的组织，更是优化经济结构、促进社会健康发展的关键，能有效反内卷、防消极思潮，为劳动者创造向上动力。', '["市场无法自发形成合理薪酬，工人在资本面前缺乏议价能力，是结构性不平等的结果。", "企业间的竞争如同囚徒困境，压榨工人成为理性选择，导致全行业内卷。", "工会通过集体议价提升工人收入，能有效拉动内需，促进企业研发和产业升级，形成正向循环。", "英国工会合法化历经百年斗争，证明制度化的劳资博弈规则是实现社会长期稳定的必要条件。", "在AI时代，个体需培养特殊技能以增强议价能力，同时社会应保障合理的休息与调整空间。"]', '[{"topic": "马克思《雇佣劳动与资本》中的劳资关系与工资决定理论", "why": "理解工资背后的权力结构，是批判纯市场论和构建公平薪酬体系的理论基石。", "direction": "阅读马克思原著《雇佣劳动与资本》（或译《工资、劳动和资本》），并结合当代劳动经济学教材如《劳动经济学》进行对比分析。"}, {"topic": "博弈论中的囚徒困境与市场内卷的形成机制", "why": "揭示了缺乏合作机制时，个体最佳策略导致整体次优结果的现象，有助于从数学模型理解内卷本质。", "direction": "学习基础博弈论，推荐《策略思维》或大学博弈论课程，并尝试构建劳资博弈的扩展式模型。"}, {"topic": "英国工会运动史与劳动法演进", "why": "了解工人组织如何通过抗争影响立法，以及法律如何反过来塑造劳资关系，为当下劳动政策提供历史借鉴。", "direction": "研读《英国工会运动史》或《英国劳动法演变》，重点关注1799-1906年的关键法案及其社会经济背景。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1784032681, 1784032792, 1784033509, '196.0', '17.977899074554443', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7636798337517687194', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '如何克服不想上班的心情《纳瓦尔宝典》 #个人成长 #副业 #读书', '如何克服不想上班的心情《纳瓦尔宝典》 #个人成长 #副业 #读书', 1778080672, 'https://www.douyin.com/video/7636798337517687194', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/owAjAA60Di2BxeYIam7PBiWfXBoYPtIzs9gBmg~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=qah2dkzibVzaPFyEkRZZYWmXhms%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714195859763C1A1D9DE0B935A15D', 8435, 1931, 429, 2424, 'done', 0, 'data/text/7636798337517687194.txt', 'data/summaries/7636798337517687194.md', '视频作者分享了自己克服“不想上班”心情的心路历程。起初遭遇中年危机，对工作失去热情，在发现同事们同样厌恶上班后寻求心理咨询。咨询师指出，不喜欢工作是正常的，建议减轻副业压力。作者由此转换叙事，将热爱的短视频创作视为主业，而把上班当成副业。这一心态转变有效缓解了痛苦，重新找回生活的平衡。核心观点是，找到真正热爱的事情并视之为主业，即使仍需从事一份工作，也能用副业心态减少抵触，从而更从容地面对上班。', '["不想上班是普遍情绪，不必因此自责或过度焦虑。", "工作环境变化可能导致热情消退，接纳“不喜欢”是改变的第一步。", "将热爱之事视为主业、上班当成副业，能有效转换心态、减轻痛苦。", "谨慎保护热爱，避免让爱好因高压输出而沦为另一种负担。", "《纳瓦尔宝典》启示：找到天赋与热爱，让工作与生活达成内在平衡。"]', '[{"topic": "认知重构与叙事疗法", "why": "通过改变内在叙事来调整情绪和行为，是心理学中实用的自助方法。", "direction": "可阅读《叙事心理治疗》或学习认知行为疗法中的“自动思维”识别与重构技术。"}, {"topic": "纳瓦尔的“热爱与工作”理念", "why": "纳瓦尔主张将热爱转化为工作，甚至认为“工作就是玩”，能根本性解决职业倦怠。", "direction": "精读《纳瓦尔宝典》，着重理解“把自己产品化”和“找到天赋所在，积累专长”等原则。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1784032681, 1784032803, 1784033764, '177.0', '10.744441032409668', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7634513520964935910', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '俄罗斯-世界地图系列🗺️ 内容主要来自<prisoners of geography> Tim Marshall #世界地理 #俄罗斯地理 #地理知识 #读书', '俄罗斯-世界地图系列🗺️ 内容主要来自<prisoners of geography> Tim Marshall #世界地理 #俄罗斯地理 #地理知识 #读书', 1777548697, 'https://www.douyin.com/video/7634513520964935910', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ospev8sPIMZdBmlAI4mzdAAjB9iamDf8PgXB5i~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=ZEM5OmdwvLOMcvU0Lu449DddWQQ%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714195902D934E1C7708D2E15E31D', 29069, 4583, 1217, 1126, 'done', 0, 'data/text/7634513520964935910.txt', 'data/summaries/7634513520964935910.md', '视频从《地理囚徒》视角解读俄罗斯。俄罗斯拥有世界最大国土和第一油气储量，但GDP仅与广东相当，揭示了其发展困境。地理上，西部平缓平原使其无险可守，历史上屡遭入侵，这驱动了向欧洲扩张以建立缓冲区的逻辑；同时，漫长的北极海岸线多冰封，缺少不冻港，数百年来寻求出海口成为外交军事核心。广袤西伯利亚虽资源丰富，但严寒气候增加开发难度。这些地理限制至今困扰普京，影响着俄乌冲突及与西方关系。俄罗斯是典型的“地理囚徒”，其行为深嵌于地图的宿命之中。', '["俄罗斯西部平原地形使其缺乏天然屏障，历史上饱受入侵，因此形成以空间换时间的扩张战略。", "寻找全年不冻港是俄罗斯数百年来地缘政策的核心驱动力，深刻影响了其对黑海、波罗的海及远东的介入。", "丰富的自然资源既是财富也是负担，导致经济结构单一，并面临“资源诅咒”。", "普京时代面临的挑战根植于地理：与西方的缓冲地带争夺、国内经济现代化难题。", "全球变暖使北极航道重要性上升，可能为俄罗斯带来新的地缘优势，但亦伴随挑战。"]', '[{"topic": "地缘政治学中的“地理囚徒”概念", "why": "理解一个国家行为不能脱离其地理禀赋，该概念能帮助分析俄罗斯、中国等国家的战略选择。", "direction": "阅读蒂姆·马歇尔的《地理的囚徒：十张地图解释世界》（Prisoners of Geography），深入理解地理如何塑造国家命运。"}, {"topic": "“资源诅咒”理论", "why": "丰富的自然资源为何常常阻碍国家经济发展，俄罗斯是典型案例，值得探究其背后的政治经济学机理。", "direction": "查阅经济学文献，如《石油与政治》、《资源诅咒》相关学术论文，或阅读《为什么国家会失败》中对资源陷阱的论述。"}, {"topic": "俄罗斯历史上的扩张与地缘战略", "why": "从沙俄到苏联再到当代，扩张逻辑一脉相承，地理因素贯穿始终，是理解欧亚大陆政治的关键。", "direction": "阅读罗伯特·卡普兰的《即将到来的地缘战争》或安德烈·P·齐甘科夫的《俄罗斯与西方》等书籍。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1784032681, 1784032811, 1784033949, '431.0', '6.486363172531128', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7630501276296986355', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '纳瓦尔关于实现个人价值的建议 《纳瓦尔宝典》#纳瓦尔 #自我意识 #个人成长 #读书', '纳瓦尔关于实现个人价值的建议 《纳瓦尔宝典》#纳瓦尔 #自我意识 #个人成长 #读书', 1776614524, 'https://www.douyin.com/video/7630501276296986355', 'https://p3-pc-sign.douyinpic.com/tos-cn-p-0015/oMH6WzCAYjAuigeeeft3ZJ4pn2YqEIeAjUPPVT~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=xwbJM15mBYcY0pV4YivgNyo%2BDyo%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714195904AE2AF9ECF184242DEA6D', 24119, 4793, 828, 4177, 'done', 0, 'data/text/7630501276296986355.txt', 'data/summaries/7630501276296986355.md', '视频以相亲遇到想被包养的弟弟为引子，探讨了《纳瓦尔宝典》中关于实现个人价值的建议。核心论点是：人无法通过出卖时间变富，但可以通过出卖“特殊技能”实现财富自由。特殊技能是社会需要但无法被标准化培训的能力，如销售或创新。由于没有人比你更擅长做自己，因此选择做自己、发展个性化技能是避免同质化竞争的关键。视频还指出，迫于生计无法做自己时，应寻找对别人是工作而对你是玩的事情，并强调自我评价与主动解决问题的态度相关。最终，传递了通过自我探索和态度转变来提升个人价值与生活质量的信息。', '["出卖时间无法变富，出卖特殊技能可以突破收入天花板", "特殊技能是社会需要但无法被标准化培训的能力，源自个人特质", "做自己是避免同质化竞争，发挥独特优势的最佳策略", "寻找对别人是工作而对自己是玩的事情，是发现特殊技能的入口", "自我评价与主动解决问题的态度相关，行动能提升自我价值感"]', '[{"topic": "《纳瓦尔宝典》中的财富与幸福哲学", "why": "本书系统阐述了纳瓦尔·拉维坎特关于财富、杠杆、特定知识和幸福的底层逻辑，是重塑个人发展观的经典之作。", "direction": "阅读《纳瓦尔宝典》全书，重点理解“特定知识（Specific Knowledge）”“产品化你自己”和“杠杆”的概念，并思考如何将其应用于自身职业规划。"}, {"topic": "特殊技能（特定知识）的构建与变现", "why": "特殊技能是个人摆脱同质化竞争、实现财富增长的核心，但如何识别、培养和变现这一能力，需要更具体的方法论。", "direction": "深入研读关于个人优势识别的书籍（如《盖洛普优势识别器》），结合《纳瓦尔宝典》中的案例，分析自身兴趣与市场需求的交集，并尝试通过内容创作、咨询或产品化输出自己的特定知识。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1784032681, 1784032824, 1784034091, '133.0', '12.764914989471436', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7628617199216951241', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '投资失误复盘《投资的怪圈》   #投资 #投资理财#富国基金#富国ETF#看多中国指投富国', '投资失误复盘《投资的怪圈》   #投资 #投资理财#富国基金#富国ETF#看多中国指投富国', 1776175853, 'https://www.douyin.com/video/7628617199216951241', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oYQf47CTFv8lTWEjFemMdAEBGdB8A9fu9QV7QJ~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=0x76vnwTuITAFOi9tZ20NToRIUw%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714195907D9AF54C81590E62ACE19', 4449, 921, 278, 522, 'done', 0, 'data/text/7628617199216951241.txt', 'data/summaries/7628617199216951241.md', '视频通过作者自身与父母投资未能战胜市场的经历，复盘了购买某地产股失误的心理原因。结合《投资的怪圈》一书，揭示了投资者常见的四大心理偏误：高估自己、对熟悉事物过度乐观、禀赋效应下的不舍得割肉、以及控制错觉导致的频繁操作。这些心理偏差使普通人难以跑赢市场。作者进而提出解决方案：建议普通人放弃择时择股，转而长期定投指数基金，以低成本、分散化的方式分享市场发展红利。同时以富国基金为例，介绍了规范命名、降费等ETF产品选择要点，并倡导全市场指数定投实现省心投资。', '["高估自己、熟悉偏好、禀赋效应、控制错觉是导致投资失误的常见心理偏误", "普通人时间精力、信息不占优势，难以通过择时择股持续战胜市场", "长期定投指数基金可降低心理影响，以低成本分享市场整体增长", "选择指数基金应关注基金公司实力、产品命名清晰度和费率水平", "全市场指数定投有助于分散风险，避免择时和风格轮动焦虑"]', '[{"topic": "行为金融学中的投资者心理偏误", "why": "了解过度自信、禀赋效应等心理偏误有助于识别自身投资决策中的非理性因素，提升决策质量。", "direction": "可阅读《投资的怪圈》《思考，快与慢》等书籍，系统学习行为经济学与投资心理学。"}, {"topic": "指数基金与ETF投资策略", "why": "指数基金是普通投资者低成本获取市场平均收益的有效工具，理解其机制与策略能避免盲目投资。", "direction": "深入学习不同指数编制方法、ETF运作机制，以及定投、网格等策略，可参考《漫步华尔街》《共同基金常识》等。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1784032681, 1784032836, 1784034382, '141.0', '11.77521300315857', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7627133288352808650', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '美国-世界地图系列🗺️《Prisoners of geography》 x《大棋局》Tim Marshall 布热津斯基 #地理 #世界地理 #美国地理 #知识分享 #读书', '美国-世界地图系列🗺️《Prisoners of geography》 x《大棋局》Tim Marshall 布热津斯基 #地理 #世界地理 #美国地理 #知识分享 #读书', 1775831195, 'https://www.douyin.com/video/7627133288352808650', 'https://p3-pc-sign.douyinpic.com/tos-cn-p-0015/oMZxg7BBSI0sizBJpDfBeCvaW83CBIA0AiAw0I~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=XNZxcRAaF2nCqK%2BeN%2FJFN1iOFEQ%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071419590915CF167BB508251A7731', 15968, 3025, 531, 1105, 'done', 0, 'data/text/7627133288352808650.txt', 'data/summaries/7627133288352808650.md', '本视频以《地理的囚徒》与《大棋局》为理论框架，通过两张地图与美国的发家史，深度解析了美国行为背后的地理诉求与战略焦虑。美国凭借两洋护体的优越地理位置，在不到百年的时间内完成了从十三州殖民地到横跨北美大陆的领土扩张。随后，通过美西战争走向海外，借两次世界大战的机遇独善其身并迅速崛起。二战后，美国通过布雷顿森林体系、马歇尔计划与北约三步走战略，确立了经济与军事上的西方领袖地位，并构建了北大西洋及第一岛链的封锁线以遏制苏联。视频揭示了美国如何利用地缘优势与全球博弈，将自身塑造为世界霸主，同时也暗示了这种扩张背后的深层约束与挣扎。', '["美国利用两洋护体的地理优势和不到百年的领土扩张，完成了本土版图的拼图与经济整合。", "西奥多·罗斯福通过美西战争和门罗主义升级，确立了美国在西半球的霸权并开启了海外扩张。", "二战后美国通过布雷顿森林体系、马歇尔计划和北约三步走战略，确立了西方领袖地位。", "美国在冷战期间构建北大西洋防线与第一岛链，通过提供保护和市场对抗苏联的军事控制。"]', '[{"topic": "门罗主义与罗斯福推论", "why": "门罗主义及其后续推论是美国干涉拉美及全球事务的核心外交基石，理解它有助于看透美国“后院”思维的底层逻辑。", "direction": "阅读《大棋局》中关于美国地缘政治目标的章节，研究门罗主义在不同历史时期的演变。"}, {"topic": "布雷顿森林体系与马歇尔计划", "why": "这两者是美国在二战后建立经济与政治霸权的双柱，揭示了美元如何取代英镑以及美国如何通过经济援助控制欧洲。", "direction": "学习国际政治经济学，阅读《布雷顿森林体系的兴衰》或相关货币战争史。"}, {"topic": "地缘政治中的海权与岛链战略", "why": "美国通过控制海洋咽喉和构建第一岛链来遏制欧亚大陆国家，这是海权论在现代地缘政治中的经典应用。", "direction": "阅读马汉的《海权论》与《地理的囚徒》，研究太平洋地缘格局与岛链封锁体系。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784032865, 1784113810, '391.0', '27.02880096435547', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7620108586748873330', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '语言暴力 《帕哈撒帕之歌》 #语言 #文字 #印第安人 #女子月经弄脏卧铺 #读书', '语言暴力 《帕哈撒帕之歌》 #语言 #文字 #印第安人 #女子月经弄脏卧铺 #读书', 1774194789, 'https://www.douyin.com/video/7620108586748873330', 'https://p3-pc-sign.douyinpic.com/tos-cn-p-0015/okEq2mGIAuDefn3PAHxMMeNICoBLQDnfCQAAMP~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=sQfeFaq%2Fp8rnf1m9jlMe0MGuy7A%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071419591226A07BAA6E47F319E14D', 345063, 20264, 6547, 74826, 'summarize_failed', 1, 'data/text/7620108586748873330.txt', NULL, NULL, NULL, NULL, NULL, NULL, 1784032681, 1784032881, NULL, '190.0', '16.121592044830322', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7619576719360591726', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '中国-世界地图系列🗺️《Prisoners of geography》 Tim Marshall #地理 #世界地理 #中国地理 #知识分享 #读书', '中国-世界地图系列🗺️《Prisoners of geography》 Tim Marshall #地理 #世界地理 #中国地理 #知识分享 #读书', 1774071656, 'https://www.douyin.com/video/7619576719360591726', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oQPptktkYAciE91OgQF4vLDDAfpDaKiEAABdeQ~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=%2BafuHi3XSH%2FdIuskyI69vg64cMo%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714195914F8EA417AB46BA6A6517D', 12293, 2153, 513, 919, 'done', 0, 'data/text/7619576719360591726.txt', 'data/summaries/7619576719360591726.md', '本视频以《地理囚徒》为理论框架，深入剖析了中国地理环境与国家战略安全的紧密联系。视频从上世纪六十年代的三线建设切入，阐述了西南腹地、西藏和新疆在不同历史时期作为战略缓冲区的重要作用，并强调了青藏铁路、天山胜利隧道及中巴经济走廊等基建工程对突破地理限制、保障能源与物流安全的关键价值。中国在兼具陆权与海权特征的地理处境下，面临着守卫漫长边疆与拓展对外航线的双重挑战。视频最终指出，在逆全球化与内部经济转型的背景下，中国必须在窗口期内完成内需拉动、制造业升级和能源安全转型，以内部团结和经济发展作为守卫国家安全的基础。', '["三线建设与西南腹地依托喜马拉雅山脉等天然屏障，构成了保障中原安全的战略纵深。", "青藏铁路、天山胜利隧道等基建工程突破了恶劣地理限制，大幅提升了边疆后勤保障与物流效率。", "中巴经济走廊打通了直连印度洋的陆路通道，使中国进口石油可绕过马六甲海峡，缩短一万多公里。", "中国兼具陆权与海权特征，面临守卫漫长边疆与保障贸易航线的双重挑战。", "应对逆全球化与经济转型压力，中国需在窗口期内实现内需拉动、制造业升级与能源安全转型。"]', '[{"topic": "地缘政治中的陆权与海权理论", "why": "视频提及中国兼具陆海双权特征，理解该理论能更深刻认知国家在不同方向的战略防御与扩张逻辑。", "direction": "阅读麦金德的《历史的地理枢纽》与马汉的《海权论》，对比海陆大国的战略差异。"}, {"topic": "马六甲困境与能源安全", "why": "中巴经济走廊的构建背景即为绕过马六甲海峡，这是中国能源进口和外贸运输的关键生命线与脆弱点。", "direction": "研究中国能源进口结构及“一带一路”倡议下的陆路通道布局（如中缅油气管道）。"}, {"topic": "三线建设的历史背景与经济影响", "why": "视频以三线建设为切入点讲述中国工业布局，这深刻影响了中国后续的工业体系分布与区域经济发展。", "direction": "查阅中国当代经济史，了解三线建设的“靠山、分散、隐蔽”方针及其对中西部城市化的长远影响。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784032894, 1784113961, '381.0', '11.361974239349365', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7619334319328348873', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '从土地逻辑到产业逻辑：云南产业园探索 #土地财政 #云南产业园 #点赞云南#七彩云南气象万千', '从土地逻辑到产业逻辑：云南产业园探索 #土地财政 #云南产业园 #点赞云南#七彩云南气象万千', 1774014514, 'https://www.douyin.com/video/7619334319328348873', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oIRPCRfDMQ9V2tmDPUdmeeVp9EDA8EfDFEQLQA~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=2P0Q%2BkK05cYnedn5rEk7NwAWhGg%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141959162EADA5B6FF09A71A741B', 16639, 3589, 813, 1208, 'done', 0, 'data/text/7619334319328348873.txt', 'data/summaries/7619334319328348873.md', '视频探讨了土地财政退潮后地方经济发展的转型路径。过去依赖卖地收入的模式因人口增速放缓和缺乏稳定税基而不可持续，国家“十五五”规划引导地方从土地逻辑转向产业逻辑。以云南为例，分析了其如何克服产业基础薄弱的劣势，依托资源与地缘优势，以产业园为载体推动产业升级。文章详细阐述了云南产业园如何通过聚集产业链、原地加工提高附加值和共享基础设施，解决现实困难，并辅以具体企业案例说明。同时指出，云南通过严格控制园区数量和主导产业来防范重复建设。最终结论是，转型的成败取决于政策退坡后产业能否真正留下并形成稳定税基。', '["土地财政因投资回报下降和缺乏稳定税基已不可持续，地方发展必须从土地逻辑转向产业逻辑。", "云南依托资源与地缘优势，以产业园为载体聚集产业链，降低协作成本并实现资源就地增值。", "云南祥丰、云铜新冶等企业通过依托园区产业链协同与技改，成功实现了产品转型与价值提升。", "云南严格限制园区数量和主导产业数量，实行差异化分工，严防重复建设和资源浪费。", "产业转型成败的最终检验标准是政策退坡后产业能否真正留下并形成稳定税基。"]', '[{"topic": "土地财政与地方税基", "why": "理解地方财政的收入结构和转型痛点，需要从经济学角度剖析一次性土地出让金与持续性税收的差异。", "direction": "建议阅读《大国大城》或学习“地方公共财政与土地经济学”相关概念。"}, {"topic": "产业集群与园区经济", "why": "产业园区如何通过集聚效应降低交易成本、促进创新，是区域经济学中的核心议题，对理解地方产业政策至关重要。", "direction": "建议学习迈克尔·波特的“产业集群”理论，或阅读《区域经济学》相关教材。"}, {"topic": "中央与地方财政事权划分", "why": "了解国家如何通过调整中央与地方的财权事权来解决地方发展动力问题，是理解宏观经济政策走向的关键。", "direction": "建议研究“分税制改革”历史及现行“财政事权和支出责任划分改革”政策文件。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784032905, 1784114039, '142.0', '10.338298797607422', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7612225749453763250', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '津巴布韦禁止锂矿出口的影响？ 锂电行业估值逻辑分享#锂电 #锂电池 #行业研究 #宁德时代', '津巴布韦禁止锂矿出口的影响？ 锂电行业估值逻辑分享#锂电 #锂电池 #行业研究 #宁德时代', 1772371495, 'https://www.douyin.com/video/7612225749453763250', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oY9QAN0CEFAOBpEgQ9fDDbDzAoHI6spIIA2fBh~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=K2b8k4XpWZQHMD3J7%2BHMexgrq0k%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607141959196A5B33BDBAF96A20E3F1', 5347, 629, 343, 333, 'summarizing', 0, 'data/text/7612225749453763250.txt', NULL, NULL, NULL, NULL, NULL, NULL, 1784032681, 1784032928, NULL, '180.0', '17.133399963378906', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7611474527730331058', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '《稀缺》 我们为何陷入忙碌与贫穷 #时间管理 #存钱 #自我成长 #读书', '《稀缺》 我们为何陷入忙碌与贫穷 #时间管理 #存钱 #自我成长 #读书', 1772184514, 'https://www.douyin.com/video/7611474527730331058', 'https://p3-pc-sign.douyinpic.com/tos-cn-p-0015/oIemAf26DCGh5hmIYYLyfIj8Cfh3IAE3YCBMJA~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=76sEZMTeLC7iBIsbHR3Wv8Wzf90%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071419592229C9646D4DE81DBC049B', 18888, 4536, 1303, 3487, 'done', 0, 'data/text/7611474527730331058.txt', 'data/summaries/7611474527730331058.md', '本视频基于哈佛与普林斯顿大学教授的研究，探讨了稀缺心态如何影响人们的心智与行为。当拥有的比需要的少时，稀缺感会盘踞大脑，导致动作变形。稀缺主要通过两种机制影响我们：一是引发管窥心态，使人只关注当下最紧迫的事而忽视长远利益；二是增加带宽负担，降低大脑算力，导致判断失误和情绪失控。为了跳出稀缺陷阱，视频提出了三个应对思路：留出余弦以应对突发状况、避免管窥以兼顾长期目标、降低带宽负担以减少内耗。最终强调，稀缺虽是客观情况，但我们可以通过主动调整心态和行为设置，避免陷入被动境地。', '["稀缺心态会占据大脑心智，导致人们在面对金钱、情感等资源匮乏时做出非理性的短视决策。", "管窥心态让人只能看到眼前最紧迫的事，虽然能短暂提升效率，但会让人为了短期利益牺牲长远规划。", "稀缺感会增加大脑的带宽负担，降低认知能力和情绪控制力，导致智商和素质在重压下下降。", "通过留出余弦、一次性设置等方法，可以有效避免管窥并降低带宽负担，提升系统运转效率。", "稀缺是客观情况，但稀缺心态可调整，应主动避免陷入被动的财务或人际环境，夺回生活掌控权。"]', '[{"topic": "稀缺心态", "why": "理解稀缺如何劫持大脑注意力与认知带宽，有助于识别日常生活中心智枯竭和短视决策的根本原因，从而跳出越努力越穷的怪圈。", "direction": "阅读塞德希尔·穆来纳森的《稀缺：我们是如何陷入贫穷与忙碌的》一书，深入研究管窥效应与带宽负担的认知心理学机制。"}, {"topic": "系统缓冲与余弦设计", "why": "在资源紧张的个人时间或企业运营中刻意留白，能有效对冲不确定性带来的冲击，避免整体系统因过度满载而崩溃。", "direction": "学习运筹学或系统思考中的约束理论，探索如何在资源管理中设计合理的冗余与弹性。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784032947, 1784114263, '176.0', '17.734943866729736', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7605222729181248947', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '生育问题#出生率 #人口出生率 #计划生育', '生育问题#出生率 #人口出生率 #计划生育', 1770728907, 'https://www.douyin.com/video/7605222729181248947', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/osGGsgfLI4yFgzLATWuAmtlerXL7CrBFsgBf4h~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=z2rtzfwTSplEe7W11KwVQvaiy%2Bg%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714195924E2D5D1212BA91F35227C', 24854, 4284, 1747, 2554, 'done', 0, 'data/text/7605222729181248947.txt', 'data/summaries/7605222729181248947.md', '视频探讨了出生率下降背后的深层结构性问题，指出人口问题本质是结构问题而非数量问题。人口老龄化叠加经济转型期，会导致消费萎缩、税基减少、社保压力加大，而AI技术虽能提升效率却无法改变财富分配格局，甚至加剧资本集中。过去计划生育是在特定历史条件下以未来老龄化换取当下脱贫扫盲和工程师红利的策略选择。当前鼓励生育的核心意义在于趁人口基数尚存为政策预留操作空间。提高生育率的关键在于替个人分担职业与养育风险，包括落实劳动法、降低职场性别歧视、推广普惠托儿、促进租住同权及教育公平，让个体敢于参与生育这一高风险项目。', '["人口问题本质是结构问题而非数量问题，老龄化会同时挤压消费和投资，缩短经济转型窗口期", "就业是把蛋糕做大而非分蛋糕，劳动人口下降会导致消费市场萎缩和税基减少，形成恶性循环", "AI提升生产效率但不改变分配方式，超额产出会向资本集中而非流向劳动者，社保压力不会自动缓解", "计划生育是以未来老龄化换取当下快速脱贫和工程师红利的战略选择，但低估了生育率下降的速度和逆转难度", "提高生育率的核心是替个人分担职业和养育风险，包括落实劳动法、降低性别歧视、推广普惠托育和教育公平"]', '[{"topic": "二次分配与社保体系的代际转移机制", "why": "理解为什么AI提升总产出却无法缓解社保压力，关键在于养老金体系依赖劳动者缴费的代际转移，而非简单的财富总量问题", "direction": "可阅读关于现收现付制养老金体系的经济学著作，如《养老金经济学》或研究社保筹资模式的相关文献"}, {"topic": "人口红利与工程师红利的转换逻辑", "why": "计划生育政策的历史评价需要放在特定发展阶段中考量，理解人口红利如何转化为工程师红利再转向老龄化压力的完整链条", "direction": "可研读蔡昉等人口经济学家的著作，了解人口转变理论与中国经济发展阶段的对应关系"}, {"topic": "不可能三角在社会政策中的表现", "why": "德国退休年龄、社保水平和税务负担的不可能三角揭示了一个普遍规律，社会政策目标之间存在刚性约束，不可兼得", "direction": "可延伸学习公共经济学中的政策约束理论，以及不同国家养老保障体系的比较研究"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114222, 1784116621, '187.0', '13.864567995071411', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7600730265711551462', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '7天读懂宏观经济- D7 效率与公平 #宏观经济   #学习', '7天读懂宏观经济- D7 效率与公平 #宏观经济   #学习', 1769684792, 'https://www.douyin.com/video/7600730265711551462', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oAGCeBsAFzQDY3fFCSS7ApfOBxBF7OESAItIcy~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785236400&x-signature=Cy1pAg9I4UgwjVogDGTGTNuAabo%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714195927D6AB97586A7EA7263BE8', 254501, 61397, 15117, 74901, 'done', 0, 'data/text/7600730265711551462.txt', 'data/summaries/7600730265711551462.md', '本文以三代人的婚恋观与生活轨迹为切入点，回顾了中国宏观经济的演变历程。爷爷时代的平等与贫困、爸爸时代的学历与房产红利，再到当代年轻人面临的学历贬值与转型压力，折射出国家在不同发展阶段对效率与公平的取舍。视频指出，高增长阶段依靠效率平滑分配结果，而低增长阶段必须通过维护公平来维持长期效率。面对住房、婚姻、生育等高风险项目，社会若让个人承担过多风险，个人便会选择退出。作者建议个人应打破旧有指标束缚，谨慎对待重资产，保持灵活性，在未被满足的细分市场中寻找新机遇。', '["三代人的择偶观与生活轨迹折射了中国宏观经济不同发展阶段的重心转移。", "中国经济经历了农产品折价支持工业起步、房地产溢价支持工业扩张的效率优先阶段。", "随着边际投资收益下降，资源错配问题凸显，供给侧改革成为扭转落后产能的必然选择。", "高增长阶段依靠效率平滑分配，低增长阶段则必须依靠机会公平来维持长期效率，防止个体退出高风险项目。", "个人应打破对重资产和旧指标的执念，保持灵活性，在未被满足的细分市场中寻找新机遇。"]', '[{"topic": "边际投资收益递减规律", "why": "解释了为什么资金继续流向重资产会导致资源错配，是理解宏观经济周期更迭和产业转型压力的关键经济学概念。", "direction": "学习微观经济学中的边际收益递减规律，并延伸至宏观层面的资本边际效率（MEC）概念。"}, {"topic": "效率与公平的替代关系", "why": "这是理解不同经济发展阶段（高增长vs低增长）下政策导向转变的核心逻辑，直接影响社会财富分配与个体命运。", "direction": "阅读阿瑟·奥肯的《平等与效率》，深入理解二者在经济发展中的权衡机制。"}, {"topic": "供给侧结构性改革", "why": "视频中提及用于扭转资源错配的关键政策，是理解当前中国经济转型、信贷流向调整及产业升级的宏观大背景。", "direction": "研究中国近年来供给侧改革的三大攻坚方向（去产能、去库存、去杠杆）及其对地方经济与银行业务的具体影响。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784082577, 1784114321, '471.0', '14.240805864334106', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7591299400112307530', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '2026财经展望#新年快乐 #财务  #省钱攻略', '2026财经展望#新年快乐 #财务  #省钱攻略', 1767487128, 'https://www.douyin.com/video/7591299400112307530', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/okJATpDtFiXAWtZQb9pEAB2AmqfIIDBfgpbzOE~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=Vowrujw523keI5%2BTR0h%2BljnniFE%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607142007305ADB7635E900AE22AF67', 7944, 1218, 904, 1710, 'done', 0, 'data/text/7591299400112307530.txt', 'data/summaries/7591299400112307530.md', '本视频是一位博主对个人2025年财务状况的深度复盘及2026年支出展望。博主详细盘点了过去一年超过30万的各项开支，涵盖旅游、租房、服饰、餐饮、美容及学习体验等，并剖析了个税APP显示43万的收入构成，包括主业薪资、不稳定副业及17万的理财收益。基于对消费主义的反思，博主计划在2026年大幅削减服饰、护肤等非必要开支，将现金流控制在20万以内。视频核心观点认为，依靠纯工资无法变富，需在享受生活与抵御消费主义诱惑之间寻找平衡，将节省的资金用于投资与再生产。', '["2025年总支出超30万，涵盖旅游、房租、服饰与体验课程，认为花在学习和体验上的钱比物质消费更有价值。", "去年总收入43万，包含主业工资、不稳定副业及17万理财收益，但投资因操作失误未跑赢大盘。", "2026年计划削减服饰、护肤和电子产品等非必要开支约4万，将全年现金流支出控制在20万以内。", "依靠工资无法实现财富跃迁，需抵御消费主义诱惑，将节省的资金用于投资与再生产。"]', '[{"topic": "恩格尔系数", "why": "视频中提到自己的恩格尔系数较高，该系数是衡量生活水平的重要经济学指标，了解它有助于更科学地评估个人消费结构的健康度。", "direction": "学习宏观经济学基础概念，了解恩格尔系数的计算方式及其在反映家庭或国家富裕程度上的应用。"}, {"topic": "消费主义与资本主义的辩证关系", "why": "视频引用《人类简史》的观点，揭示了现代社会鼓励生产与鼓励消费并存的矛盾现象，深入理解这一机制有助于建立反脆弱的个人消费观。", "direction": "阅读尤瓦尔·赫拉利《人类简史》及相关消费社会学著作，研究现代广告与金融体系如何推动消费主义。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114329, 1784117158, '267.0', '13.522638082504272', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7589991272652360970', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '7天读懂宏观经济- D6 美联储与美元 #宏观经济 #美联储 #美元 #学习
这个系列非做完不可', '7天读懂宏观经济- D6 美联储与美元 #宏观经济 #美联储 #美元 #学习
这个系列非做完不可', 1767182571, 'https://www.douyin.com/video/7589991272652360970', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/okQEDFDV9AAUpIhEMVEIf9BAECGgRkbxVpfSPR~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=TmYK5nwmy5sdoeMkAWi9%2Bpq5Ho4%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714200732FEF9F93E2C970D28AA79', 8705, 2333, 364, 797, 'done', 0, 'data/text/7589991272652360970.txt', 'data/summaries/7589991272652360970.md', '本视频从《美联储传》作者格里芬对美联储的七项指控切入，回顾了美国历史上四个中央银行的演变历程，解析了美联储的成立背景、组织结构与核心职能。视频指出美联储在灭火与放火之间存在结构性矛盾——危机虽变短，但贫富分化和资产泡沫加剧。随后视频追溯了美元中心地位的形成过程：从布雷顿森林体系的建立与特里芬难题，到尼克松冲击终结金本位，再到石油美元体系的诞生与美国金融市场回流机制的建立，解释了美元为何在持续通胀下仍被全球信赖持有的深层逻辑。', '["美联储是美国历史上第四个央行，前三个分别因违宪争议、通货紧缩和缺乏最后贷款人功能而终结", "格里芬对美联储的七项指控——垄断货币、助长通胀税、鼓励战争、加剧波动等——并非全无道理，但解散美联储恢复金本位的替代方案会导致通货紧缩和经济停滞", "美元中心地位经历了从布雷顿森林体系（美元挂钩黄金）到尼克松冲击（脱钩黄金）再到石油美元体系的演变", "特里芬难题是布雷顿森林体系的内在矛盾：输出美元需要逆差，维持黄金储备需要顺差", "石油美元与美国金融市场回流机制是美元地位延续至今的核心支撑"]', '[{"topic": "特里芬难题", "why": "它是理解布雷顿森林体系为何必然崩溃的理论核心，也是当今美元体系结构性矛盾的思想源头，对理解国际货币体系演变至关重要。", "direction": "阅读罗伯特·特里芬的《黄金与美元危机：自由兑换的未来》，结合蒙代尔关于最优货币区的理论进行延伸学习。"}, {"topic": "石油美元回流机制", "why": "它解释了美元脱离金本位后为何仍能维持全球储备货币地位，是理解当代地缘政治与金融体系互动的关键框架。", "direction": "研究1974年美沙联合经济委员会协议，阅读大卫·斯普罗特的《石油美元之战》，结合影子银行体系与离岸美元市场深入学习。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784079447, 1784114352, '658.2164375', '541.6419291496277', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7584690272131812654', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', 'A股慢牛？#A股  #美股 #投资 #知识', 'A股慢牛？#A股  #美股 #投资 #知识', 1765948347, 'https://www.douyin.com/video/7584690272131812654', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o0hlA1CieDkfOztCOgBR1IPoIA10swBA3v7AiB~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=3FiwRyV0miCsqBxq%2FaVjSUJETqI%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607142007357F9907C02417DE29B855', 5534, 1244, 255, 761, 'done', 0, 'data/text/7584690272131812654.txt', 'data/summaries/7584690272131812654.md', '美股慢牛行情的根源在于三大支柱：标普500成分股盈利持续增长构成基本面支撑，机构主导的资金结构提供稳定托底，美元国际地位持续引流全球资金。这三大因素叠加使美股走出长牛，择时容易踏空，长期持有成为主流策略。与之对比，A股在多个维度存在结构性差异：大盘股以银行、周期股为主，盈利波动大；散户主导交易，认知停留在消息和K线层面；做空机制不健全、退市标准不严格、造假成本过低，市场效率不足。尽管监管部门在引入长期资金、加大处罚力度、引导回购分红方面持续努力，A股目前仍不具备慢牛条件。然而，非有效市场恰恰提供了好企业被低估的机会，合理策略是选择好公司、蹲守好价格、设定止盈点，等待价值回归后卖出，而非照搬美股的长期持有模式。', '["美股慢牛的三大支柱：盈利增长驱动、机构主导资金结构托底、美元国际地位持续引流全球资金", "A股大盘股以银行、周期股为主，盈利波动大，结构性差异导致指数天然缺乏稳定性", "A股散户主导交易、制度不完善，做空机制不健全、退市标准不严、造假成本过低，市场效率不足", "非有效市场恰恰提供好企业被低估的机会，无需等待市场完美即可投资", "A股合理策略：选好公司、蹲守好价格、设定止盈点、等待价值回归后卖出"]', '[{"topic": "有效市场假说", "why": "理解市场有效性程度直接决定投资策略选择，A股作为非有效市场反而为价值投资者创造了系统性机会。", "direction": "阅读尤金·法玛《有效资本市场：理论与实证研究》，学习弱式、半强式、强式有效市场的区分及投资含义"}, {"topic": "指数成分股结构与市场表现", "why": "沪深300与标普500的成分股行业分布差异是两国市场表现分化的深层原因，理解这一点才能避免简单对比市盈率等指标。", "direction": "研究MSCI和FTSE Russell的指数编制方法论，对比不同市场指数的行业权重分布对长期回报的影响"}, {"topic": "机构投资者行为与市场稳定性", "why": "养老金、共同基金、指数基金等不同类型机构的行为模式差异巨大，理解其投资逻辑有助于判断市场底部支撑力量。", "direction": "学习博格《共同基金常识》，研究被动投资规模增长对市场微观结构的影响"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114491, 1784117528, '143.0', '11.176400899887085', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7583741154181909798', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '7天读懂宏观经济-D5国际收支平衡表 #宏观经济 #国际收支平衡表  #关税战 #学习 #2025掘金计划', '7天读懂宏观经济-D5国际收支平衡表 #宏观经济 #国际收支平衡表  #关税战 #学习 #2025掘金计划', 1765727352, 'https://www.douyin.com/video/7583741154181909798', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/owGUTIjHlg3fzLkDDMQe5OuJ4JegE2AtekgaAC~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=d848jVvsdMnNEq6m00f7OAQHFZo%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714200737005696281F68CB4C0418', 8718, 2464, 465, 742, 'done', 0, 'data/text/7583741154181909798.txt', 'data/summaries/7583741154181909798.md', '该视频以国际收支平衡表为核心，解答了为何中国制造物美价廉却遭遇贸易战、为何国人难以像美国一样超前消费等宏观经济痛点。国际收支平衡表记录了一国与世界的经济往来，主要分为经常账户（记录贸易）、资本与金融账户（记录金钱往来）以及误差与遗漏项。视频详细拆解了各账户的科目分类与复式记账原理，并结合中美两国的实际数据进行了深度解读。通过经常账户可看一国如何挣钱，通过金融账户可知资本去向与信心，通过储备资产可衡量抗风险能力。中国主要靠货物出口创汇，而产业结构升级促使企业出海带来投资收入；相对而言，美国则呈现出另一种挣钱与消费模式。掌握该表的阅读方法，有助于普通人看透国际贸易摩擦、资本外逃及汇率波动背后的深层逻辑。', '["国际收支平衡表记录一国与世界经济往来，包含经常账户、资本与金融账户及误差与遗漏项。", "经常账户反映贸易状况与挣钱方式，资本与金融账户反映资本流向与信心，储备资产体现抗风险能力。", "表内采用复式记账法，资产增加记减号、资产减少记加号，所有项目余额加总必然为零。", "误差与遗漏项不仅用于平账，更是监测走私和资本外逃的重要预警指标。", "中国主要靠货物出口创汇，近期初次收入增加反映了产业结构升级、供给侧改革与企业出海的变迁。"]', '[{"topic": "复式记账法在国际收支中的运用", "why": "理解资本与金融账户中“资产增加记减、减少记加”的反直觉逻辑，是读懂国际收支平衡表各科目余额勾稽关系和资本流向的基石。", "direction": "可阅读《国际经济学》或《宏观经济学》中关于国际收支平衡的章节，重点学习借贷记账规则。"}, {"topic": "误差与遗漏项与资本外逃", "why": "该项目是隐蔽性资本流动的镜子，通过观察其异常变动，能够预判国家面临的金融风险或资本外逃趋势，对投资决策有前瞻性指导价值。", "direction": "深入研究“热钱流出”、“国际资本管制”等概念，参考历次新兴市场金融危机前的国际收支数据。"}, {"topic": "经常账户结构变化与产业升级", "why": "从经常账户内部货物、服务、初次收入的占比变化，可以透视一国从依赖低端制造出口向海外投资收益、服务贸易转型的宏观经济脉络。", "direction": "研究“微笑曲线”、“全球产业链重构”等课题，结合中国历年国际收支报告进行数据趋势分析。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784080135, 1784114404, '860.9730625', '685.9504718780518', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7579608818158626523', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '两个朋友 《文明、资本与投资》丁昶 #投资 #知识分享 #投资策略 #价值投资', '两个朋友 《文明、资本与投资》丁昶 #投资 #知识分享 #投资策略 #价值投资', 1764765203, 'https://www.douyin.com/video/7579608818158626523', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o8EvaS8hTIAIQsiTwwPih6jWw72BWA8iBAILc~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=QVZzHxmiamIBJ1DVyAvtT8qtKy8%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714200740ED0673A10A405CA2D5C2', 4987, 681, 265, 271, 'done', 0, 'data/text/7579608818158626523.txt', 'data/summaries/7579608818158626523.md', '视频通过讲述两位职场朋友在跳槽与炒股中的幽默趣事，引出了丁昶在《文明、资本与投资》一书中探讨的投资策略演变。首先是曾在A股行之有效的“地效飞行器”策略，即买入市值最小的股票组合等待重组套利，但随着借壳上市供给过剩和优质资产稀缺，该策略在2016年后逐渐失效。随后视频转向美股市场，指出全球资金与美股市场之间存在严重分化，美联储通过降息托底维持美股上涨。而在美股内部，资金又高度集中于纳斯达克等难以用资本复制的科技巨头。整体而言，视频以诙谐叙事探讨了宏观货币政策与微观市场结构对投资策略的决定性影响。', '["A股“地效飞行器”策略通过投资最小市值股票利用壳资源套利，但2016年后因供给过剩而失效。", "全球资本市场严重分化，美股下跌时美联储会通过降息干预，吸引全球资金流入。", "美股内部存在分化，资金倾向于投资纳斯达克等靠资金无法复制核心壁垒的科技行业。", "投资策略的有效性高度依赖于宏观经济周期与货币政策的配合。"]', '[{"topic": "地效飞行器投资策略", "why": "该策略反映了中国A股特定历史时期壳资源的独特生态，理解它有助于把握政策变动对市场套利模式的根本影响。", "direction": "研读丁昶的《文明、资本与投资》，并了解A股注册制改革前后的并购重组规则变迁。"}, {"topic": "美股市场分化与美联储货币政策", "why": "美联储的加息与降息不仅是宏观调控工具，更是影响全球资产定价和资金流向的核心变量，对理解大类资产配置至关重要。", "direction": "学习宏观经济周期理论与美联储货币政策传导机制，研究利率对纳斯达克与传统行业板块的影响差异。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114571, 1784117771, '148.0', '11.984041929244995', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7575907912434895794', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '7天读懂宏观经济-D4汇率RPG《日银风云》#宏观经济  #汇率  #日本 #学习 #知识分享', '7天读懂宏观经济-D4汇率RPG《日银风云》#宏观经济  #汇率  #日本 #学习 #知识分享', 1763903518, 'https://www.douyin.com/video/7575907912434895794', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oEtcIgUBIvBjQiSwXICMMAmAa4Po4DFKziQ2l~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=xVKvbiEeUp2GlUb%2BAuJYYDUCK5g%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714200742F991403EDD78A33867DB', 7501, 1563, 408, 619, 'done', 0, 'data/text/7575907912434895794.txt', 'data/summaries/7575907912434895794.md', '本视频通过沉浸式角色扮演的形式，将观众代入二战后日本央行行长的视角，生动复盘了日本汇率政策的历史演变与经济逻辑。视频首先科普了名义汇率与实际汇率的区别，指出物价水平对国际竞争力的关键影响。随后，详细梳理了从布雷顿森林体系下的固定汇率、尼克松冲击后的政策两难，到广场协议被迫日元升值的历史进程。最后，揭示了日本为对冲升值压力而采取的连续降息政策，如何最终导致日元流动性泛滥并催生了股市与房地产的巨大泡沫。整体展示了汇率决策在内外平衡与国际博弈中的复杂困境。', '["汇率本质上是货币的相对价格，实际汇率由名义汇率和两国物价水平共同决定，直接影响国际竞争力。", "布雷顿森林体系下的固定汇率导致日元被低估，促成了日本出口繁荣，但也加剧了美国的逆差与黄金流失。", "1971年尼克松冲击后，日本维持固定汇率引发通胀压力，最终于1973年转向有管制的浮动汇率。", "1985年广场协议后日元被迫大幅升值，日本央行通过连续降息对冲升值压力，却意外催生了股市和房地产泡沫。"]', '[{"topic": "布雷顿森林体系与尼克松冲击", "why": "理解二战后国际货币体系的运作逻辑及其崩溃原因，是剖析全球汇率演变和美元霸权地位的基础。", "direction": "建议阅读《大国的兴衰》或学习“特里芬难题”概念，深入探究金本位崩溃的经济动因。"}, {"topic": "广场协议与日本泡沫经济", "why": "广场协议是日元升值和日本泡沫经济的导火索，研究这一历史事件有助于理解货币政策与资产泡沫的内在联系。", "direction": "建议阅读《日本经济史》或学习“流动性陷阱”与“资产泡沫化”理论。"}, {"topic": "实际汇率与购买力平价", "why": "实际汇率不仅受名义汇率影响，还取决于两国相对物价，是衡量国际贸易竞争力的核心指标。", "direction": "建议学习国际经济学中的“购买力平价理论（PPP）”及“蒙代尔-弗莱明模型”。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784080633, 1784114475, '624.826125', '496.7207410335541', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7572178832426615242', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '黄金价格分析框架 #黄金价格 #金价 #黄金 #投资 #掘金计划2025', '黄金价格分析框架 #黄金价格 #金价 #黄金 #投资 #掘金计划2025', 1763035274, 'https://www.douyin.com/video/7572178832426615242', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/owAJOHyEwiIJkSzVUaBJIQvGmPxRCXK1AiCIa~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=nRkPjcbTOvJ%2BG%2Bu1ejo%2FuvQ50oU%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714200744C6C4A6853B247D305D9A', 5668, 1295, 246, 785, 'done', 0, 'data/text/7572178832426615242.txt', 'data/summaries/7572178832426615242.md', '本视频提出了一套包含实际利率、美元走势、避险情绪和官方储备的黄金价格分析框架，并指出传统的开采成本对金价长期影响有限。作者认为，实际利率决定持金成本，美元强弱反向影响金价，危机激发避险需求，而全球央行增持黄金则是去美元化背景下金价的长期支撑。对于普通人而言，作者建议采用定投策略平滑波动，依据自身收入和资产配置需求进行长期投资。黄金投资的核心在于避险与抗通胀，而非短期投机，正如查理·芒格所言，大钱不靠买卖，靠等待。', '["实际利率（票面利率减通胀率）是决定黄金持有成本的核心，市场预期往往领先于实际数据反应。", "美元强弱与金价呈反向关系，既因为美元是计价单位，也因为美元资产是黄金的替代避险选择。", "避险情绪在危机时期推动金价上涨，黄金因其不依赖任何国家信用的特性成为资金避风港。", "全球央行对黄金的官方储备需求是金价的长期支撑，去美元化趋势为其提供了底层逻辑。", "普通人投资黄金宜采用定投策略进行长期资产配置，以平滑波动并获得趋势性平均收益。"]', '[{"topic": "费雪效应与实际利率", "why": "理解实际利率对黄金价格的决定性作用，需要深入掌握名义利率、通胀率与实际利率之间的数学关系及其经济学意义。", "direction": "建议阅读欧文·费雪的《利息理论》或宏观经济学教材中关于费雪方程式的章节。"}, {"topic": "去美元化与主权货币信用", "why": "美国冻结他国外汇储备的事件标志着全球货币体系正在发生深刻变化，这一地缘政治逻辑是理解黄金长期价值的关键。", "direction": "研究布雷顿森林体系的兴衰，以及近年来多国央行数字货币（CBDC）和双边本币结算机制的发展。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114685, 1784118246, '194.0', '16.887104034423828', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7568667882037795995', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '7天读懂宏观经济- D3预期 #宏观经济  #经济预期  #GDP #知识分享  #掘金计划2025', '7天读懂宏观经济- D3预期 #宏观经济  #经济预期  #GDP #知识分享  #掘金计划2025', 1762217819, 'https://www.douyin.com/video/7568667882037795995', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oM1JELghfAId4X4vBBe073BZTiADiAdhmK4Ikz~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=MBEsZCwfKxAJdlBJvvTIHJwNNNs%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714200747F8EA417AB46BA6A7AF98', 126794, 32007, 5733, 23861, 'done', 3, 'data/text/7568667882037795995.txt', 'data/summaries/7568667882037795995.md', '本文通过两代人截然不同的经济经历，深入探讨了“预期”在宏观经济中的关键作用。预期具有自我实现的特征，个人的自信、民众对通胀的恐慌抢购、储户对银行信誉的怀疑，都可能导致原本未必发生的结果成真。中国改革开放以来，从价格闯关引发通胀到成功治理实现软着陆，从下岗潮的悲观预期到加入WTO后昂扬向上的乐观预期，历史反复证明：预期既能成为经济繁荣的助推器，也能变成衰退的加速器。政府通过货币政策与财政政策进行逆周期调节，借助乘数效应提振总需求，但其效果受制于央行的信誉、赤字的挤出效应等因素。本质上，预期是每个人基于过往经历形成的心理模型，理解预期的形成与传导，有助于我们更清醒地看待宏观经济波动与代际观念差异。', '["预期具有自我实现特征，能通过影响个体行为改变宏观经济结果。", "央行的信誉是有效管理通胀预期的关键，历史政策成败深刻塑造市场信心。", "消极预期可引发经济下行螺旋，而积极预期能创造繁荣循环。", "政府通过财政支出和货币宽松进行逆周期调节，乘数效应放大刺激效果，但需警惕赤字和挤出效应。", "个人经历决定经济预期，代际差异反映了不同历史阶段的宏观经济环境。"]', '[{"topic": "预期自我实现", "why": "预期能够改变实际经济行为，是理解通胀、挤兑等经济现象的关键机制。", "direction": "建议学习宏观经济学中的“理性预期”理论，参考卢卡斯（Robert Lucas）相关论文，或阅读《动物精神》（乔治·阿克洛夫）。"}, {"topic": "财政政策乘数与挤出效应", "why": "乘数效应说明政府支出对经济的放大作用，挤出效应则揭示其局限性，是宏观经济政策分析的核心。", "direction": "学习凯恩斯主义经济学中的乘数原理，结合IS-LM模型理解政策效果，推荐曼昆《宏观经济学》相关章节。"}]', 'opencode_go_deepseek_v4_pro', 'deepseek-v4-pro', 1784032681, 1784081421, 1784193864, '876.484', '785.6617550849915', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7565080319636917555', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '讲个故事《人类简史》 #讲故事 #故事 #知识分享 #读书', '讲个故事《人类简史》 #讲故事 #故事 #知识分享 #读书', 1761382524, 'https://www.douyin.com/video/7565080319636917555', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o02HBCPzATHQaDPj0RMLI0feQEUev875eAGIDC~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=yIB0oaDnHV1IVNmu3Tr8LwURUao%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714200749C5DF28584A35DC2AE2FB', 18274, 2161, 2466, 954, 'summarize_failed', 1, 'data/text/7565080319636917555.txt', NULL, NULL, NULL, NULL, NULL, NULL, 1784032681, 1784114744, NULL, '162.0', '14.049869060516357', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7564378205621587250', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '7天读懂宏观经济-D2货币 #宏观经济 #货币 #货币政策 #GDP #掘金计划2025', '7天读懂宏观经济-D2货币 #宏观经济 #货币 #货币政策 #GDP #掘金计划2025', 1761219056, 'https://www.douyin.com/video/7564378205621587250', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/okVVIBALWg4vf7GA53B9YUgBe4JVGeYCGJrR30~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=hRWYpYsZYROqVJs6HaK%2FWcPeLnk%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071420075248E2AD420FB9B3B997BC', 16792, 6093, 823, 2087, 'done', 0, 'data/text/7564378205621587250.txt', 'data/summaries/7564378205621587250.md', '视频主要探讨了宏观经济中资金流向的决定机制，指出钱的去向由两只手共同决定：看不见的手即经济周期，看得见的手即货币政策。核心论点围绕美林时钟模型展开，将经济周期划分为衰退、复苏、过热和滞胀四个阶段，并分别对应债券、股票、大宗商品和现金的最佳投资标的。同时，视频解析了货币政策的四大目标及其内在矛盾，并详细拆解了央行调控市场的工具箱，包括数量型、价格型、选择型和非常规工具。理解这两只手的运作逻辑，是把握宏观资金流向和做出正确投资决策的关键所在。', '["资金流向由经济周期（看不见的手）和货币政策（看得见的手）共同决定。", "美林时钟将经济周期分为衰退、复苏、过热、滞胀四个阶段，分别对应债券、股票、大宗商品和现金的优先配置。", "货币政策追求经济增长、物价稳定、就业充分和国际收支平衡，但目标间常存矛盾，如菲利普斯曲线揭示的通胀与就业难兼容。", "央行通过数量型、价格型、选择型和非常规型工具箱来调节市场流动性和资金价格。"]', '[{"topic": "美林时钟模型", "why": "它是连接宏观经济周期与资产配置的核心桥梁，掌握它能在不同经济阶段做出最优投资选择，但也需了解其在现代经济中的局限性。", "direction": "建议阅读美林证券原版报告，并研究2000年以来全球宏观经济数据验证其有效性及变形情况。"}, {"topic": "菲利普斯曲线", "why": "它揭示了通货膨胀与失业率之间的替换关系，是理解央行制定货币政策时面临目标冲突的关键理论基础。", "direction": "学习宏观经济学中关于通胀与就业的章节，了解近年来该曲线在发达国家“平坦化”现象的深层原因。"}, {"topic": "央行货币政策工具体系", "why": "了解准备金率、公开市场操作等工具的运作机制，能帮助投资者预判市场流动性的松紧变化，从而走在资金流向的前面。", "direction": "研读中国人民银行货币政策执行报告或美联储联邦公开市场委员会（FOMC）声明，学习实际操作中的工具组合使用逻辑。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784082599, 1784114602, '751.0', '20.14861512184143', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7558851410486889778', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '7天读懂宏观经济 - D1 产出 #宏观经济学 #宏观经济 #GDP #每天跟我涨知识 #2025掘金计划', '7天读懂宏观经济 - D1 产出 #宏观经济学 #宏观经济 #GDP #每天跟我涨知识 #2025掘金计划', 1759932241, 'https://www.douyin.com/video/7558851410486889778', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oIjERbG3IfgADS5BBmEDfAU9ovAFBVmgZvroIA~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=TZCloiRVtludCpeTKetfBWH2V%2BM%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714200754BF0B11AA9CE2ED73DBCD', 15165, 5658, 854, 1817, 'done', 0, 'data/text/7558851410486889778.txt', 'data/summaries/7558851410486889778.md', '本视频主旨是开启为期七天的宏观经济学学习计划，旨在帮助观众建立系统性的经济认知框架。主讲人指出，尽管宏观经济理论是对过去经验的总结且许多实际问题尚无定论，但它能为我们思考复杂现象提供重要的分析工具。经济学本质上是研究社会资源分配及其结果的学问，宏观经济学则聚焦于整个社会层面的资源分配及其对经济活动的影响。视频强调，建立框架思维有助于我们更深刻地剖析现实问题，例如在探讨美元霸权体系时，不应仅局限于其能否维持，而应深入追问其潜在的替代方案。', '["学习宏观经济学能够为理解复杂经济现象提供系统性的思考框架。", "宏观经济理论是对过去经验的总结而非未来预言，许多实际问题尚无定论。", "经济学的核心是研究社会资源的分配方式及其带来的结果。", "宏观经济学聚焦于整个社会的资源分配及其对整体经济活动的影响。", "运用宏观思维分析现实问题时需进行系统性比较，如探讨美元霸权替代方案。"]', '[{"topic": "宏观经济学的基本概念与框架", "why": "理解宏观经济学的核心定义与边界是系统学习经济运行的起点，有助于避免陷入碎片化的信息陷阱。", "direction": "阅读《七天读懂宏观经济学》，掌握总产出、通货膨胀、失业率等核心宏观经济指标。"}, {"topic": "美元霸权体系的运作与逻辑", "why": "视频提及的美元霸权是宏观经济与国际金融的重要交汇点，理解其兴衰逻辑对认识全球资源分配至关重要。", "direction": "学习布雷顿森林体系、石油美元的运作机制，以及国际货币基金组织（IMF）的相关知识。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784082606, 1784114735, '461.0', '6.282780170440674', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7555836366350847283', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '牛市展望#牛市 #牛市来了吗 #投资', '牛市展望#牛市 #牛市来了吗 #投资', 1759231838, 'https://www.douyin.com/video/7555836366350847283', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o4IByHRIb8fGiCvuARGS3eIHLBA7vBtjzfgWrI~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=KUXKGYYXF1gNV3JVBnpLlFPmd1A%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607142007570F9371ADA5CEE9EC61E8', 4815, 1265, 478, 689, 'done', 0, 'data/text/7555836366350847283.txt', 'data/summaries/7555836366350847283.md', '这段对话探讨了当前股市究竟处于慢牛、快牛还是结构牛阶段。首先明确了慢牛由基本面驱动，策略为好股好价长期持有；快牛由资金面和情绪面驱动，估值常脱离基本面。当前市场出现估值分化，白马股估值合理而科技板块高估，引发对快牛中后期或结构牛的辨析。结构牛的特征是宽基震荡而主线独立，其成因多为产业趋势或政策引导。针对不同牛市类型，后期策略截然不同：快牛后期需配置低估值权重股防范机构拉指数出货，结构牛后期则需抱紧主线但警惕高估值。最后提出当前若为结构牛，其核心目的可能是为科技企业融资，投资者需通过核查企业上市、增发及可转债发行等融资行为来验证市场逻辑。', '["慢牛由基本面驱动且估值匹配，适宜“好股好价长期持有”策略。", "快牛由资金和情绪驱动导致估值脱离基本面，后期需配置低估值权重股防机构拉高出货。", "结构牛表现为宽基震荡而主线独立，常由产业趋势或政策引导，后期需抱紧主线但警惕高估值。", "当前市场估值显著分化，需通过核查重点科技企业的实质性融资行为来验证结构牛逻辑。"]', '[{"topic": "结构牛与快牛的周期特征", "why": "识别市场所处的牛市类型是制定投资策略的前提，能有效避免在快牛后期接盘或在结构牛中踏空主线。", "direction": "建议阅读《周期》（霍华德·马克斯），学习市场钟摆效应与周期定位理论。"}, {"topic": "企业融资行为与市场逻辑的映射", "why": "股市的重要功能是融资，观察IPO、增发及可转债发行能洞察政策导向和资金真实去向，验证市场上涨的实质支撑。", "direction": "学习“证券市场基础”中的融资与再融资机制，关注监管层对科技企业直接融资的政策文件。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114853, 1784119083, '100.0', '9.730257034301758', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7554993548124458290', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '零跑百万台下线《点球成金》 #零跑汽车第100万辆下线#科技普惠 #零跑汽车 #中国新能源崛起 #电车成本', '零跑百万台下线《点球成金》 #零跑汽车第100万辆下线#科技普惠 #零跑汽车 #中国新能源崛起 #电车成本', 1759034016, 'https://www.douyin.com/video/7554993548124458290', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oAJqYALGLDBtbEIoj2FfABgKtuuFotIf95DmAw~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=J4yhQFde6W0DxiLoJUukXCCauoA%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=2026071420075901952190DDFB6C373FC9', 3863, 570, 321, 259, 'done', 0, 'data/text/7554993548124458290.txt', 'data/summaries/7554993548124458290.md', '视频以零跑汽车第100万辆车下线为契机，通过电影《点球成金》的隐喻，剖析了零跑汽车在资源有限、品牌年轻背景下的逆袭路径。面对新能源汽车严苛的成本硬约束，零跑摒弃了依赖直觉与资本堆砌的传统模式，转而追求极致的“上垒率”——将每一分预算转化为有效配置和用户体验。通过平台化战略、全域自研以及精准挖掘冷门需求，零跑在保证安全与核心驾驶体验不打折的前提下，成功找到了价值洼地。这一里程碑不仅代表了数字上的成就，更验证了中国车企凭借精细化数据统计与成本管控，能在红海市场中实现逆风翻盘的新可能。', '["零跑汽车仅用不到一年时间实现从50万辆到100万辆下线，销量与营收实现爆发式增长并扭亏为盈。", "零跑的逆袭路径类似电影《点球成金》，在资本有限的情况下通过精细化分析追求预算的“上垒率”。", "面对电车成本硬约束，零跑坚持在安全部件与核心驾驶体验上不妥协，精准划定成本红线。", "平台化零部件通用与全域自研软硬件协同，是零跑摊薄成本、实现极致性价比的核心手段。", "零跑的成功验证了不依赖情怀和盲目砸钱，仅凭精准配置与数据驱动的用户体验也能在红海中胜出。"]', '[{"topic": "汽车BOM成本结构与管控", "why": "了解电车各部件的成本占比有助于深刻理解车企的定价策略和盈利逻辑，是分析新能源车企业竞争力的核心维度。", "direction": "学习BOM（物料清单）成本管理概念，阅读关于汽车工业工程与成本核算的相关教材或行业报告。"}, {"topic": "点球成金理论与赛伯计量学", "why": "该理论展示了如何在资源受限的情况下，通过数据统计与概率论寻找被市场低估的价值，适用于商业分析与产品规划。", "direction": "阅读迈克尔·刘易斯的著作《点球成金》，深入研究棒球统计学中的赛伯计量学在现代商业决策与运营中的应用。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114866, 1784119154, '143.0', '12.30889105796814', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7553286298276334857', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '基因检测《自私的基因》 #基因检测 #基因筛查 #基因 #vlog十亿流量扶持计划', '基因检测《自私的基因》 #基因检测 #基因筛查 #基因 #vlog十亿流量扶持计划', 1758636513, 'https://www.douyin.com/video/7553286298276334857', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oAAl3IVrRBaQUfBOAGCUGAwpLDEQGQe7eB5wl6~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=a8ZOqdU0Nzhu3w3bZBga%2FV0O5Ns%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714200801C95846E5516E91B97F06', 2778, 388, 208, 247, 'done', 0, 'data/text/7553286298276334857.txt', 'data/summaries/7553286298276334857.md', '本视频以查理芒格的名言为引子，通过分享个人基因检测结果，探讨了基因与疾病风险的关系。视频引入“自私的基因”理论，解释了为何致病基因在进化中未被淘汰——因为基因的最高目标是自我复制，只关注个体繁衍而非衰老后的健康。尽管我们无法改变碱基序列，但可以通过健康生活方式影响基因表达。面对基因带来的不可控疾病风险，视频进一步提出利用商业保险建立“安全边际”的理念，强调以小投入撬动大利益的非对称结构，呼吁人们在不确定性中为人生做好保障。', '["基因检测能提前揭示个体对特定疾病的风险与药物反应，为健康管理提供预警地图。", "自私的基因理论解释了致病基因未被淘汰的原因：基因只关注个体繁衍，而非衰老后的健康。", "人类虽无法改变碱基序列，但能通过生活方式干预和及时治疗影响基因表达，降低患病风险。", "利用商业保险建立非对称结构的安全边际，可以用小投入撬动大保障，应对不确定性。"]', '[{"topic": "拮抗性多效性假说", "why": "它完美解释了为什么某些致病基因在自然选择中未被淘汰，即同一基因在生命早期有益于繁殖，但在晚期却有害。", "direction": "阅读理查德·道金斯的《自私的基因》以及乔治·威廉斯的相关进化生物学著作，深入理解基因与个体的利益博弈。"}, {"topic": "表观遗传学", "why": "它打破了基因决定论，揭示了后天环境、饮食、生活方式如何在不改变DNA序列的情况下影响基因表达，为疾病预防提供了科学依据。", "direction": "学习DNA甲基化、组蛋白修饰等概念，探索生活习惯如何重塑基因表达。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114880, 1784119207, '136.0', '13.357568979263306', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7549914936504569126', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '牛市复盘  第二层思维 霍华德.马克斯 《投资最重要的事》#牛市 #牛市来了吗', '牛市复盘  第二层思维 霍华德.马克斯 《投资最重要的事》#牛市 #牛市来了吗', 1757851558, 'https://www.douyin.com/video/7549914936504569126', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oA6ATf1GmgheBmHICn2iAhBDrAYiIYSU0uZiXT~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=Zk5ei96js9fCdWYZUG6p78V%2F74s%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714200804ED96F6A93F4309C20D33', 15125, 3174, 1004, 2518, 'done', 0, 'data/text/7549914936504569126.txt', 'data/summaries/7549914936504569126.md', '本视频通过复盘作者在锂电和医药板块的真实投资经历，探讨了霍华德·马克斯的“第二层思维”在牛市中的应用。作者指出，仅基于行业基本面判断买卖的“第一层思维”容易错失大牛股，而洞察市场情绪与估值的“第二层思维”才能战胜市场。同时，作者强调在牛市中认清自身定位至关重要，普通投资者不应盲目接盘宏大叙事，而应在风险较小的上半场获利了结，避免在下半场成为被收割的“羊”。', '["第一层思维仅根据表面基本面做直观判断（如看空行业就卖出），容易错失大牛股。", "第二层思维要求洞察市场情绪，在众人恐慌抛售时发现资产价值与重置成本的错配并逆向买入。", "投资者需认清自身定位，区分国家产业战略与个人盈利目标，不盲目接盘宏大叙事。", "牛市下半场风险远大于上半场，贪图超额收益往往容易使自己成为被收割的“羊”。"]', '[{"topic": "第二层思维", "why": "这是霍华德·马克斯投资哲学的核心，理解它能帮助投资者跳出表面信息，建立基于市场博弈和预期的逆向投资框架。", "direction": "阅读霍华德·马克斯《投资最重要的事》第二章，结合历史牛熊转换案例研究预期差。"}, {"topic": "重置成本与市净率（PB）估值", "why": "通过评估重新建立一家同类型企业的成本来判断当前股价是否被低估，是衡量安全边际的重要逆向视角。", "direction": "学习本杰明·格雷厄姆《证券分析》中关于账面价值与企业重置成本的论述。"}, {"topic": "指数基金被动增持与产业资本退出机制", "why": "了解宽基指数纳入规则和资金流转机制，能帮助散户看破牛市中各方参与者的利益诉求，避免成为接盘侠。", "direction": "研究指数编制规则（如沪深300纳入标准）及ETF资金流动力学相关概念。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114893, 1784119266, '139.0', '13.415303945541382', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7547313149445639450', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '论持久战  #抗日战争胜利纪念日 #抗日战争  #论持久战 #孙子兵法 #知识分享', '论持久战  #抗日战争胜利纪念日 #抗日战争  #论持久战 #孙子兵法 #知识分享', 1757245784, 'https://www.douyin.com/video/7547313149445639450', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oEhXBP8eAihDIVcKdB0giBS9IderARVviAplFW~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=8GKOJiIvcyXaWoByf1haP619DAY%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714200806FF9777ECB7C3EF30DB19', 6634, 710, 32, 447, 'done', 0, 'data/text/7547313149445639450.txt', 'data/summaries/7547313149445639450.md', '本视频围绕毛泽东一九三八年《论持久战》演讲展开，剖析了抗日战争时期两种错误论调——亡国论与速胜论的根源，指出它们分别只看到敌强我弱或其余矛盾，犯了主观片面的错误。教员从敌强我弱、敌小我大、敌进步退步、敌多助寡助四个矛盾出发，得出中国不会亡国但也不能速胜、抗战必然是持久战的科学结论。全文进一步拆解了战略防御、战略相持、战略反攻三个阶段的作战方针与代表性战役，并以《孙子兵法》兵贵胜不贵久与《论持久战》持久战的比较收束，阐明二者分别站在进攻与防守角度，前者追求速战速决以减少消耗，后者在战略上以空间换时间，战术上则讲究防御中的进攻、持久中的速胜，二者并不矛盾。', '["亡国论与速胜论分别只看到敌强我弱或其余矛盾，犯了主观片面、机械唯心的错误", "中日战争四组矛盾——敌强我弱、敌小我大、进步退步、多助寡助——共同决定了抗战是持久战且最终胜利属于中国", "持久战分为战略防御、战略相持、战略反攻三个阶段，各阶段作战方针不同：运动战为主转向游击战为主再转向全面反攻", "《孙子兵法》兵贵速胜与《论持久战》持久战不矛盾，二者分别站在进攻与防守角度，且持久战中战术上仍追求局部速胜"]', '[{"topic": "《论持久战》的辩证法思想", "why": "教员运用矛盾分析法将战争局势拆解为四组对立统一的关系，是马克思主义辩证法在军事领域的经典实践，对理解战略思维方法具有普遍价值", "direction": "可阅读《论持久战》原文及《矛盾论》，重点理解主要矛盾与次要矛盾的转化关系"}, {"topic": "《孙子兵法》速胜论与持久战战略的比较", "why": "两者看似矛盾实则互补，涉及攻守异势下战略选择的底层逻辑，对理解不同战略位置的决策原则有启发意义", "direction": "可研读《孙子兵法》作战篇与谋攻篇，结合克劳塞维茨《战争论》中关于进攻与防御的比较分析"}, {"topic": "游击战十六字诀与人民战争理论", "why": "敌进我退、敌驻我扰、敌疲我打、敌退我追的十六字诀是弱军对抗强军的战术结晶，背后是以群众为基础的人民战争思想", "direction": "可阅读教员《抗日游击战争的战略问题》及《战争和战略问题》，研究游击战从战术到战略的提升路径"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114925, 1784119407, '140.0', '11.039912939071655', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7544278178630814985', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '恋爱指南 《隆中对》 #恋爱技巧 #找工作 #三国 #隆中对 #intj', '恋爱指南 《隆中对》 #恋爱技巧 #找工作 #三国 #隆中对 #intj', 1756539147, 'https://www.douyin.com/video/7544278178630814985', 'https://p3-pc-sign.douyinpic.com/tos-cn-p-0015/oMzVRFAcaILDBDBRAfBOIqIyeBBaiCBGLGf7ZL~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=cdyjh86Q%2FRxvLAKmFg32W8A1%2Fuc%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607142008096D15FEE216CF79B170D1', 10078, 1476, 734, 1316, 'done', 0, 'data/text/7544278178630814985.txt', 'data/summaries/7544278178630814985.md', '这个视频以《隆中对》为蓝本，将诸葛亮的求职历程巧妙转化为一份INTJ恋爱与求职指南。核心论点是：无论恋爱还是求职，成功的关键在于四步——自抬身价、营造氛围、掌握核心诉求、提供情绪价值。作者用三国的故事拆解了理性人格如何在不失逻辑的前提下完成高情商的自我营销与关系建立，同时反向推导出攻略INTJ的秘诀：以美强惨的形象出现，暴露柔软缺口，用共同愿景邀请对方同行。整段内容在戏谑中揭示了人际关系构建的底层逻辑。', '["自抬身价的核心是制造稀缺性与第三方背书，而非自我推销", "营造氛围的本质是在你开口前就抬高对方的评价基准", "掌握核心诉求需要主题明确、语言明快、逻辑简单，精准命中对方最在意的问题", "情绪价值是在逻辑方案之上叠加愿景画面，让对方相信你们共享同一个未来", "攻略INTJ的公式是：美强惨形象加柔软缺口加共同愿景的邀请"]', '[{"topic": "INTJ人格类型的情感模式", "why": "INTJ在亲密关系中往往被误解为冷漠，但其核心需求是被理解与被欣赏，理解这一点能帮助理性人格建立更健康的情感关系", "direction": "可阅读MBTI相关著作如《请理解我》或了解 attachment theory 中 avoidant 型依恋与理性人格的交叉"}, {"topic": "稀缺性原理与社交价值构建", "why": "诸葛亮让徐庶代为推荐而非自荐，暗合了社交心理学中稀缺性提升吸引力的机制，这一原理在恋爱、求职、品牌营销中通用", "direction": "可阅读罗伯特·西奥迪尼《影响力》中的稀缺性章节，或了解 signaling theory 在社交市场中的应用"}, {"topic": "情绪价值与战略叙事的结合", "why": "诸葛亮在纯逻辑分析后加入了百姓夹道欢迎的画面感叙事，这种逻辑加画面的结构在说服领域极为重要", "why2": "理解这一点能提升任何提案或沟通的说服力", "direction": "可研究 storytelling in leadership 或阅读《讲故事的力量》相关内容，了解叙事如何为数据赋能"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784114992, 1784119679, '126.0', '10.901519060134888', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7541982124540267826', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '博弈论 冯·诺伊曼《博弈论》（bushi）    #买房 #恋爱 #博弈论 #耶鲁大学公开课博弈论 #知识分享', '博弈论 冯·诺伊曼《博弈论》（bushi）    #买房 #恋爱 #博弈论 #耶鲁大学公开课博弈论 #知识分享', 1756004556, 'https://www.douyin.com/video/7541982124540267826', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o4tqY4gIi7BAVD8iTrBBO0gf6wxAeABmIrMuvs~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=rAV1AAWS%2F1rl%2FqTrQHg80TCLgIk%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607142008115946235B62D512AEBA54', 93832, 17607, 3961, 34725, 'done', 0, 'data/text/7541982124540267826.txt', 'data/summaries/7541982124540267826.md', '本视频通过作者面临是否在北京买房的真实抉择，生动引入了博弈论的分析框架。作者将买房问题拆解为流动性、居住体验和伴侣效应等多个维度的效用模型，推导出在特定条件下买房属于绝对劣势策略。通过对比理性凡人与纯爱战神等不同人设的收益矩阵，视频提炼出博弈论的四大核心原则：摒弃绝对劣势策略、理性可能导致次优结果、换位思考以及明确自身真实诉求。最终指出，真诚的理性人能达成最优合作，而伪装只会导致滑稽的结局。视频巧妙地将抽象的博弈论应用于生活决策，兼具趣味性与启发性。', '["将买房决策拆解为流动性与情绪价值的效用矩阵，发现买房在特定情境下属于绝对劣势策略。", "两个完全理性的个体博弈往往会陷入囚徒困境，导致无法达到整体效用最大化的合作结果。", "通过分析纯爱战神的决策过程，揭示博弈论需站在对方立场思考问题的核心原则。", "效用模型会随个人身份和目标的变化而改变，明确自身真实诉求是做出正确决策的前提。", "真诚的理性人更容易达成合作，而伪装成纯爱战神往往会导致滑稽的结局。"]', '[{"topic": "绝对劣势策略与纳什均衡", "why": "视频提到的绝对劣势策略是博弈论的基础概念，而两人都不买房的均衡状态正是经典的纳什均衡，理解它能帮助看透合作失败的根源。", "direction": "推荐观看耶鲁大学公开课《博弈论》，学习如何构建收益矩阵并寻找纳什均衡点。"}, {"topic": "效用理论与偏好序", "why": "视频中将买房的利弊量化为效用值，这涉及经济学中的效用理论，不同人对同一事物的效用评估完全不同。", "direction": "阅读微观经济学教材中关于消费者选择与效用最大化的章节，深入理解偏好如何决定决策。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115047, 1784119958, '181.0', '14.989538192749023', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7539584801784007982', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '二战起源 威尔·杜兰特《历史的教训》 #日本投降 #二战 #二战历史 #二战德国 #二战意大利', '二战起源 威尔·杜兰特《历史的教训》 #日本投降 #二战 #二战历史 #二战德国 #二战意大利', 1755446387, 'https://www.douyin.com/video/7539584801784007982', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/o0fHXEiDAayI6fwFf9FtEBAlQkDWHDQFefhNyY~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=64fUgPFVtgaEqL0MAxJ%2FyKqBKxc%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607142014590BDA3024390681B36AA5', 60761, 10572, 3733, 4776, 'done', 0, 'data/text/7539584801784007982.txt', 'data/summaries/7539584801784007982.md', '本视频基于威尔·杜兰特的《历史的教训》，从经济学视角剖析了二战的起源。德意日三国因自身资源匮乏且遭遇1929年大萧条，导致国内经济崩溃与社会动荡。为转移内部矛盾，三国均采取了“以战养战”的军国主义路线，并编造虚假叙事压迫民众服从。然而，侵略战争的消耗远超掠夺收益，现金流断裂注定其败局。战后，由于集权制度的瓦解和全球经济的合作分工，三国迎来了和平发展。视频指出，战争源于人类贪婪等本能冲动，缺乏约束的权力才是导致国家走向战争与崩溃的根本原因，而非单纯的地理资源匮乏。', '["德意日发动二战的深层原因是资源匮乏遭遇1929年大萧条，导致国内经济与社会危机爆发。", "三国均通过编造虚假叙事来转移国内矛盾，并实行以战养战的军国主义经济策略。", "侵略战争的消耗远大于掠夺收益，现金流断裂是法西斯国家最终战败的经济学逻辑。", "战后三国能和平发展，得益于集权制度的瓦解以及融入全球经济合作分工体系。", "战争的根源在于贪婪等本能冲动，缺乏约束的权力才是导致国家走向战争与崩溃的根本原因。"]', '[{"topic": "威尔·杜兰特《历史的教训》", "why": "该书从地理、经济、生物学等多个维度总结了人类历史的规律，对理解国家行为、战争根源以及权力约束具有深刻的启发意义。", "direction": "建议阅读《历史的教训》全书，重点关注其中关于经济与战争、生物学与历史章节的论述。"}, {"topic": "1929年大萧条的全球影响", "why": "大萧条不仅是一场经济危机，更是引发全球政治动荡、极端主义抬头和第二次世界大战的重要催化剂。", "direction": "可深入研究大萧条对各国政治经济体制的冲击，查阅相关经济史著作或关于二战前夕国际局势的文献。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115085, 1784120184, '128.0', '9.576040029525757', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7535120440651779379', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '结构问题 布罗代尔 《地中海与菲利浦二世时代的地中海世界》（的序言） #生育补贴 #反内卷 #关税战 #俄乌冲突 #新能源', '结构问题 布罗代尔 《地中海与菲利浦二世时代的地中海世界》（的序言） #生育补贴 #反内卷 #关税战 #俄乌冲突 #新能源', 1754406947, 'https://www.douyin.com/video/7535120440651779379', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oYI2SoUAuBh8wg9PyHIAKiiAfIB7NkAS1f1GCD~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=p2PFxnILFEh%2FTmTiSW4z8C9%2FtuE%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714201502AEAC086E49CFD3DFFB73', 109960, 59813, 1449, 22165, 'done', 0, 'data/text/7535120440651779379.txt', 'data/summaries/7535120440651779379.md', '本视频以布罗代尔的“事件、局势、结构”三层分析框架为核心，探讨了如何透过表象看清复杂世界的底层逻辑。事件是转瞬即逝的浪花，局势是潮汐更替，而结构则是决定流向的河床。作者通过关税战、俄乌冲突、新能源转型等案例，阐释了三者之间的相互触发与交叉影响。同时，将这一框架应用于生育补贴和反内卷等社会议题，指出人口和内卷问题本质上是分配与退出机制的结构性难题，需通过结构性改革解决。最后，为普通人提供了把握结构性机会的实操建议，即投身注定繁荣的行业并在创业公司中历练，将宏观结构变化转化为个人成长契机。', '["看待问题分为事件、局势、结构三个层次，事件与局势往往由深层结构性压力触发。", "国际冲突与能源博弈等事件和局势会交叉影响，推动全球地缘政治与能源结构的深层转型。", "人口与内卷等社会难题本质是分配与退出机制的结构性问题，需通过结构性改革解决。", "普通人可通过投身注定繁荣行业的创业公司来把握结构性机会，在试错中积累成为行业精英。"]', '[{"topic": "布罗代尔的“长时段”理论", "why": "视频中事件、局势、结构的划分直接源于此理论，理解它能帮助建立更系统的历史观和宏观分析能力。", "direction": "阅读布罗代尔《地中海与菲利普二世时代的地中海世界》序言，或了解法国年鉴学派史学方法论。"}, {"topic": "产能退出机制与市场出清", "why": "视频指出内卷是退出问题，理解落后产能如何有序退出对于理解宏观经济周期和产业升级至关重要。", "direction": "学习微观经济学中的市场出清概念，以及产业经济学中关于僵尸企业退出与产能过剩治理的相关理论。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115140, 1784120505, '101.0', '10.357360124588013', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7532855598570327353', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '稳定陷阱 塔勒布《智慧与魔咒》  #考公考编 #中年失业 #反脆弱 #塔勒布', '稳定陷阱 塔勒布《智慧与魔咒》  #考公考编 #中年失业 #反脆弱 #塔勒布', 1753879622, 'https://www.douyin.com/video/7532855598570327353', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015c000-ce/oIKPIMAIWjIhNTviWF4agXAlBEAGBoi7v1IhZ~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=%2FroMb9rXFIIz1i2h7fFmXw6%2B1Uc%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714201505577D2C78C022DF24C6B8', 7563, 1510, 370, 1218, 'done', 0, 'data/text/7532855598570327353.txt', 'data/summaries/7532855598570327353.md', '视频以表妹辞职创业的真实故事为引子，引出塔勒布在《智慧与魔咒》中的核心观点：月薪与海洛因、碳水并列为三大成瘾物，依赖体系的稳定收入会削弱个人的英雄主义和抗风险能力。作者对比了体系依赖型收入与技能依赖型收入的本质差异，指出收费员、银行从业者等看似稳定的岗位在技术变革或行业调整面前不堪一击，而理发师、普拉提教练等靠技能吃饭的人反而具有真正的韧性。对于当下年轻人热衷考公考编的现象，作者认为非生产性人员的薪酬若长期高于生产性人员，终将面临系统性纠偏，通过后视镜找到的稳定路径在未来未必可持续。视频最后给出两条务实建议：一是切入国外成熟但国内尚处草莽阶段的细分服务领域，二是赚消费者的零花钱而非生活费。作者本人也在践行塔勒布的反脆弱理论——保留稳定主业的同时开拓副业，构建杠铃式的收入结构。', '["塔勒布将月薪与海洛因、碳水并列为三大成瘾物，体系依赖会削弱个人的抗风险能力", "技能型收入比体系型收入更具长期韧性，理发师和教练到哪都有饭吃", "考公考编的稳定性可能面临系统性纠偏，后视镜里的稳定路径未来未必可行", "创业机会在于国外成熟但国内草莽的细分领域，以及赚零花钱而非生活费的低决策成本生意", "杠铃策略——主业保稳定、副业博收益——是普通人践行反脆弱的务实路径"]', '[{"topic": "反脆弱理论与杠铃策略", "why": "塔勒布的反脆弱理论提供了一种在不确定性中获益的思维框架，杠铃策略是其最实用的方法论之一，适用于职业规划和个人风险管理。", "direction": "阅读塔勒布《反脆弱：从不确定性中获益》，重点理解杠铃策略和非对称风险的概念"}, {"topic": "生产性与非生产性收入的结构性矛盾", "why": "当非生产性人员的薪酬系统性高于生产性人员时，往往意味着资源错配，历史上多次社会变革和经济危机都与此相关。", "direction": "了解经济学中的生产率理论与财政分配机制，可参考曼昆《经济学原理》中关于生产率与生活水平的章节"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115186, 1784120591, '120.0', '11.590759992599487', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7529979405893717298', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '奥马哈追星活动 #巴菲特 #投资  #价值投资 #奥马哈', '奥马哈追星活动 #巴菲特 #投资  #价值投资 #奥马哈', 1753209967, 'https://www.douyin.com/video/7529979405893717298', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ooE4QGpf9HSQ7xB7F3fQpDFcCYKDWLABAV0IfC~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=Ts1R4v5tSkDQIFFGIlV4asHuj7s%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714201507723E8673B34725202FD5', 4116, 581, 223, 335, 'done', 0, 'data/text/7529979405893717298.txt', 'data/summaries/7529979405893717298.md', '这期视频通过作者在奥马哈的实地探访，重温了巴菲特的投资哲学与人生智慧。视频主旨在于探讨如何屏蔽外界噪音，聚焦事物本质的投资与生活方式。首先，以奥马哈的宁静环境为切入点，说明远离华尔街噪音对专注投资决策的重要性。随后，通过回顾伯克希尔·哈撒韦从纺织厂转型的历史，总结了“不买糟糕公司”与“要么全买要么不买”的深刻教训。接着，视频对比了捡烟屁股策略与以合理价格买入好公司的理念，以喜诗糖果和内布拉斯加家具城为例，剖析了好公司的三大特征：品牌壁垒与定价权、低资本开支以及充沛的现金流。最后，视频升华至生活哲学，强调爱护身体、保持热爱与阅读的重要性。整体核心论点为：无论是投资还是生活，都应摒弃浮躁，寻找真正具有长期价值且能带来内心愉悦的标的与方式。', '["选择在奥马哈生活能够有效屏蔽华尔街噪音，帮助投资者专注研究标的本身而非盯紧记分牌。", "伯克希尔纺织厂的失败让巴菲特总结出糟糕业务会拖累优秀经理人的教训，并促使其转向以合理价格买入好公司。", "以喜诗糖果为代表的好公司具备品牌壁垒、定价权和低资本开支三大核心优势。", "内布拉斯加家具城的成功投资强调了真诚管理层、区域垄断以及充沛现金流的重要性。", "投资之外，巴菲特强调坚持热爱、多读书、保持幽默以及像保养唯一一辆车那样爱护身体。"]', '[{"topic": "捡烟屁股投资策略与优质公司投资策略的对比", "why": "这是价值投资史上最著名的认知迭代，理解这一转变有助于投资者摆脱单纯追求低价的陷阱，转而关注企业长期的内在价值与商业模式。", "direction": "建议阅读《聪明的投资者》与《穷查理宝典》，了解从格雷厄姆式安全边际到芒格式成长护城河的思想演变。"}, {"topic": "资本开支对企业自由现金流的影响", "why": "区分会计利润与自由现金流是评估商业模式的进阶能力，重资产行业的高资本开支往往会吞噬账面利润，导致股东实际回报极低。", "direction": "建议学习财务报表分析中关于自由现金流与资本支出的章节，以及巴菲特致股东信中关于股东盈余的论述。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115237, 1784120831, '141.0', '12.644781112670898', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7529287456538463497', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '通货紧缩.波士顿访友记', '通货紧缩.波士顿访友记', 1753049463, 'https://www.douyin.com/video/7529287456538463497', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ogiZduKigxH0bUaAIQaIJIPi2VIBC1w9DMPuA~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=Ngb1gD%2Fw28jxcS1xqK9gQRu0gCQ%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607142015090C74C41B67FD1C1B4E79', 9032, 1734, 1042, 1015, 'done', 0, 'data/text/7529287456538463497.txt', 'data/summaries/7529287456538463497.md', '本视频以作者在波士顿访友的见闻为切入点，探讨了宏观经济中货币供给与通胀、通缩之间的复杂关系。作者指出，出口型国家为对冲美元外汇而增发货币，导致过度投资与资产泡沫，泡沫破裂后居民杠杆高企、消费需求不足，从而陷入M2增加但感官通缩的流动性陷阱。与此同时，作者通过与当地朋友的交流，对比了中美两国在消费观念、医疗育儿、房产社区及生育意愿等方面的差异，揭示了美国社会福利保障下的生活方式以及亚裔群体在海外面临的职业天花板，展现了不同经济结构下个体的真实生存状态。', '["出口型国家为对冲外汇增发货币，引发过度投资和资产泡沫，泡沫破裂后挤压消费导致体感通缩。", "资金在缺乏投资机会时即便利率下降也只在金融系统空转，造成M2增加与通缩并存的现象。", "美国人的消费底气部分源于政府兜底预期及大病商业医保不设上限的保障。", "美国好社区的公立教育免费且质量高，但依赖较高的房产税和十年收入的购房成本。", "亚裔在美存在职业天花板，美国社会结构更适合底层或富人，中产面临回国与否的纠结。"]', '[{"topic": "流动性陷阱", "why": "视频提到M2增加但资金在金融系统空转，这触及了凯恩斯主义中的流动性陷阱概念，理解它有助于看懂当前宏观货币政策为何难以有效刺激实体经济。", "direction": "建议阅读曼昆的《宏观经济学》中关于货币政策传导机制的部分，或深入学习“流动性陷阱”与“资产负债表衰退”理论。"}, {"topic": "蒙代尔-弗莱明模型与外汇占款", "why": "视频提及出口型国家为防本币升值而发行等量货币，这涉及到固定汇率制度下的货币政策独立性丧失及外汇占款问题，是理解输入型流动性的关键。", "direction": "深入学习国际经济学中的“蒙代尔-弗莱明模型”以及“不可能三角（三元悖论）”概念。"}, {"topic": "资产负债表衰退", "why": "视频描述了泡沫破裂后居民杠杆高企导致消费不振、企业不涨工资的循环，这正是资产负债表衰退的典型特征，能解释为何需求不足难以扭转。", "direction": "推荐阅读辜朝明的《大衰退》，探究企业和居民部门从“利润最大化”转向“负债最小化”的经济学逻辑。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115248, 1784120894, '126.0', '11.172145128250122', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7525756263512231177', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '正确催婚《亲密关系》 罗兰·米勒 #催婚 #亲密关系 #恋爱 #读书', '正确催婚《亲密关系》 罗兰·米勒 #催婚 #亲密关系 #恋爱 #读书', 1752226679, 'https://www.douyin.com/video/7525756263512231177', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oU34IGFr6qG5kenwBBDAIe4v7yQA2CNB3aEkfm~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=sXqbpU%2BwQAU%2BQGhBGqNr4Z9EPPw%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714201512A4D4F4057137B2B19BF8', 4955, 581, 853, 556, 'done', 0, 'data/text/7525756263512231177.txt', 'data/summaries/7525756263512231177.md', '视频通过博主参加表妹婚礼的经历，探讨了当代年轻人对催婚和亲密关系的思考。文章指出，传统的催婚方式生硬且无效，真正能打动人的是展示婚姻带来的更高生活质量。博主认为，结婚的目的是为了过得更好，而非完成繁衍任务或寻求救赎。基于罗兰·米勒的《亲密关系》，博主提炼了三条吸引力法则作为择偶标准：寻找能帮助自我拓展的人、接近理想自我的人，以及自我认知一致的人。最终，博主决定采取积极行动，通过社交圈和相亲软件寻找伴侣，若未果则顺其自然，展现了理性且不失松弛感的婚恋观。', '["真正有效的催婚不是施压，而是展示婚姻能带来更高质量的生活。", "婚姻不应被视为人生的救命稻草或繁衍工具，而应是锦上添花的选择。", "罗兰·米勒提出的三条吸引力法则：拓展自我、接近理想自我、认知一致。", "落实择偶需要务实行动，从身边社交圈到相亲软件逐步尝试，无果则顺其自然。"]', '[{"topic": "罗兰·米勒《亲密关系》中的吸引力法则", "why": "这三条法则从心理学层面深刻揭示了人类择偶的底层逻辑，超越了表层的外貌和物质条件，有助于建立更长久和深度的情感连接。", "direction": "建议阅读罗兰·米勒的《亲密关系》原书，深入了解“社会交换理论”与“自我概念”在亲密关系中的具体应用。"}, {"topic": "命运馈赠的代价与单身焦虑心理", "why": "探讨了当代独立青年在面对同辈压力时产生的自我怀疑，反映了个人主义追求与传统社会期望之间的内在冲突。", "direction": "可阅读斯蒂芬·茨威格关于玛丽·安托瓦内特的传记，或研究社会心理学中的“同辈压力”与“从众心理”。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115313, 1784121074, '127.0', '11.817056894302368', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7524001941354597658', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '黄金有价 《黄金与美元危机》罗伯特·特里芬 货币漫游（完）#黄金 #美元 #货币 #2025掘金计划', '黄金有价 《黄金与美元危机》罗伯特·特里芬 货币漫游（完）#黄金 #美元 #货币 #2025掘金计划', 1751818224, 'https://www.douyin.com/video/7524001941354597658', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/ocrEJPyfQKvADBaBDVLDfAU98FAFC3pgl4OoQD~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=ws2KVkqDF4yjM7k%2Futi0R%2FpJZv8%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=202607142015143460F10086CD2550952B', 5394, 1013, 313, 474, 'done', 0, 'data/text/7524001941354597658.txt', 'data/summaries/7524001941354597658.md', '本视频围绕罗伯特·特里芬在《黄金与美元危机》中提出的核心矛盾，深入剖析了黄金价格与美元走势背后的深层逻辑。二战后建立的布雷顿森林体系试图通过固定汇率解决货币竞相贬值问题，却陷入了美元需贸易逆差输出货币与需贸易顺差维持金价的悖论。尽管该体系已崩塌，但这一“特里芬难题”依然存在，导致美国赤字不减时美元面临信任危机，避险资金涌入黄金推高金价。视频同时解释了近期美元与黄金双涨现象，指出各国央行同时增持两者是关键因素。最后，对于资产配置，作者建议放弃复杂的预测公式，转而采取更简单的逆向思维：直接替换掉贬值概率最大的资产。', '["布雷顿森林体系存在美元需逆差输出与需顺差攒黄金的不可调和矛盾，导致其最终崩塌。", "体系崩塌后美元仍面临特里芬难题，美国赤字不减会引发美元信任危机，避险资金转向黄金推高金价。", "美元与黄金同涨现象源于各国央行用本币同时增持两者，导致两者走出独立行情。", "资产配置无需依赖复杂预测公式，应直接替换掉贬值概率最大的资产。"]', '[{"topic": "特里芬难题", "why": "它是理解国际货币体系演变和美元霸权兴衰的核心理论基石，解释了单一主权货币作为国际储备货币的固有缺陷。", "direction": "建议阅读罗伯特·特里芬的《黄金与美元危机》，并延伸学习特别提款权（SDR）的创设背景与作用。"}, {"topic": "央行储备多元化与去美元化", "why": "了解各国央行的实际资产配置行为，有助于看透近期黄金与美元同涨的反常现象，把握全球资本流向的真实脉络。", "direction": "研究国际货币基金组织（IMF）的官方外汇储备货币构成（COFER）数据，以及多国增持黄金的动因。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115352, 1784121228, '104.0', '8.694598913192749', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7521586600603847945', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '《美元危机》理查德·邓肯  货币漫游（三）#美元 #美元霸权 #美元危机 #货币 #掘金计划2025', '《美元危机》理查德·邓肯  货币漫游（三）#美元 #美元霸权 #美元危机 #货币 #掘金计划2025', 1751255855, 'https://www.douyin.com/video/7521586600603847945', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/oQiouPpU1ACwB9K9gIFiYCDDZfIDfzgEAABtiI~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=cdUpCmq6jlsIivLhHkC8HCYJ44Y%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714201517A662B92B2A2E86B744FE', 9890, 2376, 1385, 990, 'done', 0, 'data/text/7521586600603847945.txt', 'data/summaries/7521586600603847945.md', '本视频以理查德·邓肯的《美元危机》为理论框架，剖析了布雷顿森林体系崩溃后美元本位制的形成及其内在缺陷。布雷顿森林体系下，黄金作为货币锚，贸易失衡存在自动调节机制。体系崩溃后，美元与黄金脱钩，美债取代黄金成为美元的抵押物，美国得以持续借债进口。贸易伙伴手持大量美元，无论购买美元资产还是兑换本币，最终都会推高资产泡沫并引发通货紧缩。邓肯指出该体系三大根本缺陷：全球经济依赖美国借债进口、推高全球资产泡沫、泡沫破裂后通缩。尽管体系不可持续，但美元和美债作为避险资产的地位在每次危机中反而被强化。作者通过数学推算发现，以美债利息不超过财政预算百分之三十为约束，当前美债增速可能已突破可持续极限，暗示美元体系的崩溃临界点正在逼近。', '["布雷顿森林体系崩溃后，美元与黄金脱钩，美债取代黄金成为美元抵押物，形成了缺乏自动调节机制的美元本位制", "贸易伙伴持有的美元无论回流美国还是兑换本币，最终都会推高资产泡沫并引发通货紧缩，日本失去的三十年和东南亚金融危机即是例证", "美元本位制存在三大缺陷：全球经济依赖美国借债进口、推高全球资产泡沫、泡沫破裂后通缩", "美元和美债位于避险金字塔顶端，每次全球危机中底部资金向上逃逸反而强化了其地位，这是体系至今未崩的原因", "以美债利息不超过财政预算百分之三十为约束推算，当前美债增速可能已突破可持续极限"]', '[{"topic": "布雷顿森林体系的自动调节机制", "why": "理解金本位下贸易失衡的自我修正原理，是认识当前美元本位制缺陷的理论基础，也是理解为何脱离金本位后全球失衡持续扩大的关键。", "direction": "阅读特里芬的《黄金与美元危机》以及国际经济学教材中关于国际收支自动调节机制的内容"}, {"topic": "避险金字塔与美元流动性循环", "why": "美元体系之所以在多次危机中反而被强化，核心在于全球资金的风险分层结构，理解这一机制才能判断美元崩溃的条件是否真正具备。", "direction": "研究Zoltan Pozsar关于美元流动性体系的BIS工作论文，以及货币市场基金与回购市场的运行机制"}, {"topic": "主权债务可持续性分析", "why": "通过财政预算与债务利率的数学关系推算体系崩溃边界，是一种可量化的分析方法，能帮助判断当前美债扩张是否已触及临界点。", "direction": "学习IMF主权债务可持续性分析框架（DSA），阅读Carmen Reinhart和Kenneth Rogoff的《这一次不一样：八百年金融危机史》"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115390, 1784121443, '168.0', '15.23075795173645', 1784032677, 1784032677);
INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7518738273825918234', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '一次说清稳定币（说清请扣1） 《货币的非国家化》冯·哈耶克 货币漫游（二） #稳定币 #货币 #哈耶克 #掘金计划2025', '一次说清稳定币（说清请扣1） 《货币的非国家化》冯·哈耶克 货币漫游（二） #稳定币 #货币 #哈耶克 #掘金计划2025', 1750592674, 'https://www.douyin.com/video/7518738273825918234', 'https://p9-pc-sign.douyinpic.com/tos-cn-p-0015/osBAYKBXisFOV7XXS9dXABMA56mIIDBfgofd9i~tplv-dy-360p.jpeg?lk3s=138a59ce&x-expires=1785240000&x-signature=D5gR%2BCR8UKyNuWUdRUelm5WNf4A%3D&from=327834062&s=PackSourceEnum_AWEME_DETAIL&se=false&sc=origin_cover&biz_tag=pcweb_cover&l=20260714201519462A62CD26547028F9A1', 10472, 2485, 483, 1438, 'done', 0, 'data/text/7518738273825918234.txt', 'data/summaries/7518738273825918234.md', '视频以幽默对话的形式探讨了稳定币的价值与发行方的盈利逻辑。普通人试图用稳定币对抗通胀意义不大，而真正的获利者在于稳定币的发行方。通过哈耶克的完全竞争理论，指出单纯依靠发币的超额利润最终会趋向于零。然而，如果发行方能熬过竞争实现垄断，便可利用巨大的浮存金进行投资，甚至获得国家层面的背书与委托，如购买美债、协助绕过制裁等，从而实现真正的格局跃升与巨额利润。', '["普通人试图通过持有稳定币对抗通胀的意义不大，稳定币真正的价值在于发行方的商业模式。", "货币发行方可以通过超发货币获得类似铸币税的纯利润，如美联储百分之二的通胀目标即隐含相应的利润空间。", "根据哈耶克的完全竞争理论，私人货币发行的超额利润在长期竞争中会趋向于零。", "稳定币发行方的终局在于熬死竞争对手后，利用庞大的浮存金投资和上调手续费获利。", "垄断后的稳定币巨头将具备国家级影响力，甚至能参与美债购买和绕过地缘政治制裁的金融博弈。"]', '[{"topic": "货币的非国家化", "why": "哈耶克提出的私人货币竞争理论是理解稳定币竞争终局和超额利润趋向于零的核心逻辑基础。", "direction": "阅读哈耶克著作《货币的非国家化》，深入理解货币竞争机制对币值稳定和发行方行为的影响。"}, {"topic": "铸币税与通胀税", "why": "发行方通过超发货币获取的利润本质上是铸币税，理解这一定义有助于看清稳定币发行方与央行类似的盈利手段。", "direction": "学习宏观经济学中关于铸币税、通胀税以及央行货币政策目标的相关概念。"}, {"topic": "浮存金的商业模式", "why": "稳定币沉淀的资金池形成浮存金，这是金融巨头核心的盈利模式之一，理解它能看透稳定币发行的深层动机。", "direction": "了解沃伦·巴菲特如何利用伯克希尔·哈撒韦的保险浮存金进行投资的相关案例和理论。"}]', 'volc_glm_5_2', 'glm-5.2', 1784032681, 1784115429, 1784121673, '193.0', '10.971109867095947', 1784032677, 1784032677);
