INSERT OR IGNORE INTO videos (aweme_id, sec_user_id, title, desc_text, create_time, aweme_url, cover_url, liked_count, collected_count, comment_count, share_count, status, retry_count, transcript_path, summary_path, summary, key_points, knowledge_points, llm_provider, llm_model, downloaded_at, transcribed_at, summarized_at, video_duration, transcribe_duration, fetched_at, updated_at) VALUES ('7496538753285393702', 'MS4wLjABAAAA0uvwnOav1l0s_q4ysXFSd7i8dmkO8Q7KQ6B-i-VLy7I', '读书博主的自我修养。肉体是供奉灵魂的神殿。
靠自律是没有用的。 
我们老师曾教导我，
自律就像水缸里的水，
牛逼的人可以坚持100天，
到101天的时候也会崩溃。 
习惯不会。
把有价值的小事当成习惯，
如果能这样就好了。
但习惯的培养需要毅力。 
弱点不需要。
弱点是你的支点，
你可以用它来撬动自己。 
我的弱点是缺少内部积分卡，
需要寻求外界认可。
于是我会把训练痕迹拍下来发朋友圈。
把看的书整一整拍成视频。 
当然我们会懒惰。
但重要的是记住你真正想要什么。
你想要躺着玩手机，
我也想。
但我真正想要的，我是说真正想要的，
是成为更好的人。 
是的这是我的另一个弱点。
“不够好”是我一直以来的困扰。
这听起来是个纯纯的悲剧，
但在解决之前，
“更好”是我的杠杆，也是我的奖赏。 
所以你的弱点是什么。
你如何设计自己的奖赏机制。 
I''ve got my weaknesses, but that doesn''t matter.
I''m no weak. I''m a troop. 
注：1.拍照主要对光线、角度和拍摄技巧要求较高，实际效果并没看起来明显；2.2024年忙着拍视频没有好好锻炼，所以没有照片；3.因为对光线要求高所以搬家之后没在家拍过了；4.之前有网友问我老师是谁，这位@冯志BodyTemple 。 
